fn normalized_remote_accounts(accounts: &[RemoteAccountSettings]) -> Vec<RemoteAccountSettings> {
    if accounts.is_empty() {
        vec![RemoteAccountSettings::default()]
    } else {
        accounts.to_vec()
    }
}

fn normalized_repository_workspaces(workspaces: &[PathBuf]) -> Vec<PathBuf> {
    let mut normalized: Vec<PathBuf> = Vec::new();
    for workspace in workspaces {
        let workspace = workspace
            .canonicalize()
            .unwrap_or_else(|_| workspace.clone());
        let workspace = user_facing_path_buf(&workspace);
        if normalized
            .iter()
            .any(|existing| paths_equal(existing.as_path(), workspace.as_path()))
        {
            continue;
        }
        normalized.push(workspace);
    }
    normalized
}

fn user_facing_path_buf(path: &Path) -> PathBuf {
    PathBuf::from(user_facing_path_string(path))
}

fn user_facing_path_string(path: &Path) -> String {
    let path = path.display().to_string();
    if let Some(rest) = path.strip_prefix(r"\\?\UNC\") {
        return format!(r"\\{rest}");
    }
    path.strip_prefix(r"\\?\")
        .map(ToOwned::to_owned)
        .unwrap_or(path)
}

fn validate_remote_account_settings(name: &str, host: &str) -> Result<(), String> {
    let name = name.trim();
    let host = host.trim();
    if name.is_empty() {
        return Err("remote account name is empty".to_owned());
    }
    if host.is_empty() {
        return Err("remote account host is empty".to_owned());
    }
    if name.contains(['\n', '\r']) || host.contains(['\n', '\r']) {
        return Err("remote account fields must be single line".to_owned());
    }
    if !remote_account_host_is_valid(host) {
        return Err("remote account host is invalid".to_owned());
    }
    Ok(())
}

fn validate_custom_git_action_settings(name: &str, command: &str) -> Result<(), String> {
    let name = name.trim();
    let command = command.trim();
    if name.is_empty() {
        return Err("custom action name is empty".to_owned());
    }
    if command.is_empty() {
        return Err("custom action command is empty".to_owned());
    }
    if command.contains(['\n', '\r']) {
        return Err("custom action command must be single line".to_owned());
    }
    if command != "git" && !command.starts_with("git ") {
        return Err("custom action command must start with git".to_owned());
    }
    Ok(())
}

fn remote_account_host_is_valid(host: &str) -> bool {
    let host = host.trim();
    if host.eq_ignore_ascii_case("Generic Host") {
        return true;
    }
    if host.contains(char::is_whitespace) {
        return false;
    }
    if let Some(rest) = host
        .strip_prefix("https://")
        .or_else(|| host.strip_prefix("http://"))
    {
        return !rest.is_empty() && rest.contains('.');
    }
    if let Some(rest) = host.strip_prefix("git@") {
        return rest.contains(':')
            && rest
                .split(':')
                .next()
                .is_some_and(|part| part.contains('.'));
    }
    host.contains('.') || host.contains(':')
}

fn validate_repo_remote_action_dialog(name: &str, url: &str) -> Result<(), String> {
    let name = name.trim();
    let url = url.trim();
    if name.is_empty() {
        return Err("remote name is empty".to_owned());
    }
    if url.is_empty() {
        return Err("remote URL is empty".to_owned());
    }
    if name.contains(char::is_whitespace) || name.contains(['\n', '\r']) {
        return Err("remote name must not contain whitespace".to_owned());
    }
    if url.contains(['\n', '\r']) {
        return Err("remote URL must be single line".to_owned());
    }
    Ok(())
}

