    fn worktree_diff_viewer(&self, ui: &mut Ui) {
        let Some(selected) = &self.selected_worktree_file else {
            return;
        };

        let key = git::worktree_diff_key(&selected.path, selected.staged);
        if self.loading_diff_key.as_deref() == Some(key.as_str()) {
            ui.horizontal(|ui| {
                ui.spinner();
                ui.label(RichText::new(self.tr("diff.loading")).color(theme::muted()));
            });
            return;
        }

        let Some(diff) = self.diff_cache.get(&key) else {
            ui.label(RichText::new(self.tr("diff.queued")).color(theme::muted()));
            return;
        };

        if diff.text.trim().is_empty() {
            ui.label(RichText::new(self.tr("diff.empty")).color(theme::muted()));
            return;
        }

        let truncated_label = self.tr("diff.truncated");
        let mut selected_rows = Vec::new();
        let diff_response = worktree_diff_panel_frame().show(ui, |ui| {
            let inner_size = safe_ui_size(ui.available_size());
            safe_set_min_size(ui, inner_size);
            fill_diff_scroll_area(
                ui,
                ("worktree_diff_scroll", key),
                &diff.text,
                DiffDisplayMode::Full,
                self.language,
                &mut selected_rows,
                (diff.text.lines().count() > 1_200).then_some(truncated_label),
            );
        });
        let diff_rect = diff_response.response.rect;
        paint_workspace_card_inset_shadow(ui, diff_rect);
    }

    fn pull_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_pull_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let actions_enabled = !self.branch_actions_busy();
        let remotes = self.remote_names();
        if !remotes.iter().any(|remote| remote == &dialog.remote) {
            dialog.remote = remotes
                .first()
                .cloned()
                .unwrap_or_else(|| "origin".to_owned());
        }
        let remote_branches = self.remote_branch_names_for(&dialog.remote);
        if !remote_branches
            .iter()
            .any(|branch| branch == &dialog.remote_branch)
        {
            dialog.remote_branch = remote_branches.first().cloned().unwrap_or_default();
        }
        let remote_url = self.remote_url_for_name(&dialog.remote).unwrap_or_default();

        compact_action_dialog(ctx, self.tr("pull.title"), PULL_DIALOG_WIDTH, |ui| {
            ui.horizontal(|ui| {
                ui.label(
                    RichText::new(self.tr("pull.remote"))
                        .small()
                        .color(theme::muted()),
                );
                egui::ComboBox::from_id_salt("pull_remote_selector")
                    .width(ui.available_width())
                    .selected_text(dialog.remote.as_str())
                    .show_ui(ui, |ui| {
                        for remote in &remotes {
                            if ui
                                .selectable_value(&mut dialog.remote, remote.clone(), remote)
                                .clicked()
                            {
                                let branches = self.remote_branch_names_for(&dialog.remote);
                                dialog.remote_branch =
                                    branches.first().cloned().unwrap_or_default();
                            }
                        }
                    });
            });
            ui.add_space(4.0);
            themed_text_edit_selection(ui);
            let mut remote_url_display = remote_url.clone();
            ui.add_enabled(
                false,
                themed_singleline_text_edit(
                    &mut remote_url_display,
                    self.tr("repo.remote.missing"),
                ),
            );
            ui.add_space(8.0);
            ui.horizontal(|ui| {
                ui.label(
                    RichText::new(self.tr("pull.remote_branch"))
                        .small()
                        .color(theme::muted()),
                );
                let branch_choices = remote_branches
                    .iter()
                    .map(|branch| (branch.clone(), branch.clone()))
                    .collect::<Vec<_>>();
                searchable_branch_dropdown(
                    ui,
                    egui::Id::new("pull_remote_branch_selector"),
                    &mut dialog.remote_branch,
                    &branch_choices,
                    (ui.available_width() - 76.0).max(180.0),
                    self.tr("pull.remote_branch"),
                    self.tr("repo.source.search"),
                );
                if ui
                    .add_enabled(actions_enabled, egui::Button::new(self.tr("pull.refresh")))
                    .clicked()
                    && !dialog.remote.trim().is_empty()
                {
                    let remote = dialog.remote.trim().to_owned();
                    execute = Some(Box::new(move |root| git::fetch_remote(root, &remote)));
                }
            });
            ui.horizontal(|ui| {
                ui.label(
                    RichText::new(self.tr("pull.local_branch"))
                        .small()
                        .color(theme::muted()),
                );
                ui.label(RichText::new(dialog.local_branch.as_str()).color(theme::text()));
            });
            ui.add_space(8.0);
            ui.label(
                RichText::new(self.tr("pull.options"))
                    .small()
                    .color(theme::muted()),
            );
            ui.group(|ui| {
                action_checkbox(ui, &mut dialog.commit_merge, self.tr("pull.commit_merge"));
                action_checkbox(ui, &mut dialog.include_tags, self.tr("pull.include_tags"));
                action_checkbox(
                    ui,
                    &mut dialog.force_merge_commit,
                    self.tr("pull.force_merge_commit"),
                );
                action_checkbox(ui, &mut dialog.rebase, self.tr("pull.rebase"));
            });
            ui.add_space(12.0);
            ui.horizontal(|ui| {
                ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                    let default_action_enabled = actions_enabled
                        && !dialog.remote.trim().is_empty()
                        && !dialog.remote_branch.trim().is_empty();
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui
                        .add_enabled(
                            default_action_enabled,
                            egui::Button::new(self.tr("action.pull")),
                        )
                        .clicked()
                        || (submit_requested && default_action_enabled)
                    {
                        let remote = dialog.remote.trim().to_owned();
                        let remote_branch = dialog.remote_branch.trim().to_owned();
                        let options = git::PullOptions {
                            commit_merge: dialog.commit_merge,
                            include_tags: dialog.include_tags,
                            force_merge_commit: dialog.force_merge_commit,
                            rebase: dialog.rebase,
                        };
                        execute = Some(Box::new(move |root| {
                            git::pull_from_remote(root, &remote, &remote_branch, options)
                        }));
                        close_after = true;
                    }
                });
            });
        });

        if let Some(action) = execute {
            self.execute_git_action(action);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_pull_action = Some(dialog);
        }
    }

    fn push_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_push_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut push_after_close: Option<(String, Vec<git::PushBranchSpec>, git::PushOptions)> =
            None;
        let actions_enabled = !self.branch_actions_busy();
        let remotes = self.remote_names();
        if !remotes.iter().any(|remote| remote == &dialog.remote) {
            dialog.remote = remotes
                .first()
                .cloned()
                .unwrap_or_else(|| "origin".to_owned());
            let branches = self.remote_branch_names_for(&dialog.remote);
            Self::update_push_rows_for_remote(&mut dialog.rows, &dialog.remote, &branches);
        }
        let remote_branches = self.remote_branch_names_for(&dialog.remote);
        let remote_url = self.remote_url_for_name(&dialog.remote).unwrap_or_default();
        let title = format!(
            "{}: {}",
            self.tr("push.title"),
            self.active_repo_display_name()
        );

        compact_action_dialog(ctx, &title, PUSH_DIALOG_WIDTH, |ui| {
            let mut remote_url_display = remote_url.clone();
            push_remote_form_row(
                ui,
                self.tr("push.remote"),
                self.tr("repo.remote.missing"),
                &mut remote_url_display,
                |ui| {
                    egui::ComboBox::from_id_salt("push_remote_selector")
                        .width(PUSH_REMOTE_FORM_SELECTOR_WIDTH)
                        .selected_text(dialog.remote.as_str())
                        .show_ui(ui, |ui| {
                            for remote in &remotes {
                                if ui
                                    .selectable_value(&mut dialog.remote, remote.clone(), remote)
                                    .clicked()
                                {
                                    let branches = self.remote_branch_names_for(&dialog.remote);
                                    Self::update_push_rows_for_remote(
                                        &mut dialog.rows,
                                        &dialog.remote,
                                        &branches,
                                    );
                                }
                            }
                        });
                },
            );

            ui.add_space(8.0);
            ui.label(
                RichText::new(self.tr("push.branches"))
                    .small()
                    .color(theme::muted()),
            );
            egui::Frame::new()
                .fill(theme::panel_soft())
                .stroke(Stroke::new(1.0, theme::inset_shadow()))
                .inner_margin(egui::Margin::symmetric(6, 6))
                .show(ui, |ui| {
                    let table_width = ui.available_width();
                    push_branch_table_header(
                        ui,
                        table_width,
                        self.tr("push.select"),
                        self.tr("push.local_branch"),
                        self.tr("push.remote_branch"),
                        self.tr("push.track"),
                    );
                    for row in &mut dialog.rows {
                        push_branch_table_row(
                            ui,
                            self.language,
                            table_width,
                            row,
                            &remote_branches,
                        );
                    }
                });

            ui.add_space(8.0);
            let mut all_selected =
                !dialog.rows.is_empty() && dialog.rows.iter().all(|row| row.selected);
            if action_checkbox(ui, &mut all_selected, self.tr("push.select_all")).changed() {
                for row in &mut dialog.rows {
                    row.selected = all_selected;
                    if row.selected && row.remote_branch.trim().is_empty() {
                        row.remote_branch = row.local_branch.clone();
                    }
                }
            }

            ui.add_space(8.0);
            ui.horizontal(|ui| {
                action_checkbox(ui, &mut dialog.push_tags, self.tr("push.push_tags"));
                action_checkbox(ui, &mut dialog.force, self.tr("push.force"));
            });

            ui.add_space(12.0);
            ui.horizontal(|ui| {
                ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                    let selected_push_branches = Self::selected_push_branches(&dialog);
                    let selected_count = dialog.rows.iter().filter(|row| row.selected).count();
                    let has_blank_selected_branch = dialog
                        .rows
                        .iter()
                        .any(|row| row.selected && row.remote_branch.trim().is_empty());
                    let default_action_enabled = actions_enabled
                        && !dialog.remote.trim().is_empty()
                        && !has_blank_selected_branch
                        && (selected_count > 0 || dialog.push_tags);
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui
                        .add_enabled(
                            default_action_enabled,
                            egui::Button::new(self.tr("action.push")),
                        )
                        .clicked()
                        || (submit_requested && default_action_enabled)
                    {
                        let remote = dialog.remote.trim().to_owned();
                        let branches = selected_push_branches;
                        let options = git::PushOptions {
                            push_tags: dialog.push_tags,
                            force: dialog.force,
                        };
                        if dialog.force {
                            self.pending_force_push_confirm = Some(ConfirmForcePushDialog {
                                remote,
                                branches,
                                options,
                            });
                        } else {
                            push_after_close = Some((remote, branches, options));
                        }
                        close_after = true;
                    }
                });
            });
        });

        if let Some((remote, branches, options)) = push_after_close {
            self.start_push_with_credential_retry(remote, branches, options);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_push_action = Some(dialog);
        }
    }

    fn force_push_confirm_modal(&mut self, ctx: &egui::Context) {
        let Some(dialog) = self.pending_force_push_confirm.take() else {
            return;
        };

        let mut keep_open = true;
        let mut push_after_close: Option<(String, Vec<git::PushBranchSpec>, git::PushOptions)> =
            None;
        compact_action_dialog(
            ctx,
            self.tr("push.force_confirm.title"),
            ACTION_DIALOG_WIDTH,
            |ui| {
                ui.label(RichText::new(self.tr("push.force_confirm.message")).color(theme::text()));
                ui.add_space(8.0);
                for branch in &dialog.branches {
                    ui.label(
                        RichText::new(format!(
                            "{} -> {}/{}",
                            branch.local_branch, dialog.remote, branch.remote_branch
                        ))
                        .small()
                        .color(theme::muted()),
                    );
                }
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                        if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                            keep_open = false;
                        }
                        if dialog_primary_button(ui, self.tr("push.force_confirm.submit"), true)
                            .clicked()
                        {
                            let remote = dialog.remote.clone();
                            let branches = dialog.branches.clone();
                            let options = dialog.options;
                            push_after_close = Some((remote, branches, options));
                            keep_open = false;
                        }
                    });
                });
            },
        );

        if let Some((remote, branches, options)) = push_after_close {
            self.start_push_with_credential_retry(remote, branches, options);
        }
        if keep_open {
            self.pending_force_push_confirm = Some(dialog);
        }
    }

    fn create_pull_request_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_create_pull_request.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut push_after_close: Option<(String, String, String)> = None;
        let actions_enabled = !self.branch_actions_busy();
        let remotes = self.remote_names();
        if !remotes.iter().any(|remote| remote == &dialog.remote) {
            dialog.remote = remotes
                .first()
                .cloned()
                .unwrap_or_else(|| "origin".to_owned());
        }
        let local_branches = self
            .snapshot
            .as_ref()
            .map(|snapshot| {
                snapshot
                    .branches
                    .iter()
                    .filter(|branch| !branch.remote)
                    .map(|branch| branch.name.clone())
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();
        if !local_branches
            .iter()
            .any(|branch| branch == &dialog.local_branch)
        {
            dialog.local_branch = local_branches
                .first()
                .cloned()
                .unwrap_or_else(|| dialog.local_branch.clone());
        }
        if dialog.remote_branch.trim().is_empty() {
            dialog.remote_branch = dialog.local_branch.clone();
        }
        let remote_branches = self.remote_branch_names_for(&dialog.remote);
        let remote_branch_choices = pull_request_remote_branch_choices(
            &dialog.local_branch,
            &dialog.remote_branch,
            &remote_branches,
        );
        let remote_base_url = self
            .remote_url_for_name(&dialog.remote)
            .and_then(|remote_url| remote_web_url(&remote_url));
        let remote_display = remote_base_url
            .as_ref()
            .map(|base_url| format!("{}: {}", dialog.remote, base_url))
            .unwrap_or_else(|| format!("{}: {}", dialog.remote, self.tr("repo.remote.missing")));

        compact_action_dialog(
            ctx,
            self.tr("pull_request.title"),
            PULL_DIALOG_WIDTH,
            |ui| {
                ui.horizontal(|ui| {
                    ui.label(
                        RichText::new(self.tr("pull_request.remote"))
                            .small()
                            .color(theme::muted()),
                    );
                    egui::ComboBox::from_id_salt("pull_request_remote_selector")
                        .width(ui.available_width())
                        .selected_text(remote_display.as_str())
                        .show_ui(ui, |ui| {
                            for remote in &remotes {
                                let remote_label = self
                                    .remote_url_for_name(remote)
                                    .and_then(|remote_url| remote_web_url(&remote_url))
                                    .map(|base_url| format!("{remote}: {base_url}"))
                                    .unwrap_or_else(|| {
                                        format!("{remote}: {}", self.tr("repo.remote.missing"))
                                    });
                                if ui
                                    .selectable_value(
                                        &mut dialog.remote,
                                        remote.clone(),
                                        remote_label,
                                    )
                                    .clicked()
                                {
                                    dialog.validation_error = None;
                                    let branches = self.remote_branch_names_for(&dialog.remote);
                                    let choices = pull_request_remote_branch_choices(
                                        &dialog.local_branch,
                                        &dialog.remote_branch,
                                        &branches,
                                    );
                                    if !choices.iter().any(|branch| branch == &dialog.remote_branch)
                                    {
                                        dialog.remote_branch =
                                            choices.first().cloned().unwrap_or_default();
                                    }
                                }
                            }
                        });
                });
                ui.add_space(6.0);
                ui.horizontal(|ui| {
                    ui.label(
                        RichText::new(self.tr("pull_request.local_branch"))
                            .small()
                            .color(theme::muted()),
                    );
                    let branch_choices = local_branches
                        .iter()
                        .map(|branch| (branch.clone(), branch.clone()))
                        .collect::<Vec<_>>();
                    if searchable_branch_dropdown(
                        ui,
                        egui::Id::new("pull_request_local_branch_selector"),
                        &mut dialog.local_branch,
                        &branch_choices,
                        ui.available_width(),
                        self.tr("pull_request.local_branch"),
                        self.tr("repo.source.search"),
                    ) && dialog.remote_branch.trim().is_empty()
                    {
                        dialog.remote_branch = dialog.local_branch.clone();
                    }
                });
                ui.add_space(6.0);
                ui.horizontal(|ui| {
                    ui.label(
                        RichText::new(self.tr("pull_request.remote_branch"))
                            .small()
                            .color(theme::muted()),
                    );
                    let branch_choices = remote_branch_choices
                        .iter()
                        .map(|branch| (branch.clone(), branch.clone()))
                        .collect::<Vec<_>>();
                    searchable_branch_dropdown(
                        ui,
                        egui::Id::new("pull_request_remote_branch_selector"),
                        &mut dialog.remote_branch,
                        &branch_choices,
                        ui.available_width(),
                        self.tr("pull_request.remote_branch"),
                        self.tr("repo.source.search"),
                    );
                });
                ui.add_space(4.0);
                ui.label(
                    RichText::new(self.tr("pull_request.hint"))
                        .small()
                        .color(theme::muted()),
                );
                if let Some(error) = dialog.validation_error.as_ref() {
                    ui.add_space(6.0);
                    ui.label(RichText::new(error).color(theme::warning()).strong());
                }
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                        if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                        let submit_requested = dialog_default_submit_requested(ui);
                        if dialog_primary_button(
                            ui,
                            self.tr("pull_request.submit"),
                            actions_enabled,
                        )
                        .clicked()
                            || (submit_requested && actions_enabled)
                        {
                            let remote = dialog.remote.trim().to_owned();
                            let local_branch = dialog.local_branch.trim().to_owned();
                            let remote_branch = dialog.remote_branch.trim().to_owned();
                            let base_url = self
                                .remote_url_for_name(&remote)
                                .and_then(|remote_url| remote_web_url(&remote_url));
                            let validation_error = if remote.is_empty() {
                                Some(self.tr("pull_request.error.remote_invalid").to_owned())
                            } else if base_url.is_none() {
                                Some(self.tr("repo.remote.missing").to_owned())
                            } else if !local_branches.iter().any(|branch| branch == &local_branch) {
                                Some(
                                    self.tr("pull_request.error.local_branch_invalid")
                                        .to_owned(),
                                )
                            } else if !valid_checkout_local_branch_name(&remote_branch) {
                                Some(
                                    self.tr("pull_request.error.remote_branch_invalid")
                                        .to_owned(),
                                )
                            } else {
                                None
                            };

                            if let Some(error) = validation_error {
                                dialog.validation_error = Some(error);
                            } else if let (Some(snapshot), Some(base_url)) =
                                (self.snapshot.as_ref(), base_url)
                            {
                                self.pending_pull_request_open_after_push =
                                    Some(PullRequestOpenAfterPush {
                                        root: snapshot.root.clone(),
                                        base_url,
                                        branch: remote_branch.clone(),
                                    });
                                push_after_close = Some((remote, local_branch, remote_branch));
                                close_after = true;
                            }
                        }
                    });
                });
            },
        );

        if let Some((remote, local_branch, remote_branch)) = push_after_close {
            self.start_pull_request_push_with_credential_retry(remote, local_branch, remote_branch);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_create_pull_request = Some(dialog);
        }
    }

    fn commit_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_commit_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let mut undo_label: Option<String> = None;
        let remotes = self.remote_names();

        let title = match &dialog {
            CommitActionDialog::CreateBranch { .. } => self.tr("branch.create"),
            CommitActionDialog::CreateTag { .. } => self.tr("menu.create_tag"),
            CommitActionDialog::ConfirmCheckout { .. } => self.tr("menu.checkout_commit"),
            CommitActionDialog::ConfirmCherryPick { .. } => self.tr("menu.cherry_pick"),
            CommitActionDialog::ConfirmCherryPickBatch { .. } => {
                self.tr("commit.cherry_pick_batch")
            }
            CommitActionDialog::ConfirmRevert { .. } => self.tr("menu.revert"),
            CommitActionDialog::ConfirmReset { .. } => self.tr("menu.reset"),
        };

        compact_action_dialog(ctx, title, ACTION_DIALOG_WIDTH, |ui| match &mut dialog {
            CommitActionDialog::CreateBranch {
                hash,
                short_hash,
                name,
                checkout,
            } => {
                ui.label(
                    RichText::new(format!("{} {short_hash}", self.tr("commit.create_from")))
                        .color(theme::muted()),
                );
                ui.add_space(8.0);
                ui.label(
                    RichText::new(self.tr("branch.name"))
                        .small()
                        .color(theme::muted()),
                );
                let name_hint = placeholder_for_label(self.language, self.tr("branch.name"));
                themed_text_edit_selection(ui);
                ui.add(themed_singleline_text_edit(name, &name_hint));
                action_checkbox(ui, checkout, self.tr("branch.checkout"));
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if (ui.button(self.tr("dialog.create")).clicked() || submit_requested)
                        && !name.trim().is_empty()
                    {
                        let branch_name = name.trim().to_owned();
                        let hash = hash.clone();
                        let checkout = *checkout;
                        execute = Some(Box::new(move |root| {
                            git::create_branch(root, &branch_name, &hash, checkout)
                        }));
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::CreateTag {
                hash,
                short_hash,
                name,
                push_after_create,
                remote,
            } => {
                ui.label(
                    RichText::new(format!("{} {short_hash}", self.tr("commit.tag_commit")))
                        .color(theme::muted()),
                );
                ui.add_space(8.0);
                ui.label(
                    RichText::new(self.tr("tag.name"))
                        .small()
                        .color(theme::muted()),
                );
                let name_hint = placeholder_for_label(self.language, self.tr("tag.name"));
                themed_text_edit_selection(ui);
                ui.add(themed_singleline_text_edit(name, &name_hint));
                action_checkbox(ui, push_after_create, self.tr("tag.push_after_create"));
                if *push_after_create {
                    tag_remote_selector(ui, self.language, &remotes, remote);
                }
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if (ui.button(self.tr("dialog.create")).clicked() || submit_requested)
                        && !name.trim().is_empty()
                    {
                        let tag_name = name.trim().to_owned();
                        let hash = hash.clone();
                        let push_after_create = *push_after_create;
                        let remote = remote.trim().to_owned();
                        execute = Some(Box::new(move |root| {
                            git::create_tag(root, &tag_name, &hash)?;
                            if push_after_create && !remote.is_empty() {
                                git::push_tag(root, &remote, &tag_name)?;
                            }
                            Ok(())
                        }));
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::ConfirmCheckout { hash, short_hash } => {
                ui.label(
                    RichText::new(format!(
                        "{} {short_hash}?",
                        self.tr("commit.checkout_confirm")
                    ))
                    .color(theme::text()),
                );
                ui.label(RichText::new(self.tr("commit.detached_warning")).color(theme::warning()));
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui.button(self.tr("dialog.checkout")).clicked() || submit_requested {
                        let hash = hash.clone();
                        execute = Some(Box::new(move |root| git::checkout_commit(root, &hash)));
                        undo_label = Some(self.tr("dialog.checkout").to_owned());
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::ConfirmCherryPick { hash, short_hash } => {
                ui.label(RichText::new(self.tr("commit.confirm_cherry_pick")).color(theme::text()));
                ui.label(
                    RichText::new(short_hash.as_str())
                        .monospace()
                        .color(theme::muted()),
                );
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui.button(self.tr("menu.cherry_pick")).clicked() || submit_requested {
                        let hash = hash.clone();
                        execute = Some(Box::new(move |root| git::cherry_pick_commit(root, &hash)));
                        undo_label = Some(self.tr("menu.cherry_pick").to_owned());
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::ConfirmCherryPickBatch {
                hashes,
                short_hashes,
            } => {
                ui.label(
                    RichText::new(self.tr("commit.confirm_cherry_pick_batch")).color(theme::text()),
                );
                ui.label(
                    RichText::new(format!(
                        "{} {}",
                        hashes.len(),
                        self.tr("commit.cherry_pick_selected")
                    ))
                    .color(theme::muted()),
                );
                ui.label(
                    RichText::new(short_hashes.join(", "))
                        .monospace()
                        .color(theme::muted()),
                );
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui.button(self.tr("menu.cherry_pick")).clicked() || submit_requested {
                        let hashes = hashes.clone();
                        execute = Some(Box::new(move |root| {
                            git::cherry_pick_commits(root, &hashes)
                        }));
                        undo_label = Some(self.tr("menu.cherry_pick").to_owned());
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::ConfirmRevert { hash, short_hash } => {
                ui.label(RichText::new(self.tr("commit.confirm_revert")).color(theme::text()));
                ui.label(
                    RichText::new(short_hash.as_str())
                        .monospace()
                        .color(theme::muted()),
                );
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui.button(self.tr("menu.revert")).clicked() || submit_requested {
                        let hash = hash.clone();
                        execute = Some(Box::new(move |root| git::revert_commit(root, &hash)));
                        undo_label = Some(self.tr("menu.revert").to_owned());
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
            CommitActionDialog::ConfirmReset {
                hash,
                short_hash,
                mode,
            } => {
                ui.label(RichText::new(self.tr("commit.confirm_reset")).color(theme::warning()));
                ui.label(
                    RichText::new(short_hash.as_str())
                        .monospace()
                        .color(theme::muted()),
                );
                ui.add_space(8.0);
                ui.radio_value(mode, ResetMode::Soft, self.tr("reset.soft"));
                ui.radio_value(mode, ResetMode::Mixed, self.tr("reset.mixed"));
                ui.radio_value(mode, ResetMode::Hard, self.tr("reset.hard"));
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui.button(self.tr("menu.reset")).clicked() || submit_requested {
                        let hash = hash.clone();
                        let mode = *mode;
                        execute = Some(Box::new(move |root| {
                            git::reset_to_commit(root, &hash, mode)
                        }));
                        if mode == ResetMode::Hard {
                            undo_label = Some(self.tr("menu.reset").to_owned());
                        }
                        close_after = true;
                    }
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                });
            }
        });

        if let Some(action) = execute {
            if let Some(label) = undo_label {
                self.start_undoable_git_action(label, RepositoryUndoKind::Position, action);
            } else {
                self.execute_git_action(action);
            }
            self.clear_cherry_pick_selection();
        }

        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_commit_action = Some(dialog);
        }
    }

    fn worktree_action_modal(&mut self, ctx: &egui::Context) {
        let Some(dialog) = self.pending_worktree_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;

        match dialog {
            WorktreeActionDialog::ConfirmDiscard { path, untracked } => {
                compact_action_dialog(
                    ctx,
                    self.tr("worktree.discard"),
                    ACTION_DIALOG_WIDTH,
                    |ui| {
                        ui.label(RichText::new(&path).monospace().color(theme::text()));
                        ui.label(
                            RichText::new(if untracked {
                                self.tr("worktree.discard_untracked_warning")
                            } else {
                                self.tr("worktree.discard_tracked_warning")
                            })
                            .color(theme::warning()),
                        );
                        ui.add_space(12.0);
                        ui.horizontal(|ui| {
                            let submit_requested = dialog_default_submit_requested(ui);
                            if ui.button(self.tr("dialog.discard")).clicked() || submit_requested {
                                let path = path.clone();
                                execute = Some(Box::new(move |root| {
                                    if untracked {
                                        git::clean_untracked_path(root, &path)
                                    } else {
                                        git::discard_path(root, &path)
                                    }
                                }));
                                close_after = true;
                            }
                            if ui.button(self.tr("dialog.cancel")).clicked() {
                                close_after = true;
                            }
                        });
                    },
                );

                if let Some(action) = execute {
                    self.execute_git_action(action);
                }
                if close_after {
                    keep_open = false;
                }
                if keep_open {
                    self.pending_worktree_action =
                        Some(WorktreeActionDialog::ConfirmDiscard { path, untracked });
                }
            }
            WorktreeActionDialog::ConfirmDiscardAll => {
                compact_action_dialog(ctx, self.tr("repo_discard"), ACTION_DIALOG_WIDTH, |ui| {
                    ui.label(
                        RichText::new(self.tr("worktree.discard_all_confirm")).color(theme::text()),
                    );
                    ui.label(
                        RichText::new(self.tr("worktree.discard_all_warning"))
                            .color(theme::warning()),
                    );
                    ui.add_space(12.0);
                    ui.horizontal(|ui| {
                        let submit_requested = dialog_default_submit_requested(ui);
                        if ui.button(self.tr("dialog.discard")).clicked() || submit_requested {
                            execute = Some(Box::new(move |root| git::discard_all_changes(root)));
                            close_after = true;
                        }
                        if ui.button(self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                    });
                });

                if let Some(action) = execute {
                    self.execute_git_action(action);
                }
                if close_after {
                    keep_open = false;
                }
                if keep_open {
                    self.pending_worktree_action = Some(WorktreeActionDialog::ConfirmDiscardAll);
                }
            }
            WorktreeActionDialog::ResolveConflicts { selected_path } => {
                let conflict_files = self
                    .snapshot
                    .as_ref()
                    .map(worktree_conflict_files)
                    .unwrap_or_default();
                let mut selected_path =
                    selected_path.or_else(|| conflict_files.first().map(|file| file.path.clone()));
                let mut accept_side = None;
                let mut merge_path = None;

                let modal_rect = conflict_resolution_modal_rect(ctx);
                egui::Area::new(egui::Id::new("conflict_resolution_modal"))
                    .order(egui::Order::Foreground)
                    .fixed_pos(modal_rect.min)
                    .show(ctx, |ui| {
                        safe_set_min_size(ui, CONFLICT_MODAL_SIZE);
                        ui.set_max_size(CONFLICT_MODAL_SIZE);
                        soft_panel_frame(conflict_resolution_dialog_background(), 12, 12).show(
                            ui,
                            |ui| {
                                safe_set_min_size(ui, CONFLICT_MODAL_INNER_SIZE);
                                ui.set_max_size(CONFLICT_MODAL_INNER_SIZE);
                                ui.with_layout(Layout::top_down(Align::Min), |ui| {
                                    ui.allocate_ui_with_layout(
                                        Vec2::new(CONFLICT_MODAL_INNER_SIZE.x, 32.0),
                                        Layout::right_to_left(Align::Center),
                                        |ui| {
                                            if window_control_button(ui, "\u{00d7}", true).clicked()
                                            {
                                                close_after = true;
                                            }
                                        },
                                    );
                                    ui.add_space(8.0);
                                    let content_height = ui.available_height();
                                    let panel_size =
                                        Vec2::new(CONFLICT_LIST_PANEL_SIZE.x, content_height);
                                    let action_panel_size =
                                        Vec2::new(CONFLICT_ACTION_PANEL_SIZE.x, content_height);
                                    ui.horizontal(|ui| {
                                        ui.allocate_ui_with_layout(
                                            panel_size,
                                            Layout::top_down(Align::Min),
                                            |ui| {
                                                conflict_resolution_list_panel(
                                                    ui,
                                                    panel_size,
                                                    &conflict_files,
                                                    self.language,
                                                    &mut selected_path,
                                                );
                                            },
                                        );
                                        ui.add_space(CONFLICT_MODAL_PANEL_GAP);
                                        ui.allocate_ui_with_layout(
                                            action_panel_size,
                                            Layout::top_down(Align::Min),
                                            |ui| {
                                                if let Some(action) =
                                                    conflict_resolution_actions_panel(
                                                        ui,
                                                        action_panel_size,
                                                        self.language,
                                                        selected_path.is_some(),
                                                    )
                                                {
                                                    match action {
                                                        ConflictResolutionDialogAction::Accept(
                                                            side,
                                                        ) => {
                                                            if let Some(path) =
                                                                selected_path.clone()
                                                            {
                                                                accept_side = Some((path, side));
                                                                close_after = true;
                                                            }
                                                        }
                                                        ConflictResolutionDialogAction::Merge => {
                                                            merge_path = selected_path.clone();
                                                            close_after = true;
                                                        }
                                                    }
                                                }
                                            },
                                        );
                                    });
                                });
                            },
                        );
                    });

                if let Some((path, side)) = accept_side {
                    self.execute_git_action(move |root| {
                        git::accept_conflict_side(root, &path, side)
                    });
                }
                if let Some(path) = merge_path {
                    self.open_conflict_merge_tool(&path);
                }
                if close_after {
                    keep_open = false;
                }
                if keep_open {
                    self.pending_worktree_action =
                        Some(WorktreeActionDialog::ResolveConflicts { selected_path });
                }
            }
        }
    }

    fn blame_action_modal(&mut self, ctx: &egui::Context) {
        let Some(dialog) = self.pending_blame_action.take() else {
            return;
        };
        let title = format!("{}: {}", self.tr("blame.title"), dialog.display_path);
        let path_label = self.tr("blame.path");
        let loading_label = self.tr("blame.loading");
        let empty_label = self.tr("blame.empty");
        let line_label = self.tr("blame.line");
        let commit_label = self.tr("blame.commit");
        let author_label = self.tr("blame.author");
        let summary_label = self.tr("blame.summary");
        let content_label = self.tr("blame.content");
        let close_label = self.tr("dialog.close");
        let mut close_after = false;

        compact_action_dialog(ctx, &title, 860.0, |ui| {
            ui.label(
                RichText::new(format!("{path_label}: {}", dialog.display_path))
                    .small()
                    .color(theme::muted()),
            );
            ui.add_space(8.0);

            if let Some(lines) = dialog.lines.as_ref() {
                if lines.is_empty() {
                    ui.label(RichText::new(empty_label).color(theme::muted()));
                } else {
                    ScrollArea::both()
                        .id_salt(("blame_lines_scroll", dialog.path.as_str()))
                        .max_height(430.0)
                        .auto_shrink([false, false])
                        .show(ui, |ui| {
                            egui::Grid::new(("blame_lines_grid", dialog.path.as_str()))
                                .num_columns(5)
                                .spacing(Vec2::new(14.0, 4.0))
                                .striped(false)
                                .show(ui, |ui| {
                                    for label in [
                                        line_label,
                                        commit_label,
                                        author_label,
                                        summary_label,
                                        content_label,
                                    ] {
                                        ui.label(
                                            RichText::new(label).small().color(theme::muted()),
                                        );
                                    }
                                    ui.end_row();

                                    for line in lines {
                                        ui.label(
                                            RichText::new(line.final_line.to_string())
                                                .monospace()
                                                .color(theme::muted()),
                                        );
                                        ui.add(
                                            egui::Label::new(
                                                RichText::new(line.short_commit.as_str())
                                                    .monospace()
                                                    .color(theme::accent()),
                                            )
                                            .selectable(true),
                                        );
                                        ui.add(
                                            egui::Label::new(
                                                RichText::new(line.author.as_str())
                                                    .color(theme::text()),
                                            )
                                            .selectable(true),
                                        );
                                        ui.add(
                                            egui::Label::new(
                                                RichText::new(line.summary.as_str())
                                                    .color(theme::muted()),
                                            )
                                            .selectable(true),
                                        );
                                        ui.add(
                                            egui::Label::new(
                                                RichText::new(line.content.as_str())
                                                    .monospace()
                                                    .color(theme::text()),
                                            )
                                            .selectable(true),
                                        );
                                        ui.end_row();
                                    }
                                });
                        });
                }
            } else {
                ui.horizontal(|ui| {
                    ui.spinner();
                    ui.label(RichText::new(loading_label).color(theme::muted()));
                });
            }

            ui.add_space(12.0);
            ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                if ui.button(close_label).clicked() {
                    close_after = true;
                }
            });
        });

        if close_after {
            self.blame_task = None;
        } else {
            self.pending_blame_action = Some(dialog);
        }
    }

    fn create_patch_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_create_patch_action.take() else {
            return;
        };
        if !self.active_repo_root_matches(&dialog.repo_root) {
            return;
        }

        if dialog.overwrite_request.is_some() {
            let mut confirm_overwrite = false;
            let mut return_to_dialog = false;
            compact_action_dialog(ctx, self.tr("patch.create.overwrite_title"), 560.0, |ui| {
                ui.label(
                    RichText::new(self.tr("patch.create.overwrite_message")).color(theme::text()),
                );
                ui.add_space(6.0);
                ScrollArea::vertical()
                    .id_salt("create_patch_overwrite_paths")
                    .max_height(150.0)
                    .auto_shrink([false, true])
                    .show(ui, |ui| {
                        for path in &dialog.overwrite_paths {
                            ui.add(
                                egui::Label::new(
                                    RichText::new(user_facing_path_string(path))
                                        .monospace()
                                        .color(theme::muted()),
                                )
                                .selectable(true),
                            );
                        }
                    });
                ui.add_space(10.0);
                ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                    if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                        return_to_dialog = true;
                    }
                    if dialog_primary_button(
                        ui,
                        self.tr("patch.create.overwrite_confirm"),
                        !self.branch_actions_busy(),
                    )
                    .clicked()
                    {
                        confirm_overwrite = true;
                    }
                });
            });
            if return_to_dialog {
                dialog.overwrite_request = None;
                dialog.overwrite_paths.clear();
            } else if confirm_overwrite {
                let request = dialog.overwrite_request.take().expect("checked above");
                dialog.overwrite_paths.clear();
                self.start_create_patch_task(request);
            }
            self.pending_create_patch_action = Some(dialog);
            return;
        }

        let worktree_files = self
            .snapshot
            .as_ref()
            .filter(|snapshot| paths_equal(&snapshot.root, &dialog.repo_root))
            .map(|snapshot| {
                let mut files = BTreeMap::new();
                for file in snapshot.staged.iter().chain(&snapshot.unstaged) {
                    files
                        .entry(file.path.clone())
                        .or_insert_with(|| file.clone());
                }
                files.into_values().collect::<Vec<_>>()
            })
            .unwrap_or_default();
        let commits = self
            .snapshot
            .as_ref()
            .filter(|snapshot| paths_equal(&snapshot.root, &dialog.repo_root))
            .map(|snapshot| {
                history_dialog_commits(snapshot, dialog.branch_scope, dialog.sort_order)
            })
            .unwrap_or_default();
        let available_hashes = self
            .snapshot
            .as_ref()
            .filter(|snapshot| paths_equal(&snapshot.root, &dialog.repo_root))
            .map(|snapshot| {
                history_dialog_commits(snapshot, HistoryBranchScope::All, dialog.sort_order)
                    .into_iter()
                    .map(|commit| commit.hash)
                    .collect::<HashSet<_>>()
            })
            .unwrap_or_default();
        dialog.commit_selection.retain_available(&available_hashes);
        if !commits
            .iter()
            .any(|commit| commit.hash == dialog.focused_commit_hash)
        {
            dialog.focused_commit_hash = commits
                .first()
                .map(|commit| commit.hash.clone())
                .unwrap_or_default();
            dialog.selected_file_path = None;
            dialog.selected_diff_rows.clear();
        }
        let patch_running = self.create_patch_busy();
        let actions_enabled = !self.branch_actions_busy();
        let mut close_after = false;
        let mut request = None;
        let mut hash_copied = false;
        let dialog_width = match dialog.tab {
            CreatePatchTab::Worktree => 640.0,
            CreatePatchTab::History => 960.0,
        };

        compact_action_dialog(ctx, self.tr("patch.create.title"), dialog_width, |ui| {
            ui.horizontal(|ui| {
                if AppButton::repo_tab(
                    UiIcon::Workspace,
                    self.tr("patch.create.worktree_tab"),
                    dialog.tab == CreatePatchTab::Worktree,
                )
                .show(ui)
                .clicked()
                {
                    dialog.tab = CreatePatchTab::Worktree;
                    dialog.validation_error_key = None;
                }
                if AppButton::repo_tab(
                    UiIcon::History,
                    self.tr("patch.create.history_tab"),
                    dialog.tab == CreatePatchTab::History,
                )
                .show(ui)
                .clicked()
                {
                    dialog.tab = CreatePatchTab::History;
                    dialog.validation_error_key = None;
                }
            });

            ui.add_space(8.0);
            if patch_running {
                ui.horizontal(|ui| {
                    ui.spinner();
                    ui.label(RichText::new(self.tr("patch.create.running")).color(theme::muted()));
                });
                ui.add_space(6.0);
            }
            match dialog.tab {
                CreatePatchTab::Worktree => {
                    if worktree_files.is_empty() {
                        ui.allocate_ui(Vec2::new(ui.available_width(), 72.0), |ui| {
                            ui.centered_and_justified(|ui| {
                                ui.label(
                                    RichText::new(self.tr("patch.create.empty_worktree"))
                                        .color(theme::muted()),
                                );
                            });
                        });
                    } else {
                        let mut all_selected = worktree_files.iter().all(|file| {
                            dialog.selected_worktree_paths.contains(file.path.as_str())
                        });
                        let selected_label = format!(
                            "{} ({}/{})",
                            self.tr("patch.create.changed_files"),
                            dialog.selected_worktree_paths.len(),
                            worktree_files.len()
                        );
                        if action_checkbox(ui, &mut all_selected, &selected_label).changed() {
                            if all_selected {
                                dialog
                                    .selected_worktree_paths
                                    .extend(worktree_files.iter().map(|file| file.path.clone()));
                            } else {
                                dialog.selected_worktree_paths.clear();
                            }
                        }
                        ui.add_space(4.0);
                        ScrollArea::vertical()
                            .id_salt("create_patch_worktree_files")
                            .max_height(create_patch_worktree_list_height(worktree_files.len()))
                            .auto_shrink([false, true])
                            .show(ui, |ui| {
                                ui.spacing_mut().item_spacing.y = 2.0;
                                for file in &worktree_files {
                                    let mut selected =
                                        dialog.selected_worktree_paths.contains(file.path.as_str());
                                    if action_checkbox(ui, &mut selected, &file.display_path)
                                        .changed()
                                    {
                                        if selected {
                                            dialog
                                                .selected_worktree_paths
                                                .insert(file.path.clone());
                                        } else {
                                            dialog.selected_worktree_paths.remove(&file.path);
                                        }
                                    }
                                }
                            });
                    }
                }
                CreatePatchTab::History => {
                    hash_copied |= self.create_patch_history_tab(ui, &mut dialog, &commits);
                }
            }

            ui.add_space(8.0);
            ui.horizontal(|ui| {
                ui.add_sized(
                    [96.0, 24.0],
                    egui::Label::new(
                        RichText::new(self.tr("patch.create.output_path")).color(theme::text()),
                    ),
                );
                let hint =
                    placeholder_for_label(self.language, self.tr("patch.create.output_path"));
                themed_text_edit_selection(ui);
                ui.add_sized(
                    [(ui.available_width() - 42.0).max(120.0), 24.0],
                    themed_singleline_text_edit(&mut dialog.output_path, &hint),
                );
                if ui
                    .add_enabled(actions_enabled, egui::Button::new("..."))
                    .on_hover_text(self.tr("patch.create.browse"))
                    .clicked()
                {
                    let picker = rfd::FileDialog::new()
                        .set_directory(&dialog.repo_root)
                        .set_file_name("patch.diff")
                        .add_filter("Patch", &["patch", "diff"]);
                    if let Some(path) = picker.save_file() {
                        dialog.output_path = user_facing_path_string(&path);
                        dialog.validation_error_key = None;
                    }
                }
            });

            if dialog.tab == CreatePatchTab::History {
                action_checkbox(
                    ui,
                    &mut dialog.separate_files,
                    self.tr("patch.create.separate_files"),
                );
            }

            if let Some(error_key) = dialog.validation_error_key {
                ui.add_space(4.0);
                ui.label(RichText::new(self.tr(error_key)).color(theme::warning()));
            }

            let no_selection = match dialog.tab {
                CreatePatchTab::Worktree => dialog.selected_worktree_paths.is_empty(),
                CreatePatchTab::History => dialog.commit_selection.is_empty(),
            };
            let output_path = PathBuf::from(dialog.output_path.trim());
            let path_valid = validate_patch_output_path(&output_path).is_ok();
            let can_submit = actions_enabled && !no_selection && path_valid;

            ui.add_space(10.0);
            ui.horizontal(|ui| {
                ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                    ui.add_enabled_ui(!patch_running, |ui| {
                        if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                    });
                    if dialog_primary_button(ui, self.tr("patch.create.submit"), can_submit)
                        .clicked()
                    {
                        if no_selection {
                            dialog.validation_error_key = Some("patch.create.no_selection");
                        } else if let Err(error) = validate_patch_output_path(&output_path) {
                            dialog.validation_error_key = Some(match error {
                                PatchPathError::Empty
                                | PatchPathError::Directory
                                | PatchPathError::MissingParent => "patch.create.invalid_output",
                            });
                        } else {
                            let candidate = match dialog.tab {
                                CreatePatchTab::Worktree => git::CreatePatchRequest::Worktree {
                                    output_path,
                                    paths: dialog.selected_worktree_paths.iter().cloned().collect(),
                                },
                                CreatePatchTab::History => git::CreatePatchRequest::Commits {
                                    output_path,
                                    hashes: dialog.commit_selection.ordered(),
                                    separate: dialog.separate_files,
                                },
                            };
                            let existing_paths = create_patch_output_paths(&candidate)
                                .into_iter()
                                .filter(|path| path.exists())
                                .collect::<Vec<_>>();
                            if existing_paths.is_empty() {
                                request = Some(candidate);
                            } else {
                                dialog.overwrite_request = Some(candidate);
                                dialog.overwrite_paths = existing_paths;
                            }
                        }
                    }
                });
            });
        });

        if let Some(request) = request {
            self.start_create_patch_task(request);
        }
        if hash_copied {
            self.show_toast(self.tr("status.hash_copied"));
        }
        if !close_after {
            self.pending_create_patch_action = Some(dialog);
        }
    }

    fn create_patch_history_tab(
        &mut self,
        ui: &mut Ui,
        dialog: &mut CreatePatchDialog,
        commits: &[Commit],
    ) -> bool {
        if commits.is_empty() {
            ui.allocate_ui(Vec2::new(ui.available_width(), 470.0), |ui| {
                ui.centered_and_justified(|ui| {
                    ui.label(
                        RichText::new(self.tr("patch.create.history_empty")).color(theme::muted()),
                    );
                });
            });
            return false;
        }

        let selected_hashes = dialog
            .commit_selection
            .ordered()
            .into_iter()
            .collect::<HashSet<_>>();
        let browser_outcome = history_commit_browser(
            ui,
            commits,
            &dialog.focused_commit_hash,
            &mut dialog.branch_scope,
            &mut dialog.sort_order,
            &mut dialog.search,
            &mut dialog.show_remote_refs,
            self.history_show_branch_refs,
            self.history_show_tag_refs,
            &mut self.layout_prefs,
            self.language,
            &selected_hashes,
            &HashSet::new(),
            &mut dialog.history_cache,
            HistoryCommitBrowserConfig {
                id_salt: "create_patch_commit_browser_scroll",
                show_view_controls: true,
                show_search: true,
                show_cherry_pick: false,
                show_jump: false,
                show_context_menu: false,
                select_rows: false,
                multi_select: true,
                show_rebase_plan_controls: false,
                max_height: Some(245.0),
            },
            None,
        );
        if browser_outcome.prefs_changed {
            self.layout_prefs.save();
        }
        if let Some(intent) = browser_outcome.selection_intent {
            dialog.commit_selection.apply(
                &browser_outcome.visible_hashes,
                &intent.hash,
                intent.gesture,
            );
        }
        if browser_outcome.toggle_all_visible {
            let commit_selection = &mut dialog.commit_selection;
            commit_selection.toggle_visible(&browser_outcome.visible_hashes);
        }
        if let Some(commit) = browser_outcome.picked_commit {
            if dialog.focused_commit_hash != commit.hash {
                dialog.focused_commit_hash = commit.hash;
                dialog.selected_file_path = None;
                dialog.selected_diff_rows.clear();
            }
        }

        self.request_commit_details_hash(dialog.focused_commit_hash.clone());
        ui.add_space(8.0);
        self.create_patch_commit_preview(ui, dialog, commits);
        browser_outcome.hash_copied
    }

    fn create_patch_commit_preview(
        &mut self,
        ui: &mut Ui,
        dialog: &mut CreatePatchDialog,
        commits: &[Commit],
    ) {
        let Some(commit) = commits
            .iter()
            .find(|commit| commit.hash == dialog.focused_commit_hash)
            .cloned()
        else {
            return;
        };
        let details = self.details_cache.get(&commit.hash).cloned();
        if dialog.selected_file_path.is_none()
            && let Some(path) = details
                .as_ref()
                .and_then(|details| details.files.first())
                .map(|file| file.diff_path.clone())
        {
            dialog.selected_file_path = Some(path.clone());
            self.request_file_diff(commit.hash.clone(), path);
        }

        let height = 205.0;
        let width = ui.available_width();
        let gap = LAYOUT_GAP as f32;
        let left_width = (width * 0.42).max(300.0);
        let right_width = (width - left_width - gap).max(280.0);
        let (rect, _) = ui.allocate_exact_size(Vec2::new(width, height), Sense::hover());
        let left_rect = Rect::from_min_size(rect.left_top(), Vec2::new(left_width, height));
        let right_rect = Rect::from_min_size(
            Pos2::new(left_rect.right() + gap, rect.top()),
            Vec2::new(right_width, height),
        );

        let mut clicked_file = None;
        ui.allocate_new_ui(egui::UiBuilder::new().max_rect(left_rect), |ui| {
            source_tree_panel_frame().show(ui, |ui| {
                safe_set_min_size(ui, frame_inner_size(left_width, height, 8, 8));
                source_tree_meta_line(ui, self.tr("commit.author"), &commit.author);
                source_tree_meta_line(ui, self.tr("commit.when"), &commit.date);
                ui.label(RichText::new(&commit.subject).color(theme::text()));
                ui.add_space(4.0);
                history_file_table_header(ui, self.language);
                if self.loading_details_hash.as_deref() == Some(commit.hash.as_str()) {
                    ui.spinner();
                } else if let Some(details) = details.as_ref() {
                    ScrollArea::vertical()
                        .id_salt("create_patch_changed_files_scroll")
                        .max_height(112.0)
                        .auto_shrink([false, false])
                        .show(ui, |ui| {
                            for file in &details.files {
                                let selected = dialog.selected_file_path.as_deref()
                                    == Some(file.diff_path.as_str());
                                if history_file_table_row(ui, &file.status, &file.path, selected)
                                    .clicked()
                                {
                                    clicked_file = Some(file.diff_path.clone());
                                }
                            }
                        });
                }
            });
        });

        if let Some(path) = clicked_file {
            dialog.selected_file_path = Some(path.clone());
            dialog.selected_diff_rows.clear();
            self.request_file_diff(commit.hash.clone(), path);
        }

        ui.allocate_new_ui(egui::UiBuilder::new().max_rect(right_rect), |ui| {
            source_tree_panel_frame().show(ui, |ui| {
                safe_set_min_size(ui, frame_inner_size(right_width, height, 8, 8));
                let Some(path) = dialog.selected_file_path.as_ref() else {
                    ui.label(RichText::new(self.tr("commit.select_file")).color(theme::muted()));
                    return;
                };
                let key = git::diff_key(&commit.hash, path);
                if self.loading_diff_key.as_deref() == Some(key.as_str()) {
                    ui.spinner();
                    return;
                }
                let Some(diff) = self.diff_cache.get(&key) else {
                    ui.label(RichText::new(self.tr("diff.queued")).color(theme::muted()));
                    return;
                };
                fill_diff_scroll_area(
                    ui,
                    ("create_patch_diff_scroll", &commit.hash, path),
                    &diff.text,
                    dialog.diff_display_mode,
                    self.language,
                    &mut dialog.selected_diff_rows,
                    (diff.text.lines().count() > 1_200).then_some(self.tr("diff.truncated")),
                );
            });
        });
    }

    fn archive_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_archive_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let actions_enabled = !self.branch_actions_busy();
        let snapshot_root = self.snapshot.as_ref().map(|snapshot| snapshot.root.clone());
        let selected_commit = self
            .snapshot
            .as_ref()
            .and_then(|snapshot| {
                self.selected_commit
                    .and_then(|index| snapshot.commits.get(index))
                    .or_else(|| snapshot.commits.first())
            })
            .map(|commit| commit.short_hash.clone())
            .unwrap_or_else(|| "HEAD".to_owned());

        compact_action_dialog(ctx, self.tr("archive.title"), ARCHIVE_DIALOG_WIDTH, |ui| {
            ui.horizontal(|ui| {
                ui.add_sized(
                    [92.0, 24.0],
                    egui::Label::new(
                        RichText::new(self.tr("archive.output_path")).color(theme::text()),
                    ),
                );
                let output_path_hint =
                    placeholder_for_label(self.language, self.tr("archive.output_path"));
                themed_text_edit_selection(ui);
                ui.add_sized(
                    [ui.available_width() - 42.0, 24.0],
                    themed_singleline_text_edit(&mut dialog.output_path, &output_path_hint),
                );
                if ui.button("...").clicked() {
                    let mut file_dialog = rfd::FileDialog::new()
                        .add_filter("Zip archive", &["zip"])
                        .add_filter("Tar archive", &["tar", "tar.gz"])
                        .set_file_name("archive.zip");
                    if let Some(root) = snapshot_root.as_ref() {
                        file_dialog = file_dialog.set_directory(root);
                    }
                    if let Some(path) = file_dialog.save_file() {
                        dialog.output_path = user_facing_path_string(&path);
                    }
                }
            });
            ui.horizontal(|ui| {
                ui.add_sized(
                    [92.0, 24.0],
                    egui::Label::new(
                        RichText::new(self.tr("archive.folder_prefix")).color(theme::text()),
                    ),
                );
                let folder_prefix_hint =
                    placeholder_for_label(self.language, self.tr("archive.folder_prefix"));
                themed_text_edit_selection(ui);
                ui.add_sized(
                    [ui.available_width(), 24.0],
                    themed_singleline_text_edit(&mut dialog.folder_prefix, &folder_prefix_hint),
                );
            });
            ui.horizontal(|ui| {
                ui.add_sized(
                    [92.0, 24.0],
                    egui::Label::new(RichText::new(self.tr("archive.target")).color(theme::text())),
                );
                ui.radio_value(
                    &mut dialog.target,
                    ArchiveTarget::Worktree,
                    self.tr("archive.worktree"),
                );
            });
            ui.horizontal(|ui| {
                ui.add_sized([92.0, 24.0], egui::Label::new(""));
                ui.radio_value(
                    &mut dialog.target,
                    ArchiveTarget::Commit,
                    self.tr("archive.commit"),
                );
                ui.add_enabled_ui(dialog.target == ArchiveTarget::Commit, |ui| {
                    let target_commit_hint =
                        placeholder_for_label(self.language, self.tr("archive.commit"));
                    themed_text_edit_selection(ui);
                    ui.add_sized(
                        [ui.available_width() - 42.0, 24.0],
                        themed_singleline_text_edit(&mut dialog.target_commit, &target_commit_hint),
                    );
                    if ui.button("...").clicked() {
                        dialog.target = ArchiveTarget::Commit;
                        dialog.target_commit = selected_commit.clone();
                    }
                });
            });

            if let Some(error) = dialog.validation_error.as_ref() {
                ui.add_space(4.0);
                ui.label(RichText::new(error).color(theme::warning()).small());
            }

            ui.add_space(12.0);
            ui.horizontal(|ui| {
                ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                    if ui.button(self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                    let submit_requested = dialog_default_submit_requested(ui);
                    if ui
                        .add_enabled(actions_enabled, egui::Button::new(self.tr("dialog.ok")))
                        .clicked()
                        || (submit_requested && actions_enabled)
                    {
                        if let Some(error) = validate_archive_dialog(self.language, &dialog) {
                            dialog.validation_error = Some(error);
                        } else {
                            let output_path = PathBuf::from(dialog.output_path.trim());
                            let folder_prefix = dialog.folder_prefix.trim().to_owned();
                            let target = archive_target_ref(&dialog);
                            execute = Some(Box::new(move |root| {
                                git::archive(root, &output_path, &folder_prefix, &target)
                            }));
                            close_after = true;
                        }
                    }
                });
            });
        });

        if let Some(action) = execute {
            self.execute_git_action(action);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_archive_action = Some(dialog);
        }
    }

    fn interactive_rebase_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_interactive_rebase_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let mut hash_copied = false;
        let actions_enabled = !self.branch_actions_busy();
        let commits = self
            .snapshot
            .as_ref()
            .map(|snapshot| {
                interactive_rebase_commits_for_scope(
                    snapshot,
                    dialog.scope,
                    &dialog.base_hash,
                    dialog.sort_order,
                )
            })
            .unwrap_or_default();
        dialog.rewrites_published_history = self.snapshot.as_ref().is_some_and(|snapshot| {
            interactive_rebase_rewrites_published_history(snapshot, &commits)
        });
        let disabled_hashes = interactive_rebase_disabled_hashes(&commits);
        let plan_editing = dialog.editing_reword_hash.is_some();
        let mut table_disabled_hashes = disabled_hashes.clone();
        if plan_editing {
            table_disabled_hashes.extend(commits.iter().map(|commit| commit.hash.clone()));
        }
        dialog.selected_hashes.retain(|hash| {
            !disabled_hashes.contains(hash) && commits.iter().any(|commit| commit.hash == *hash)
        });
        if dialog
            .squash_target_hash
            .as_ref()
            .is_some_and(|hash| !dialog.selected_hashes.contains(hash))
        {
            dialog.squash_target_hash = None;
            dialog.squash_range_hashes.clear();
        }
        dialog
            .squash_range_hashes
            .retain(|hash| commits.iter().any(|commit| commit.hash == *hash));
        for commit in commits
            .iter()
            .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        {
            dialog
                .actions
                .entry(commit.hash.clone())
                .or_insert(InteractiveRebaseTodoAction::Pick);
        }
        interactive_rebase_synchronize_plan(&mut dialog, &commits);
        if disabled_hashes.contains(&dialog.selected_hash)
            || !commits
                .iter()
                .any(|commit| commit.hash == dialog.selected_hash)
        {
            if let Some(commit) = commits
                .iter()
                .find(|commit| !interactive_rebase_commit_is_merge(commit))
            {
                dialog.selected_hash = commit.hash.clone();
                dialog.selected_short_hash = commit.short_hash.clone();
            }
        }

        compact_action_dialog(
            ctx,
            self.tr("interactive_rebase.title"),
            INTERACTIVE_REBASE_DIALOG_WIDTH,
            |ui| {
                ui.label(
                    RichText::new(self.tr("interactive_rebase.select_commit"))
                        .small()
                        .color(theme::muted()),
                );
                ui.horizontal(|ui| {
                    ui.label(
                        RichText::new(self.tr("interactive_rebase.base_commit"))
                            .small()
                            .color(theme::muted()),
                    );
                    ui.label(
                        RichText::new(&dialog.base_short_hash)
                            .monospace()
                            .color(theme::text()),
                    );
                });
                if dialog.rewrites_published_history {
                    ui.label(
                        RichText::new(self.tr("interactive_rebase.published_warning"))
                            .small()
                            .color(theme::warning()),
                    );
                    action_checkbox(
                        ui,
                        &mut dialog.acknowledge_published_rewrite,
                        self.tr("interactive_rebase.confirm_published"),
                    );
                }
                ui.add_space(8.0);
                let table_commits = interactive_rebase_display_commits(&dialog, &commits);
                let browser_outcome = history_commit_browser(
                    ui,
                    &table_commits,
                    &dialog.selected_hash,
                    &mut dialog.branch_scope,
                    &mut dialog.sort_order,
                    &mut dialog.search,
                    &mut dialog.show_remote_refs,
                    self.history_show_branch_refs,
                    self.history_show_tag_refs,
                    &mut self.layout_prefs,
                    self.language,
                    &dialog.selected_hashes,
                    &table_disabled_hashes,
                    &mut dialog.history_cache,
                    HistoryCommitBrowserConfig {
                        id_salt: "interactive_rebase_commit_browser_scroll",
                        show_view_controls: true,
                        show_search: true,
                        show_cherry_pick: false,
                        show_jump: false,
                        show_context_menu: false,
                        select_rows: true,
                        multi_select: false,
                        show_rebase_plan_controls: true,
                        max_height: Some(430.0),
                    },
                    Some(HistoryRebasePlanControls {
                        actions: &mut dialog.actions,
                        autosquash_targets: &mut dialog.autosquash_targets,
                        reword_messages: &mut dialog.reword_messages,
                        reword_authors: &mut dialog.reword_authors,
                        confirmed_reword_hashes: &mut dialog.confirmed_reword_hashes,
                        editing_reword_hash: &mut dialog.editing_reword_hash,
                        ordered_hashes: &mut dialog.ordered_hashes,
                        dragged_hash: &mut dialog.dragged_hash,
                    }),
                );
                hash_copied |= browser_outcome.hash_copied;
                if browser_outcome.prefs_changed {
                    self.layout_prefs.save();
                }
                if let Some(commit) = browser_outcome.picked_commit {
                    dialog.selected_hash = commit.hash;
                    dialog.selected_short_hash = commit.short_hash;
                }
                if let Some(hash) = browser_outcome.toggled_cherry_pick_hash {
                    if !dialog.selected_hashes.insert(hash.clone()) {
                        dialog.selected_hashes.remove(&hash);
                    }
                }

                ui.add_space(10.0);
                let selected_actionable_hashes =
                    interactive_rebase_selected_actionable_hashes(&dialog, &commits)
                        .into_iter()
                        .filter(|hash| !dialog.confirmed_reword_hashes.contains(hash))
                        .collect::<Vec<_>>();
                let selected_batch_count = selected_actionable_hashes.len();
                let squash_targets = interactive_rebase_selected_squash_targets(&dialog, &commits)
                    .into_iter()
                    .filter(|commit| !dialog.confirmed_reword_hashes.contains(&commit.hash))
                    .collect::<Vec<_>>();
                let selected_squash_range_hashes =
                    interactive_rebase_selected_squash_range_hashes(&dialog, &commits)
                        .into_iter()
                        .filter(|hash| !dialog.confirmed_reword_hashes.contains(hash))
                        .collect::<Vec<_>>();
                let selected = commits
                    .iter()
                    .position(|commit| commit.hash == dialog.selected_hash)
                    .map(|index| {
                        let commit = &commits[index];
                        (
                            index,
                            commit.hash.clone(),
                            commit.short_hash.clone(),
                            commit.subject.clone(),
                            interactive_rebase_commit_is_merge(commit),
                        )
                    });
                if dialog
                    .squash_target_hash
                    .as_ref()
                    .is_none_or(|hash| !squash_targets.iter().any(|commit| commit.hash == *hash))
                {
                    dialog.squash_target_hash = selected
                        .as_ref()
                        .filter(|(_, hash, _, _, is_merge)| {
                            !*is_merge && squash_targets.iter().any(|commit| commit.hash == *hash)
                        })
                        .map(|(_, hash, _, _, _)| hash.clone())
                        .or_else(|| squash_targets.first().map(|commit| commit.hash.clone()));
                }

                if let Some(error) = dialog.validation_error.as_ref() {
                    ui.add_space(4.0);
                    ui.label(RichText::new(error).color(theme::warning()).small());
                }

                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    ui.label(
                        RichText::new(format!(
                            "{} {}",
                            self.tr("interactive_rebase.selected_count"),
                            selected_batch_count
                        ))
                        .small()
                        .color(theme::muted()),
                    );
                    if ui
                        .add_enabled(
                            !plan_editing,
                            egui::Button::new(self.tr("interactive_rebase.reset")),
                        )
                        .clicked()
                    {
                        let autosquash_plan = interactive_rebase_autosquash_plan(&commits);
                        dialog.actions = autosquash_plan.actions;
                        dialog.autosquash_targets = autosquash_plan.targets;
                        dialog.ordered_hashes = autosquash_plan.ordered_hashes;
                        dialog.dragged_hash = None;
                        dialog.squash_target_hash = None;
                        dialog.squash_range_hashes.clear();
                        dialog.reword_messages.clear();
                        dialog.reword_authors.clear();
                        dialog.confirmed_reword_hashes.clear();
                        dialog.editing_reword_hash = None;
                    }
                    if ui
                        .add_enabled(
                            !plan_editing && selected_batch_count > 0,
                            egui::Button::new(self.tr("interactive_rebase.drop_selected")),
                        )
                        .clicked()
                    {
                        dialog.squash_target_hash = None;
                        dialog.squash_range_hashes.clear();
                        for hash in &selected_actionable_hashes {
                            dialog
                                .actions
                                .insert(hash.clone(), InteractiveRebaseTodoAction::Drop);
                        }
                    }
                    let can_squash_to_target = !plan_editing
                        && squash_targets.len() >= 2
                        && selected_squash_range_hashes.len() >= 2
                        && dialog.squash_target_hash.is_some();
                    ui.label(
                        RichText::new(self.tr("interactive_rebase.squash_target"))
                            .small()
                            .color(theme::muted()),
                    );
                    ui.add_enabled_ui(can_squash_to_target, |ui| {
                        let selected_target_label = dialog
                            .squash_target_hash
                            .as_ref()
                            .and_then(|hash| {
                                squash_targets
                                    .iter()
                                    .find(|commit| commit.hash == *hash)
                                    .map(|commit| {
                                        format!("{} {}", commit.short_hash, commit.subject)
                                    })
                            })
                            .unwrap_or_else(|| self.tr("interactive_rebase.todo.none").to_owned());
                        egui::ComboBox::from_id_salt("interactive_rebase_squash_target")
                            .selected_text(selected_target_label)
                            .show_ui(ui, |ui| {
                                for target in &squash_targets {
                                    let label = format!("{} {}", target.short_hash, target.subject);
                                    ui.selectable_value(
                                        &mut dialog.squash_target_hash,
                                        Some(target.hash.clone()),
                                        label,
                                    );
                                }
                            });
                    });
                    let squash_button_label = interactive_rebase_squash_target_button_label(
                        self.language,
                        &dialog,
                        &commits,
                    );
                    let squash_target_applied =
                        interactive_rebase_squash_target_applied(&dialog, &commits);
                    if dialog_action_button(
                        ui,
                        &squash_button_label,
                        can_squash_to_target,
                        squash_target_applied,
                    )
                    .clicked()
                    {
                        if let Some(target_hash) = dialog.squash_target_hash.clone() {
                            interactive_rebase_apply_squash_range_to_target(
                                &mut dialog,
                                &commits,
                                &target_hash,
                            );
                        }
                    }
                    if ui
                        .add_enabled(
                            !plan_editing && selected_batch_count > 0,
                            egui::Button::new(self.tr("interactive_rebase.reset_selected")),
                        )
                        .clicked()
                    {
                        for hash in &selected_actionable_hashes {
                            dialog
                                .actions
                                .insert(hash.clone(), InteractiveRebaseTodoAction::Pick);
                            dialog.reword_messages.remove(hash);
                            dialog.reword_authors.remove(hash);
                            dialog.confirmed_reword_hashes.remove(hash);
                        }
                        dialog.squash_target_hash = None;
                        dialog.squash_range_hashes.clear();
                    }
                    ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                        if ui.button(self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                        let submit_requested = dialog_default_submit_requested(ui);
                        let can_rebase = actions_enabled
                            && !plan_editing
                            && !commits.is_empty()
                            && interactive_rebase_dialog_has_changes(&dialog);
                        if ui
                            .add_enabled(can_rebase, egui::Button::new(self.tr("dialog.ok")))
                            .clicked()
                            || (submit_requested && can_rebase)
                        {
                            if dialog.rewrites_published_history
                                && !dialog.acknowledge_published_rewrite
                            {
                                dialog.validation_error = Some(
                                    i18n::t(
                                        self.language,
                                        "interactive_rebase.error.confirm_published",
                                    )
                                    .to_owned(),
                                );
                            } else if let Some(error) =
                                validate_interactive_rebase_dialog(self.language, &dialog, &commits)
                            {
                                dialog.validation_error = Some(error);
                            } else {
                                let base = dialog.base_hash.clone();
                                let todo_items = interactive_rebase_todo_items(&dialog, &commits);
                                execute = Some(Box::new(move |root| {
                                    git::interactive_rebase(root, &base, &todo_items)
                                }));
                                close_after = true;
                            }
                        }
                    });
                });
            },
        );

        self.interactive_rebase_reword_modal(ctx, &mut dialog, &commits);

        if hash_copied {
            self.show_toast(self.tr("status.hash_copied"));
        }
        if let Some(action) = execute {
            if let Some(snapshot) = self.snapshot.as_ref() {
                self.pending_rewritten_history_prompt_root = Some(snapshot.root.clone());
            }
            self.start_undoable_git_action(
                self.tr("interactive_rebase.title").to_owned(),
                RepositoryUndoKind::Position,
                action,
            );
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_interactive_rebase_action = Some(dialog);
        }
    }

    fn interactive_rebase_reword_modal(
        &self,
        ctx: &egui::Context,
        dialog: &mut InteractiveRebaseActionDialog,
        commits: &[Commit],
    ) {
        let Some(hash) = dialog.editing_reword_hash.clone() else {
            return;
        };
        let is_reword = dialog.actions.get(&hash) == Some(&InteractiveRebaseTodoAction::Reword);
        let Some(commit) = commits.iter().find(|commit| commit.hash == hash) else {
            dialog.editing_reword_hash = None;
            return;
        };
        if !is_reword {
            dialog.editing_reword_hash = None;
            return;
        }

        let mut save = false;
        let mut cancel_reword = false;
        egui::Modal::new(egui::Id::new("interactive_rebase_reword_modal"))
            .area(
                egui::Modal::default_area(egui::Id::new("interactive_rebase_reword_modal"))
                    .anchor(Align2::CENTER_TOP, dialog::top_anchor_offset()),
            )
            .backdrop_color(Color32::from_black_alpha(136))
            .frame(dialog_window_frame())
            .show(ctx, |ui| {
                let width = ACTION_DIALOG_WIDTH + 96.0;
                egui::Frame::new()
                    .fill(theme::panel())
                    .corner_radius(CornerRadius::same(6))
                    .shadow(panel_shadow())
                    .inner_margin(egui::Margin::same(0))
                    .show(ui, |ui| {
                        ui.set_width(width);
                        compact_dialog_title_bar(
                            ui,
                            self.tr("interactive_rebase.reword.title"),
                            width,
                        );
                        egui::Frame::new()
                            .inner_margin(egui::Margin::symmetric(12, 10))
                            .show(ui, |ui| {
                                ui.set_width((width - 24.0).max(0.0));
                                ui.label(
                                    RichText::new(format!(
                                        "{} {} {}",
                                        self.tr("interactive_rebase.reword.commit"),
                                        commit.short_hash,
                                        commit.subject
                                    ))
                                    .small()
                                    .color(theme::muted()),
                                );
                                ui.add_space(8.0);
                                let message = dialog
                                    .reword_messages
                                    .entry(hash.clone())
                                    .or_insert_with(|| commit.subject.clone());
                                let author = dialog
                                    .reword_authors
                                    .entry(hash.clone())
                                    .or_insert_with(|| InteractiveRebaseAuthor {
                                        name: commit.author.clone(),
                                        email: commit.author_email.clone(),
                                    });
                                themed_text_edit_selection(ui);
                                egui::Frame::new()
                                    .fill(theme::panel_recessed())
                                    .corner_radius(CornerRadius::same(4))
                                    .inner_margin(egui::Margin::symmetric(8, 6))
                                    .show(ui, |ui| {
                                        ui.add_sized(
                                            Vec2::new(ui.available_width(), 76.0),
                                            TextEdit::multiline(message)
                                                .frame(false)
                                                .hint_text(
                                                    self.tr("interactive_rebase.reword.hint"),
                                                )
                                                .text_color(theme::text()),
                                        );
                                    });
                                ui.add_space(8.0);
                                ui.horizontal(|ui| {
                                    ui.set_height(24.0);
                                    ui.add_sized(
                                        Vec2::new(48.0, 20.0),
                                        egui::Label::new(
                                            RichText::new(
                                                self.tr("interactive_rebase.reword.author"),
                                            )
                                            .small()
                                            .color(theme::muted()),
                                        ),
                                    );
                                    ui.add_sized(
                                        Vec2::new((ui.available_width() - 48.0).max(80.0), 24.0),
                                        themed_singleline_text_edit(
                                            &mut author.name,
                                            self.tr("interactive_rebase.reword.author_hint"),
                                        ),
                                    );
                                });
                                ui.horizontal(|ui| {
                                    ui.set_height(24.0);
                                    ui.add_sized(
                                        Vec2::new(48.0, 20.0),
                                        egui::Label::new(
                                            RichText::new(
                                                self.tr("interactive_rebase.reword.email"),
                                            )
                                            .small()
                                            .color(theme::muted()),
                                        ),
                                    );
                                    ui.add_sized(
                                        Vec2::new((ui.available_width() - 48.0).max(80.0), 24.0),
                                        themed_singleline_text_edit(
                                            &mut author.email,
                                            self.tr("interactive_rebase.reword.email_hint"),
                                        ),
                                    );
                                });
                                ui.add_space(10.0);
                                dialog_footer_row(ui, |ui| {
                                    if dialog_cancel_button(
                                        ui,
                                        self.tr("interactive_rebase.reword.cancel"),
                                    )
                                    .clicked()
                                    {
                                        cancel_reword = true;
                                    }
                                    if dialog_primary_button(
                                        ui,
                                        self.tr("interactive_rebase.reword.done"),
                                        !message.trim().is_empty()
                                            && !author.name.trim().is_empty()
                                            && !author.email.trim().is_empty(),
                                    )
                                    .clicked()
                                    {
                                        save = true;
                                    }
                                });
                            });
                    });
            });

        if cancel_reword {
            dialog
                .actions
                .insert(hash.clone(), InteractiveRebaseTodoAction::Pick);
            dialog.reword_messages.remove(&hash);
            dialog.reword_authors.remove(&hash);
            dialog.confirmed_reword_hashes.remove(&hash);
            dialog.editing_reword_hash = None;
        } else if save {
            dialog.confirmed_reword_hashes.insert(hash);
            dialog.editing_reword_hash = None;
        }
    }

    fn rebase_control_modal(&mut self, ctx: &egui::Context) {
        let Some(dialog) = self.pending_rebase_control_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut open_conflicts = false;
        let mut mark_rewrite_prompt = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let has_conflicts = self
            .snapshot
            .as_ref()
            .is_some_and(|snapshot| !worktree_conflict_files(snapshot).is_empty());
        let rebase_editing = self
            .snapshot
            .as_ref()
            .is_some_and(|snapshot| snapshot.rebase_editing);
        let staged_count = self
            .snapshot
            .as_ref()
            .map_or(0, |snapshot| snapshot.staged.len());
        let actions_enabled = !self.branch_actions_busy();

        fixed_action_dialog(
            ctx,
            self.tr("interactive_rebase.in_progress.title"),
            ACTION_DIALOG_WIDTH,
            REBASE_CONTROL_DIALOG_HEIGHT,
            |ui| {
                ui.label(
                    RichText::new(self.tr("interactive_rebase.in_progress.detail"))
                        .color(theme::text()),
                );
                if has_conflicts {
                    ui.add_space(6.0);
                    ui.label(
                        RichText::new(self.tr("interactive_rebase.in_progress.conflicts"))
                            .small()
                            .color(theme::warning()),
                    );
                }
                if rebase_editing && !has_conflicts {
                    ui.add_space(6.0);
                    ui.label(
                        RichText::new(self.tr("interactive_rebase.in_progress.edit_ready"))
                            .small()
                            .color(theme::muted()),
                    );
                }
                if let Some(message) = dialog.message.as_ref() {
                    ui.add_space(8.0);
                    ScrollArea::vertical()
                        .auto_shrink([false, false])
                        .max_height(110.0)
                        .show(ui, |ui| {
                            let mut message = message.clone();
                            ui.add(
                                TextEdit::multiline(&mut message)
                                    .id_salt("rebase_control_error_text")
                                    .font(FontId::monospace(12.0))
                                    .desired_width(f32::INFINITY)
                                    .desired_rows(4),
                            );
                        });
                }
                if has_conflicts {
                    ui.add_space(10.0);
                    if dialog_primary_button(
                        ui,
                        self.tr("worktree.resolve_conflicts"),
                        actions_enabled,
                    )
                    .clicked()
                    {
                        open_conflicts = true;
                        close_after = true;
                    }
                }
                dialog_footer_row(ui, |ui| {
                    if ui.button(self.tr("dialog.close")).clicked() {
                        close_after = true;
                    }
                    if ui
                        .add_enabled(
                            actions_enabled,
                            egui::Button::new(self.tr("interactive_rebase.in_progress.abort")),
                        )
                        .clicked()
                    {
                        execute = Some(Box::new(|root| git::rebase_abort(root)));
                        close_after = true;
                    }
                    if ui
                        .add_enabled(
                            actions_enabled,
                            egui::Button::new(self.tr("interactive_rebase.in_progress.skip")),
                        )
                        .clicked()
                    {
                        execute = Some(Box::new(|root| git::rebase_skip(root)));
                        mark_rewrite_prompt = true;
                        close_after = true;
                    }
                    if rebase_editing
                        && ui
                            .add_enabled(
                                actions_enabled && staged_count > 0,
                                egui::Button::new(self.tr("interactive_rebase.in_progress.amend")),
                            )
                            .clicked()
                    {
                        execute = Some(Box::new(|root| git::rebase_amend(root)));
                        close_after = true;
                    }
                    if dialog_primary_button(
                        ui,
                        self.tr("interactive_rebase.in_progress.continue"),
                        actions_enabled && !has_conflicts && (!rebase_editing || staged_count == 0),
                    )
                    .clicked()
                    {
                        execute = Some(Box::new(|root| git::rebase_continue(root)));
                        mark_rewrite_prompt = true;
                        close_after = true;
                    }
                });
            },
        );

        if open_conflicts {
            self.pending_worktree_action = Some(WorktreeActionDialog::ResolveConflicts {
                selected_path: None,
            });
        }
        if let Some(action) = execute {
            if mark_rewrite_prompt {
                if let Some(snapshot) = self.snapshot.as_ref() {
                    self.pending_rewritten_history_prompt_root = Some(snapshot.root.clone());
                }
            }
            self.execute_git_action(action);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_rebase_control_action = Some(dialog);
        }
    }

    fn rewritten_history_prompt_modal(&mut self, ctx: &egui::Context) {
        let Some(prompt) = self.pending_rewritten_history_prompt.take() else {
            return;
        };

        let mut keep_open = true;
        let mut open_push = false;
        compact_action_dialog(
            ctx,
            self.tr("rewrite_prompt.title"),
            ACTION_DIALOG_WIDTH,
            |ui| {
                ui.label(RichText::new(self.tr("rewrite_prompt.message")).color(theme::text()));
                ui.add_space(8.0);
                ui.label(
                    RichText::new(format!(
                        "{} -> {}  +{} / -{}",
                        prompt.branch, prompt.upstream, prompt.ahead, prompt.behind
                    ))
                    .small()
                    .color(theme::muted()),
                );
                ui.add_space(12.0);
                ui.horizontal(|ui| {
                    ui.with_layout(Layout::right_to_left(Align::Center), |ui| {
                        if dialog_cancel_button(ui, self.tr("rewrite_prompt.later")).clicked() {
                            keep_open = false;
                        }
                        if dialog_primary_button(ui, self.tr("rewrite_prompt.open_push"), true)
                            .clicked()
                        {
                            open_push = true;
                            keep_open = false;
                        }
                    });
                });
            },
        );

        if open_push {
            self.open_push_dialog_with_force(Some(prompt.branch.clone()), None, true);
        }
        if keep_open {
            self.pending_rewritten_history_prompt = Some(prompt);
        }
    }

    fn git_flow_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_git_flow_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut run_after_close: Option<(GitFlowOperation, git::GitFlowConfig)> = None;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let actions_enabled = !self.branch_actions_busy();
        let local_branch_names = self
            .snapshot
            .as_ref()
            .map(|snapshot| {
                snapshot
                    .branches
                    .iter()
                    .filter(|branch| !branch.remote)
                    .map(|branch| branch.name.clone())
                    .collect::<Vec<_>>()
            })
            .unwrap_or_default();

        match &mut dialog {
            GitFlowActionDialog::Initialize {
                config,
                validation_error,
            } => {
                let default_config = self
                    .snapshot
                    .as_ref()
                    .map(|snapshot| git_flow_config_defaults(snapshot));
                compact_action_dialog(
                    ctx,
                    self.tr("git_flow.initialize.title"),
                    GIT_FLOW_DIALOG_WIDTH,
                    |ui| {
                        ui.label(
                            RichText::new(self.tr("git_flow.initialize.detail"))
                                .color(theme::text()),
                        );
                        ui.add_space(8.0);
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.production_branch"),
                            &mut config.production_branch,
                        );
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.development_branch"),
                            &mut config.development_branch,
                        );
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.feature_prefix"),
                            &mut config.feature_prefix,
                        );
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.release_prefix"),
                            &mut config.release_prefix,
                        );
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.hotfix_prefix"),
                            &mut config.hotfix_prefix,
                        );
                        git_flow_config_field(
                            ui,
                            self.language,
                            self.tr("git_flow.version_tag_prefix"),
                            &mut config.version_tag_prefix,
                        );

                        if let Some(error) = validation_error.as_ref() {
                            ui.add_space(6.0);
                            ui.label(RichText::new(error).color(theme::warning()).small());
                        }
                        let footer = git_flow_action_footer(
                            ui,
                            Some(self.tr("git_flow.use_defaults")),
                            self.tr("dialog.cancel"),
                            self.tr("git_flow.initialize.submit"),
                            actions_enabled,
                        );
                        if footer.reset_clicked {
                            if let Some(default_config) = default_config.clone() {
                                *config = default_config;
                                *validation_error = None;
                            }
                        }
                        if footer.cancel_clicked {
                            close_after = true;
                        }
                        if footer.submit_requested {
                            if let Some(error) =
                                validate_git_flow_config_dialog(self.language, config)
                            {
                                *validation_error = Some(error);
                            } else {
                                let config = config.clone();
                                execute = Some(Box::new(move |root| {
                                    git::initialize_git_flow(root, config)
                                }));
                                close_after = true;
                            }
                        }
                    },
                );
            }
            GitFlowActionDialog::ActionPicker { config } => {
                compact_action_dialog(ctx, self.tr("git_flow.other_action.title"), 320.0, |ui| {
                    for operation in [
                        GitFlowOperation::Start(git::GitFlowBranchKind::Feature),
                        GitFlowOperation::Finish(git::GitFlowBranchKind::Feature),
                        GitFlowOperation::Start(git::GitFlowBranchKind::Release),
                        GitFlowOperation::Finish(git::GitFlowBranchKind::Release),
                        GitFlowOperation::Start(git::GitFlowBranchKind::Hotfix),
                        GitFlowOperation::Finish(git::GitFlowBranchKind::Hotfix),
                    ] {
                        if git_flow_action_picker_button(
                            ui,
                            git_flow_operation_title(self.language, operation),
                            actions_enabled,
                        )
                        .clicked()
                        {
                            run_after_close = Some((operation, config.clone()));
                        }
                        ui.add_space(4.0);
                    }
                    if git_flow_cancel_footer(ui, self.tr("dialog.cancel")) {
                        close_after = true;
                    }
                });
            }
            GitFlowActionDialog::Run {
                operation,
                config,
                name,
                start_point,
                branch_name,
                finish_rebase,
                finish_delete_branch,
                finish_force_delete,
                finish_create_tag,
                finish_tag_message,
                finish_push_remote,
                validation_error,
            } => {
                let title = git_flow_operation_title(self.language, *operation);
                let start_options = match *operation {
                    GitFlowOperation::Start(kind) => {
                        git_flow_start_point_options(self.snapshot.as_ref(), config, kind)
                    }
                    GitFlowOperation::Finish(_) => Vec::new(),
                };
                if matches!(*operation, GitFlowOperation::Start(_))
                    && !start_options
                        .iter()
                        .any(|option| option.name == *start_point)
                    && !start_options.is_empty()
                {
                    *start_point = start_options[0].name.clone();
                }
                let finish_options = match *operation {
                    GitFlowOperation::Finish(kind) => {
                        git_flow_finish_branch_options(self.snapshot.as_ref(), config, kind)
                    }
                    GitFlowOperation::Start(_) => Vec::new(),
                };
                if matches!(*operation, GitFlowOperation::Finish(_))
                    && !finish_options
                        .iter()
                        .any(|option| option.branch_name == *branch_name)
                    && !finish_options.is_empty()
                {
                    *branch_name = finish_options[0].branch_name.clone();
                }
                compact_action_dialog(ctx, title, GIT_FLOW_DIALOG_WIDTH, |ui| {
                    if matches!(*operation, GitFlowOperation::Start(_)) {
                        ui.label(
                            RichText::new(git_flow_operation_detail(self.language, *operation))
                                .color(theme::text()),
                        );
                        ui.add_space(8.0);
                    }
                    match *operation {
                        GitFlowOperation::Start(kind) => {
                            git_flow_config_field(
                                ui,
                                self.language,
                                self.tr("git_flow.name"),
                                name,
                            );
                            git_flow_start_point_row(
                                ui,
                                self.language,
                                self.tr("git_flow.start_from"),
                                start_point,
                                &start_options,
                            );
                            ui.add_space(8.0);
                            git_flow_start_preview_panel(
                                ui,
                                self.language,
                                config,
                                kind,
                                name,
                                start_point,
                                &start_options,
                            );
                        }
                        GitFlowOperation::Finish(kind) => {
                            git_flow_finish_branch_row(
                                ui,
                                self.language,
                                git_flow_finish_branch_label(self.language, kind),
                                branch_name,
                                &finish_options,
                            );
                            ui.add_space(8.0);
                            ui.label(
                                RichText::new(self.tr("pull.options"))
                                    .small()
                                    .color(theme::muted()),
                            );
                            match kind {
                                git::GitFlowBranchKind::Feature => {
                                    action_checkbox(
                                        ui,
                                        finish_rebase,
                                        self.tr("git_flow.finish.rebase_development"),
                                    );
                                }
                                git::GitFlowBranchKind::Release
                                | git::GitFlowBranchKind::Hotfix => {
                                    action_checkbox(
                                        ui,
                                        finish_create_tag,
                                        self.tr("git_flow.finish.tag_message"),
                                    );
                                    ui.add_enabled_ui(*finish_create_tag, |ui| {
                                        themed_text_edit_selection(ui);
                                        ui.add_sized(
                                            [ui.available_width(), 24.0],
                                            themed_singleline_text_edit(
                                                finish_tag_message,
                                                self.tr("git_flow.finish.tag_message_placeholder"),
                                            ),
                                        );
                                    });
                                }
                            }
                            ui.add_space(6.0);
                            ui.horizontal_wrapped(|ui| {
                                ui.label(
                                    RichText::new(self.tr("git_flow.finish.after"))
                                        .small()
                                        .color(theme::muted()),
                                );
                                action_checkbox(
                                    ui,
                                    finish_delete_branch,
                                    self.tr("git_flow.finish.delete_branch"),
                                );
                                action_checkbox(
                                    ui,
                                    finish_force_delete,
                                    self.tr("git_flow.finish.force_delete"),
                                );
                                if matches!(
                                    kind,
                                    git::GitFlowBranchKind::Release
                                        | git::GitFlowBranchKind::Hotfix
                                ) {
                                    action_checkbox(
                                        ui,
                                        finish_push_remote,
                                        self.tr("git_flow.finish.push_remote"),
                                    );
                                }
                            });
                        }
                    }
                    if matches!(*operation, GitFlowOperation::Finish(_)) {
                        ui.add_space(8.0);
                        if let GitFlowOperation::Finish(kind) = *operation {
                            match kind {
                                git::GitFlowBranchKind::Feature => {
                                    git_flow_finish_preview_panel(
                                        ui,
                                        self.language,
                                        config,
                                        kind,
                                        branch_name,
                                        &finish_options,
                                    );
                                }
                                git::GitFlowBranchKind::Release
                                | git::GitFlowBranchKind::Hotfix => {
                                    git_flow_finish_release_preview_panel(
                                        ui,
                                        self.language,
                                        config,
                                        kind,
                                        branch_name,
                                        *finish_create_tag,
                                        &finish_options,
                                    );
                                }
                            }
                        }
                    }

                    if let Some(error) = validation_error.as_ref() {
                        ui.add_space(6.0);
                        ui.label(RichText::new(error).color(theme::warning()).small());
                    }
                    let footer = git_flow_action_footer(
                        ui,
                        None,
                        self.tr("dialog.cancel"),
                        git_flow_operation_submit_label(self.language, *operation),
                        actions_enabled,
                    );
                    if footer.cancel_clicked {
                        close_after = true;
                    }
                    if footer.submit_requested {
                        if let Some(error) = validate_git_flow_run_dialog(
                            self.language,
                            config,
                            *operation,
                            name,
                            start_point,
                            branch_name,
                            &start_options,
                            &finish_options,
                            &local_branch_names,
                        ) {
                            *validation_error = Some(error);
                        } else {
                            let config = config.clone();
                            match *operation {
                                GitFlowOperation::Start(kind) => {
                                    let name = name.trim().to_owned();
                                    let start_point = start_point.trim().to_owned();
                                    execute = Some(Box::new(move |root| {
                                        git::start_git_flow_action(
                                            root,
                                            config,
                                            kind,
                                            name,
                                            start_point,
                                        )
                                    }));
                                }
                                GitFlowOperation::Finish(kind) => {
                                    let branch_name = branch_name.trim().to_owned();
                                    let options = git::GitFlowFinishOptions {
                                        rebase: *finish_rebase,
                                        delete_branch: *finish_delete_branch,
                                        force_delete: *finish_force_delete,
                                        create_tag: *finish_create_tag,
                                        tag_message: finish_tag_message.trim().to_owned(),
                                        push_remote: *finish_push_remote,
                                    };
                                    execute = Some(Box::new(move |root| {
                                        git::finish_git_flow_action(
                                            root,
                                            config,
                                            kind,
                                            &branch_name,
                                            options,
                                        )
                                    }));
                                }
                            }
                            close_after = true;
                        }
                    }
                });
            }
        }

        if let Some(action) = execute {
            self.execute_git_action(action);
        }
        if close_after {
            keep_open = false;
        }
        if let Some((operation, config)) = run_after_close {
            self.open_git_flow_run_dialog(operation, config);
        } else if keep_open {
            self.pending_git_flow_action = Some(dialog);
        }
    }

    fn lfs_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_lfs_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut next_dialog: Option<LfsActionDialog> = None;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let actions_enabled = !self.branch_actions_busy();

        match &mut dialog {
            LfsActionDialog::Intro => {
                compact_action_dialog(ctx, self.tr("lfs.init.title"), LFS_DIALOG_WIDTH, |ui| {
                    ui.label(
                        RichText::new(self.tr("lfs.intro.heading"))
                            .strong()
                            .color(theme::text()),
                    );
                    ui.add_space(6.0);
                    ui.label(RichText::new(self.tr("lfs.intro.body")).color(theme::text()));
                    ui.add_space(8.0);
                    ui.label(RichText::new(self.tr("lfs.intro.note")).color(theme::muted()));
                    dialog_footer_row(ui, |ui| {
                        if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                        let submit_requested = dialog_default_submit_requested(ui);
                        if dialog_primary_button(ui, self.tr("lfs.start"), actions_enabled)
                            .clicked()
                            || (submit_requested && actions_enabled)
                        {
                            if let Some(snapshot) = self.snapshot.as_ref() {
                                match git::lfs_tracked_patterns(&snapshot.root) {
                                    Ok(patterns) => {
                                        next_dialog = Some(LfsActionDialog::Track {
                                            original_patterns: patterns.clone(),
                                            patterns,
                                            selected: None,
                                            validation_error: None,
                                        });
                                        close_after = true;
                                    }
                                    Err(error) => {
                                        self.error = Some(error.to_string());
                                        close_after = true;
                                    }
                                }
                            }
                        }
                    });
                });
            }
            LfsActionDialog::Track {
                original_patterns,
                patterns,
                selected,
                validation_error,
            } => {
                compact_action_dialog(ctx, self.tr("lfs.init.title"), LFS_DIALOG_WIDTH, |ui| {
                    ui.vertical_centered(|ui| {
                        ui.label(
                            RichText::new(self.tr("lfs.track.title"))
                                .strong()
                                .color(theme::accent_deep()),
                        );
                    });
                    ui.label(RichText::new(self.tr("lfs.patterns_label")).color(theme::text()));
                    ui.add_space(4.0);
                    ui.horizontal(|ui| {
                        ui.vertical(|ui| {
                            lfs_pattern_list(ui, patterns, selected, self.language);
                            ui.add_space(4.0);
                            ui.horizontal(|ui| {
                                if ui.button(self.tr("lfs.add")).clicked() {
                                    patterns.push(String::new());
                                    *selected = Some(patterns.len().saturating_sub(1));
                                }
                                let remove_enabled =
                                    selected.and_then(|index| patterns.get(index)).is_some();
                                if ui
                                    .add_enabled(
                                        remove_enabled,
                                        egui::Button::new(self.tr("lfs.remove")),
                                    )
                                    .clicked()
                                {
                                    if let Some(index) = selected.take() {
                                        if index < patterns.len() {
                                            patterns.remove(index);
                                        }
                                    }
                                }
                            });
                        });
                        ui.add_space(10.0);
                        ui.add_sized(
                            [150.0, 160.0],
                            egui::Label::new(
                                RichText::new(self.tr("lfs.pattern_help")).color(theme::text()),
                            )
                            .wrap(),
                        );
                    });

                    if let Some(error) = validation_error.as_ref() {
                        ui.add_space(4.0);
                        ui.label(RichText::new(error).color(theme::warning()).small());
                    }

                    dialog_footer_row(ui, |ui| {
                        if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                            close_after = true;
                        }
                        let submit_requested = dialog_default_submit_requested(ui);
                        if dialog_primary_button(ui, self.tr("lfs.track_files"), actions_enabled)
                            .clicked()
                            || (submit_requested && actions_enabled)
                        {
                            if let Some(error) = validate_lfs_patterns(self.language, patterns) {
                                *validation_error = Some(error);
                            } else {
                                let options = git::LfsTrackOptions {
                                    original_patterns: original_patterns.clone(),
                                    patterns: patterns.clone(),
                                };
                                execute = Some(Box::new(move |root| {
                                    git::configure_lfs_patterns(root, options)
                                }));
                                close_after = true;
                            }
                        }
                    });
                });
            }
        }

        if let Some(action) = execute {
            self.execute_git_action(action);
        }
        if let Some(next) = next_dialog {
            self.pending_lfs_action = Some(next);
            return;
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_lfs_action = Some(dialog);
        }
    }

    fn submodule_action_modal(&mut self, ctx: &egui::Context) {
        let Some(mut dialog) = self.pending_submodule_action.take() else {
            return;
        };

        let mut keep_open = true;
        let mut close_after = false;
        let mut execute: Option<Box<dyn FnOnce(&std::path::Path) -> anyhow::Result<()> + Send>> =
            None;
        let actions_enabled = !self.branch_actions_busy();
        let snapshot_root = self.snapshot.as_ref().map(|snapshot| snapshot.root.clone());

        compact_action_dialog(
            ctx,
            self.tr("submodule.title"),
            DEPENDENCY_DIALOG_WIDTH,
            |ui| {
                dependency_source_row(
                    ui,
                    self.language,
                    self.tr("submodule.source"),
                    &mut dialog.source,
                    snapshot_root.as_deref(),
                );
                dependency_repo_type_row(
                    ui,
                    self.language,
                    self.tr("submodule.repo_type"),
                    &dialog.source,
                );
                dependency_local_path_row(
                    ui,
                    self.language,
                    self.tr("submodule.local_path"),
                    &mut dialog.local_path,
                    snapshot_root.as_deref(),
                );
                dependency_advanced_toggle(
                    ui,
                    &mut dialog.advanced_open,
                    self.tr("dependency.advanced_options"),
                );
                if dialog.advanced_open {
                    dependency_text_row(
                        ui,
                        self.language,
                        self.tr("submodule.source_branch"),
                        &mut dialog.source_branch,
                    );
                    action_checkbox(ui, &mut dialog.recursive, self.tr("submodule.recursive"));
                }

                if let Some(error) = dialog.validation_error.as_ref() {
                    ui.add_space(4.0);
                    ui.label(RichText::new(error).color(theme::warning()).small());
                }

                dialog_footer_row(ui, |ui| {
                    if dialog_cancel_button(ui, self.tr("dialog.cancel")).clicked() {
                        close_after = true;
                    }
                    let submit_requested = dialog_default_submit_requested(ui);
                    if dialog_primary_button(ui, self.tr("dialog.ok"), actions_enabled).clicked()
                        || (submit_requested && actions_enabled)
                    {
                        if let Some(error) =
                            validate_submodule_action_dialog(self.language, &dialog)
                        {
                            dialog.validation_error = Some(error);
                        } else {
                            let options = git::SubmoduleAddOptions {
                                source: dialog.source.trim().to_owned(),
                                local_path: normalize_dialog_relative_path(&dialog.local_path),
                                source_branch: dialog.source_branch.trim().to_owned(),
                                recursive: dialog.recursive,
                            };
                            execute = Some(Box::new(move |root| git::add_submodule(root, options)));
                            close_after = true;
                        }
                    }
                });
            },
        );

        if let Some(action) = execute {
            self.execute_git_action(action);
        }
        if close_after {
            keep_open = false;
        }
        if keep_open {
            self.pending_submodule_action = Some(dialog);
        }
    }

