fn window_control_button(ui: &mut Ui, label: &str, close: bool) -> egui::Response {
    let (rect, response) = ui.allocate_exact_size(Vec2::new(36.0, 24.0), Sense::click());
    let fill = if close {
        Color32::from_rgb(192, 55, 43)
    } else if response.hovered() {
        theme::hover()
    } else {
        theme::panel_soft()
    };
    ui.painter().rect_filled(rect, CornerRadius::same(4), fill);
    ui.painter().text(
        rect.center(),
        Align2::CENTER_CENTER,
        label,
        FontId::proportional(14.0),
        if close { Color32::WHITE } else { theme::text() },
    );
    pointing_hand_cursor(response)
}

fn top_menu_accelerator_pressed(ctx: &egui::Context) -> Option<TopMenu> {
    let alt_only = egui::Modifiers {
        alt: true,
        ..egui::Modifiers::NONE
    };
    ctx.input_mut(|input| {
        [
            (egui::Key::F, TopMenu::File),
            (egui::Key::V, TopMenu::View),
            (egui::Key::R, TopMenu::Repository),
            (egui::Key::A, TopMenu::Actions),
            (egui::Key::T, TopMenu::Tools),
            (egui::Key::H, TopMenu::Help),
        ]
        .into_iter()
        .find_map(|(key, menu)| input.consume_key(alt_only, key).then_some(menu))
    })
}

fn top_menu_button(
    ui: &mut Ui,
    label: &'static str,
    force_open: bool,
    add_contents: impl FnOnce(&mut Ui),
) {
    ui.scope(|ui| {
        apply_menu_visuals(ui);
        let popup_id = ui.make_persistent_id(("top_menu_popup", label));
        if force_open {
            ui.memory_mut(|memory| {
                memory.close_popup();
                memory.open_popup(popup_id);
            });
        }
        let popup_open = ui.memory(|memory| memory.is_popup_open(popup_id));
        let fill = if popup_open {
            menu_text_button_hover_fill()
        } else {
            Color32::TRANSPARENT
        };
        let response = ui.add(
            egui::Button::new(RichText::new(label).color(theme::text()).size(13.0))
                .fill(fill)
                .stroke(Stroke::NONE)
                .corner_radius(CornerRadius::same(4)),
        );
        let response = pointing_hand_cursor(response);
        if response.clicked() {
            ui.memory_mut(|memory| memory.toggle_popup(popup_id));
        }
        if popup_open {
            paint_text_button_hover_shadow(ui, response.rect);
        } else {
            paint_text_button_hover_shadow_for_response(ui, &response);
        }
        apply_menu_visuals(ui);
        ui.visuals_mut().window_stroke = Stroke::NONE;
        ui.visuals_mut().popup_shadow = panel_shadow();
        egui::popup::popup_below_widget(
            ui,
            popup_id,
            &response,
            egui::popup::PopupCloseBehavior::CloseOnClickOutside,
            |ui| {
                apply_menu_visuals(ui);
                ui.set_min_width(220.0);
                add_contents(ui);
            },
        );
    });
}

fn close_top_menu_popup(ui: &mut Ui) {
    ui.close_menu();
    ui.memory_mut(|memory| memory.close_popup());
}

fn menu_button(ui: &mut Ui, label: &'static str, add_contents: impl FnOnce(&mut Ui)) {
    hover_submenu_button(ui, label, add_contents);
}

fn hover_submenu_button(ui: &mut Ui, label: &'static str, add_contents: impl FnOnce(&mut Ui)) {
    hover_submenu_button_enabled(ui, true, label, add_contents);
}

fn hover_submenu_button_enabled(
    ui: &mut Ui,
    enabled: bool,
    label: &'static str,
    add_contents: impl FnOnce(&mut Ui),
) {
    ui.scope(|ui| {
        apply_menu_visuals(ui);
        let area_id = ui.make_persistent_id(("hover_submenu_area", label));
        let state_id = ui.make_persistent_id(("hover_submenu_rect", label));
        let pointer_pos = ui.input(|input| input.pointer.hover_pos());
        let pointer_in_submenu = ui
            .ctx()
            .data(|data| data.get_temp::<Option<Rect>>(state_id).flatten())
            .is_some_and(|rect| pointer_pos.is_some_and(|pos| rect.expand(8.0).contains(pos)));
        let row_rect_width = ui.available_width().max(160.0);
        let (rect, response) = ui.allocate_exact_size(
            Vec2::new(row_rect_width, 22.0),
            if enabled {
                Sense::click()
            } else {
                Sense::hover()
            },
        );
        let response = pointing_hand_cursor(response);
        let submenu_open = enabled && (response.hovered() || pointer_in_submenu);
        let fill = if submenu_open || response.has_focus() {
            menu_text_button_hover_fill()
        } else {
            Color32::TRANSPARENT
        };
        let text_color = if enabled {
            theme::text()
        } else {
            theme::muted()
        };
        if submenu_open {
            paint_text_button_hover_shadow(ui, rect);
        }
        ui.painter().rect_filled(rect, CornerRadius::same(4), fill);
        ui.painter().text(
            rect.left_center() + Vec2::new(6.0, 0.0),
            Align2::LEFT_CENTER,
            label,
            FontId::proportional(13.0),
            text_color,
        );
        ui.painter().text(
            rect.right_center() - Vec2::new(8.0, 0.0),
            Align2::RIGHT_CENTER,
            ">",
            FontId::proportional(11.0),
            text_color,
        );
        if submenu_open {
            let mut pos = rect.right_top() + Vec2::new(-2.0, -2.0);
            if let Some(to_global) = ui.ctx().layer_transform_to_global(ui.layer_id()) {
                pos = to_global * pos;
            }
            let area = egui::Area::new(area_id)
                .order(egui::Order::Foreground)
                .fixed_pos(pos)
                .show(ui.ctx(), |ui| {
                    apply_menu_visuals(ui);
                    egui::Frame::new()
                        .fill(theme::panel())
                        .corner_radius(CornerRadius::same(6))
                        .shadow(panel_shadow())
                        .inner_margin(egui::Margin::symmetric(6, 6))
                        .show(ui, |ui| {
                            apply_menu_visuals(ui);
                            ui.set_min_width(170.0);
                            add_contents(ui);
                        });
                });
            ui.ctx().data_mut(|data| {
                data.insert_temp::<Option<Rect>>(state_id, Some(area.response.rect))
            });
        } else {
            ui.ctx()
                .data_mut(|data| data.insert_temp::<Option<Rect>>(state_id, None));
        }
    });
}

fn apply_menu_visuals(ui: &mut Ui) {
    ui.spacing_mut().button_padding = Vec2::new(6.0, 2.0);
    ui.visuals_mut().widgets.inactive.bg_fill = Color32::TRANSPARENT;
    ui.visuals_mut().widgets.inactive.weak_bg_fill = Color32::TRANSPARENT;
    ui.visuals_mut().widgets.inactive.bg_stroke = Stroke::NONE;
    ui.visuals_mut().widgets.hovered.bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.hovered.weak_bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.hovered.bg_stroke = Stroke::NONE;
    ui.visuals_mut().widgets.open.bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.open.weak_bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.open.bg_stroke = Stroke::NONE;
    ui.visuals_mut().widgets.active.bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.active.weak_bg_fill = menu_text_button_hover_fill();
    ui.visuals_mut().widgets.active.bg_stroke = Stroke::NONE;
    ui.visuals_mut().selection.stroke = Stroke::NONE;
    ui.visuals_mut().window_stroke = Stroke::NONE;
    ui.visuals_mut().window_shadow = panel_shadow();
    ui.visuals_mut().popup_shadow = panel_shadow();
}

fn menu_text_button_hover_fill() -> Color32 {
    theme::accent_soft()
}

fn menu_text_button(ui: &mut Ui, enabled: bool, label: &str) -> egui::Response {
    menu_text_button_with_text(ui, enabled, label.to_owned())
}

fn menu_text_button_with_text(ui: &mut Ui, enabled: bool, text: String) -> egui::Response {
    ui.scope(|ui| {
        apply_menu_visuals(ui);
        let response = ui.add_enabled(
            enabled,
            egui::Button::new(text)
                .stroke(Stroke::NONE)
                .corner_radius(CornerRadius::same(4)),
        );
        if enabled {
            paint_text_button_hover_shadow_for_response(ui, &response);
        }
        if response.clicked() {
            close_top_menu_popup(ui);
        }
        response
    })
    .inner
}

fn menu_shortcut_button(ui: &mut Ui, enabled: bool, label: &str, shortcut: &str) -> egui::Response {
    menu_text_button_with_text(ui, enabled, format!("{label}\t{shortcut}"))
}

