fn resource_header(ui: &mut Ui, title: &str, meta: &str, action: impl FnOnce(&mut Ui)) {
    ui.horizontal(|ui| {
        ui.label(
            RichText::new(title)
                .size(22.0)
                .strong()
                .color(theme::text()),
        );
        ui.label(RichText::new(meta).small().color(theme::muted()));
        ui.with_layout(Layout::right_to_left(Align::Center), action);
    });
    ui.add_space(8.0);
}

