#[derive(Clone, Copy, Debug)]
struct TagTableColumns {
    name: f32,
    target: f32,
    subject: f32,
    action: f32,
}

fn tag_table_columns(width: f32) -> TagTableColumns {
    let action = 112.0;
    let target = 150.0;
    let name = width.mul_add(0.26, 0.0).clamp(180.0, 240.0);
    let subject = (width - name - target - action).clamp(260.0, 520.0);
    TagTableColumns {
        name,
        target,
        subject,
        action,
    }
}

