#[derive(Clone, Copy, Debug)]
struct SearchColumnWidths {
    desc: f32,
    date: f32,
    author: f32,
    hash: f32,
}

fn search_column_widths(width: f32) -> SearchColumnWidths {
    let hash = 92.0;
    let date = 132.0;
    let author = 180.0;
    let fixed = hash + date + author;
    let desc = (width - fixed).max(180.0);
    SearchColumnWidths {
        desc,
        date,
        author,
        hash,
    }
}

fn search_table_header(ui: &mut Ui, language: Language) {
    let labels = if language == Language::Chinese {
        (
            "\u{63cf}\u{8ff0}",
            "\u{65e5}\u{671f}",
            "\u{4f5c}\u{8005}",
            "\u{63d0}\u{4ea4}",
        )
    } else {
        ("Description", "Date", "Author", "Commit")
    };
    let (rect, _) = ui.allocate_exact_size(Vec2::new(ui.available_width(), 24.0), Sense::hover());
    let cols = search_column_widths(rect.width());
    let mut x = rect.left();
    let y = rect.center().y;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.desc - 12.0,
        labels.0,
        theme::muted(),
        false,
    );
    x += cols.desc;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.date - 12.0,
        labels.1,
        theme::muted(),
        false,
    );
    x += cols.date;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.author - 12.0,
        labels.2,
        theme::muted(),
        false,
    );
    x += cols.author;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.hash - 12.0,
        labels.3,
        theme::muted(),
        false,
    );
}

fn search_commit_row(ui: &mut Ui, commit: &Commit, selected: bool) -> (egui::Response, bool) {
    let response = ui.allocate_response(
        Vec2::new(ui.available_width(), HISTORY_TABLE_ROW_HEIGHT),
        Sense::click(),
    );
    let rect = response.rect;
    if selected || response.hovered() {
        ui.painter().rect_filled(
            rect,
            CornerRadius::ZERO,
            if selected {
                theme::accent_deep()
            } else {
                theme::accent_soft()
            },
        );
    }

    let cols = search_column_widths(rect.width());
    let text_color = if selected {
        Color32::WHITE
    } else {
        theme::text()
    };
    let muted_color = if selected {
        Color32::from_rgb(222, 247, 244)
    } else {
        theme::muted()
    };
    let mut x = rect.left();
    let y = rect.center().y;
    let hash_rect = Rect::from_min_size(
        Pos2::new(x, rect.top()),
        Vec2::new(cols.hash, rect.height()),
    );
    let copy_response = ui
        .interact(
            hash_rect,
            ui.id().with(("search_hash", &commit.hash)),
            Sense::click(),
        )
        .on_hover_text(commit.hash.as_str());
    let hash_copied = copy_response.clicked();
    if hash_copied {
        ui.ctx().copy_text(commit.hash.clone());
    }
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.desc - 12.0,
        &commit.subject,
        text_color,
        false,
    );
    x += cols.desc;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.date - 12.0,
        &commit.relative_time,
        text_color,
        false,
    );
    x += cols.date;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.author - 12.0,
        &commit.author,
        text_color,
        false,
    );
    x += cols.author;
    draw_clipped_cell(
        ui,
        x + 6.0,
        y,
        cols.hash - 12.0,
        &commit.short_hash,
        muted_color,
        true,
    );
    (response, hash_copied)
}

fn empty_list_panel(ui: &mut Ui, text: &str) {
    soft_panel_frame(theme::panel(), 18, 18).show(ui, |ui| {
        ui.set_min_height(160.0);
        ui.centered_and_justified(|ui| {
            ui.label(RichText::new(text).color(theme::muted()));
        });
    });
}

fn sidebar_nav_card_width(available_width: f32, count: usize) -> f32 {
    let count = count.max(1) as f32;
    let gaps = (count - 1.0) * 6.0;
    ((available_width - gaps).max(0.0) / count)
        .min(70.0)
        .max(36.0)
}

fn sidebar_nav_card(
    ui: &mut Ui,
    width: f32,
    selected: bool,
    icon: UiIcon,
    label: &str,
) -> egui::Response {
    let (rect, response) = ui.allocate_exact_size(Vec2::new(width, 58.0), Sense::click());
    let visuals = tab_visual_state(
        TabVisualMode::Detached,
        selected,
        response.hovered(),
        theme::panel(),
    );
    ui.painter()
        .rect_filled(rect, CornerRadius::same(6), visuals.fill);
    let icon_rect = Rect::from_center_size(
        Pos2::new(rect.center().x, rect.top() + 18.0),
        Vec2::splat(18.0),
    );
    egui::Image::new(icon_source(icon))
        .fit_to_exact_size(icon_rect.size())
        .tint(visuals.icon)
        .paint_at(ui, icon_rect);

    let text_rect = Rect::from_min_max(
        Pos2::new(rect.left() + 4.0, rect.top() + 34.0),
        Pos2::new(rect.right() - 4.0, rect.bottom() - 4.0),
    );
    ui.painter()
        .with_clip_rect(text_rect.intersect(ui.clip_rect()))
        .text(
            text_rect.center_top(),
            Align2::CENTER_TOP,
            label,
            FontId::proportional(11.0),
            visuals.text,
        );

    pointing_hand_cursor(response).on_hover_text(label)
}

#[derive(Clone, Copy)]
enum RepoTabShadowSide {
    Top,
    Left,
    Right,
    Bottom,
}

fn paint_connected_tab_shadow_for_state(ui: &mut Ui, rect: Rect, visuals: TabVisualState) {
    if visuals.shadow {
        paint_repo_tab_shadow(ui, rect, visuals.bottom_shadow);
    }
}

fn paint_repo_tab_shadow(ui: &mut Ui, rect: Rect, include_bottom: bool) {
    let shadow = egui::epaint::Shadow {
        offset: [2, 3],
        blur: 6,
        spread: 0,
        color: theme::accent_shadow(),
    };
    let base_alpha = if include_bottom {
        shadow.color.a().saturating_sub(16).max(24)
    } else {
        shadow.color.a().max(42)
    };

    for layer in 0..3 {
        let highlight_color = repo_tab_highlight_color(base_alpha, layer);
        paint_repo_tab_shadow_side(
            ui,
            rect,
            RepoTabShadowSide::Top,
            layer,
            0.34,
            highlight_color,
        );
        paint_repo_tab_shadow_side(
            ui,
            rect,
            RepoTabShadowSide::Left,
            layer,
            0.28,
            highlight_color,
        );
        paint_repo_tab_shadow_side(
            ui,
            rect,
            RepoTabShadowSide::Right,
            layer,
            0.58,
            repo_tab_shadow_color(shadow.color, base_alpha, layer),
        );
        if include_bottom {
            paint_repo_tab_shadow_side(
                ui,
                rect,
                RepoTabShadowSide::Bottom,
                layer,
                0.42,
                repo_tab_shadow_color(shadow.color, base_alpha, layer),
            );
        }
    }
}

fn repo_tab_highlight_color(base_alpha: u8, layer: usize) -> Color32 {
    let alpha = ((base_alpha as f32 * 0.42) as u8)
        .saturating_sub((layer as u8).saturating_mul(10))
        .max(10);
    Color32::WHITE.gamma_multiply(alpha as f32 / 255.0)
}

fn repo_tab_shadow_color(shadow_color: Color32, base_alpha: u8, layer: usize) -> Color32 {
    let alpha = ((base_alpha as f32 * 0.72) as u8)
        .saturating_sub((layer as u8).saturating_mul(8))
        .max(8);
    Color32::from_rgba_unmultiplied(shadow_color.r(), shadow_color.g(), shadow_color.b(), alpha)
}

fn paint_repo_tab_shadow_side(
    ui: &mut Ui,
    rect: Rect,
    side: RepoTabShadowSide,
    layer: usize,
    side_weight: f32,
    color: Color32,
) {
    if color.a() == 0 {
        return;
    }
    let color = color.gamma_multiply(side_weight);
    ui.painter().rect_filled(
        repo_tab_shadow_rect(rect, side, layer),
        CornerRadius::same(3),
        color,
    );
}

fn repo_tab_shadow_rect(rect: Rect, side: RepoTabShadowSide, layer: usize) -> Rect {
    let highlight_spread = 0.5 + layer as f32 * 0.55;
    let shadow_spread = 1.0 + layer as f32 * 0.65;
    match side {
        RepoTabShadowSide::Top => Rect::from_min_max(
            Pos2::new(
                rect.left() - highlight_spread,
                rect.top() - highlight_spread,
            ),
            Pos2::new(rect.right() + highlight_spread, rect.top() + 0.8),
        ),
        RepoTabShadowSide::Left => Rect::from_min_max(
            Pos2::new(
                rect.left() - highlight_spread,
                rect.top() - highlight_spread,
            ),
            Pos2::new(rect.left() + 0.8, rect.bottom() + 0.6),
        ),
        RepoTabShadowSide::Right => Rect::from_min_max(
            Pos2::new(rect.right(), rect.top() + 2.0),
            Pos2::new(rect.right() + shadow_spread, rect.bottom() - 0.6),
        ),
        RepoTabShadowSide::Bottom => Rect::from_min_max(
            Pos2::new(rect.left() + 1.0, rect.bottom() - shadow_spread),
            Pos2::new(rect.right() - 1.0, rect.bottom()),
        ),
    }
}

struct RepoTabInteraction {
    tab_clicked: bool,
    close_clicked: bool,
    rename_requested: bool,
    rename_submitted: bool,
    rename_cancelled: bool,
    response: egui::Response,
}

fn repo_tab_with_close(
    ui: &mut Ui,
    icon: UiIcon,
    selected: bool,
    label: &str,
    close_label: &str,
    tab_id: egui::Id,
    rename: Option<&mut RepoTabRenameState>,
) -> RepoTabInteraction {
    let width = repo_tab_width(ui, label);
    let is_renaming = rename.is_some();
    let sense = if is_renaming {
        Sense::hover()
    } else {
        Sense::click_and_drag()
    };
    let (_, response) = ui.allocate_exact_size(Vec2::new(width, REPO_TAB_HEIGHT), sense);
    let rect = response.rect;
    let close_rect = Rect::from_center_size(
        Pos2::new(rect.right() - 12.0, rect.center().y),
        Vec2::splat(18.0),
    );
    let close_hovered = repo_tab_close_hovered(ui, close_rect);
    let tab_hovered = response.hovered() || close_hovered;
    let show_close = selected || tab_hovered;
    let visuals = tab_visual_state(
        TabVisualMode::Connected,
        selected,
        tab_hovered,
        connected_tab_content_fill(),
    );
    let fill = repo_tab_fill(selected, tab_hovered);
    let text_color = repo_tab_text_color(selected, tab_hovered);
    let icon_color = repo_tab_icon_color(selected, tab_hovered);
    let icon_rect = Rect::from_center_size(
        Pos2::new(rect.left() + 17.0, rect.center().y),
        Vec2::splat(14.0),
    );
    let text_rect = Rect::from_min_max(
        Pos2::new(rect.left() + 34.0, rect.top()),
        Pos2::new(close_rect.left() - 2.0, rect.bottom()),
    );

    paint_connected_tab_shadow_for_state(ui, rect, visuals);
    ui.painter().rect_filled(rect, top_corners(3), fill);
    egui::Image::new(icon_source(icon))
        .fit_to_exact_size(icon_rect.size())
        .tint(icon_color)
        .paint_at(ui, icon_rect);
    let mut rename_submitted = false;
    let mut rename_cancelled = false;
    if let Some(rename) = rename {
        let editor_rect = Rect::from_center_size(
            text_rect.center(),
            Vec2::new(text_rect.width(), REPO_TAB_HEIGHT - 8.0),
        );
        themed_text_edit_selection(ui);
        let editor_response = ui.put(
            editor_rect,
            TextEdit::singleline(&mut rename.value)
                .id(tab_id.with("rename"))
                .font(FontId::proportional(12.0))
                .text_color(text_color)
                .frame(false),
        );
        let requested_focus = rename.request_focus;
        if requested_focus {
            editor_response.request_focus();
            rename.request_focus = false;
        }
        let escape_pressed = ui.input(|input| input.key_pressed(egui::Key::Escape));
        let enter_pressed = ui.input(|input| input.key_pressed(egui::Key::Enter));
        rename_cancelled = editor_response.has_focus() && escape_pressed;
        rename_submitted = !rename_cancelled
            && ((editor_response.has_focus() && enter_pressed)
                || (!requested_focus && editor_response.lost_focus()));
    } else {
        ui.painter()
            .with_clip_rect(text_rect.intersect(ui.clip_rect()))
            .text(
                text_rect.left_center(),
                Align2::LEFT_CENTER,
                label,
                FontId::proportional(12.0),
                text_color,
            );
    }

    let mut close_clicked = false;
    if show_close {
        let close_response = ui
            .interact(close_rect, tab_id.with("close"), Sense::click())
            .on_hover_text(close_label);
        close_clicked = close_response.clicked();
        let close_hovering = close_response.hovered();
        let close_color = repo_tab_close_color(selected, tab_hovered, close_hovering);
        if close_hovering {
            let close_fill = if !selected && tab_hovered {
                Color32::from_white_alpha(36)
            } else {
                theme::panel_soft()
            };
            ui.painter()
                .rect_filled(close_rect, CornerRadius::same(3), close_fill);
        }
        ui.painter().text(
            close_rect.center(),
            Align2::CENTER_CENTER,
            "\u{00d7}",
            FontId::proportional(16.0),
            close_color,
        );
    }

    RepoTabInteraction {
        tab_clicked: response.clicked() && !close_clicked,
        close_clicked,
        rename_requested: response.double_clicked() && !close_clicked && !close_hovered,
        rename_submitted,
        rename_cancelled,
        response,
    }
}

fn repo_tab_overflow_menu(
    ui: &mut Ui,
    id_salt: &'static str,
    label: &str,
    items: &[RepoTabVisibilityItem],
    repo_tab_names: &[String],
    active_repo_tab: Option<usize>,
    source_active: bool,
    new_tab_label: &str,
    switch_to: &mut Option<usize>,
    activate_source_tab: &mut bool,
) {
    let (response, popup_id) = repo_tab_overflow_button(ui, id_salt, label);
    egui::popup::popup_below_widget(
        ui,
        popup_id,
        &response,
        egui::popup::PopupCloseBehavior::CloseOnClick,
        |ui| {
            ui.set_min_width(220.0);
            for item in items {
                match *item {
                    RepoTabVisibilityItem::Repo(index) => {
                        if repo_tab_overflow_option(
                            ui,
                            active_repo_tab == Some(index),
                            &repo_tab_names[index],
                        )
                        .clicked()
                        {
                            *switch_to = Some(index);
                            ui.close_menu();
                        }
                    }
                    RepoTabVisibilityItem::Source => {
                        if repo_tab_overflow_option(ui, source_active, new_tab_label).clicked() {
                            *activate_source_tab = true;
                            ui.close_menu();
                        }
                    }
                }
            }
        },
    );
}

fn repo_tab_overflow_button(
    ui: &mut Ui,
    id_salt: &'static str,
    label: &str,
) -> (egui::Response, egui::Id) {
    let response = AppButton::repo_tab(UiIcon::More, label, false).show(ui);
    let popup_id = ui.make_persistent_id(("repo_tab_overflow_popup", id_salt));
    if response.clicked() {
        ui.memory_mut(|memory| memory.toggle_popup(popup_id));
    }
    (response, popup_id)
}

fn repo_tab_overflow_option(ui: &mut Ui, selected: bool, label: &str) -> egui::Response {
    let text = RichText::new(label).color(if selected {
        Color32::WHITE
    } else {
        theme::text()
    });
    pointing_hand_cursor(ui.selectable_label(selected, text))
}

fn repo_tab_close_hovered(ui: &Ui, close_rect: Rect) -> bool {
    ui.ctx()
        .pointer_hover_pos()
        .map_or(false, |pos| close_rect.contains(pos))
}

fn source_tab_button(ui: &mut Ui, selected: bool, icon: UiIcon, label: &str) -> egui::Response {
    AppButton::detached_tab(icon, label, selected).show(ui)
}

fn workspace_repository_tab_button(
    ui: &mut Ui,
    selected: bool,
    icon: UiIcon,
    label: &str,
) -> egui::Response {
    AppButton::repo_tab(icon, label, selected).show(ui)
}

fn repository_workspace_tab_strip(ui: &mut Ui, workspaces: &[PathBuf], current: &mut usize) {
    if workspaces.is_empty() {
        return;
    }
    if *current >= workspaces.len() {
        *current = workspaces.len() - 1;
    }

    ui.horizontal_wrapped(|ui| {
        ui.add_space(16.0);
        for (index, workspace) in workspaces.iter().enumerate() {
            let label = repository_workspace_tab_label(workspace);
            let response =
                workspace_repository_tab_button(ui, *current == index, UiIcon::Workspace, &label)
                    .on_hover_text(user_facing_path_string(workspace));
            if response.clicked() {
                *current = index;
            }
        }
    });
}

fn repository_workspace_tab_label(workspace: &Path) -> String {
    workspace
        .file_name()
        .and_then(|name| name.to_str())
        .filter(|name| !name.is_empty())
        .map(ToOwned::to_owned)
        .unwrap_or_else(|| user_facing_path_string(workspace))
}

fn known_repository_row(ui: &mut Ui, repository: &KnownRepository) -> egui::Response {
    let width = ui.available_width().min(820.0);
    let (rect, response) = ui.allocate_exact_size(Vec2::new(width, 46.0), Sense::click());
    let fill = if response.hovered() {
        theme::accent_soft()
    } else {
        Color32::TRANSPARENT
    };
    ui.painter().rect_filled(
        rect.shrink2(Vec2::new(2.0, 2.0)),
        CornerRadius::same(5),
        fill,
    );

    draw_ui_icon(
        ui,
        Rect::from_center_size(
            Pos2::new(rect.left() + 22.0, rect.center().y),
            Vec2::splat(18.0),
        ),
        UiIcon::Folder,
        theme::accent(),
    );
    ui.painter().text(
        Pos2::new(rect.left() + 46.0, rect.top() + 15.0),
        Align2::LEFT_CENTER,
        &repository.name,
        FontId::proportional(14.0),
        theme::text(),
    );
    ui.painter().text(
        Pos2::new(rect.left() + 46.0, rect.top() + 32.0),
        Align2::LEFT_CENTER,
        user_facing_path_string(&repository.root),
        FontId::proportional(11.0),
        theme::muted(),
    );

    response
}

fn workspace_repository_status_row(
    ui: &mut Ui,
    rect: Rect,
    repository: &KnownRepository,
    snapshot: Option<&RepositorySnapshot>,
    language: Language,
) -> egui::Response {
    let response = ui.interact(
        rect,
        ui.id()
            .with(("workspace_repository_status_row", &repository.root)),
        Sense::click(),
    );
    let body_rect = workspace_repository_row_body_rect(rect);
    let fill = if response.hovered() {
        theme::accent_soft()
    } else {
        Color32::TRANSPARENT
    };
    if fill != Color32::TRANSPARENT {
        ui.painter().rect_filled(
            workspace_repository_row_hover_rect(rect),
            CornerRadius::same(5),
            fill,
        );
    }

    draw_ui_icon(
        ui,
        Rect::from_center_size(
            Pos2::new(body_rect.left() + 18.0, body_rect.top() + 16.0),
            Vec2::splat(18.0),
        ),
        UiIcon::Folder,
        theme::accent(),
    );
    let text_left = body_rect.left() + 42.0;
    let text_right = body_rect.right() - 8.0;
    let top_line_top = body_rect.top() + 3.0;
    let top_line_bottom = body_rect.top() + 21.0;
    let branch_line_top = body_rect.top() + 25.0;
    let branch_line_bottom = body_rect.top() + 43.0;
    let path_left = workspace_repository_path_left(text_left, text_right);
    let name_rect = Rect::from_min_max(
        Pos2::new(text_left, top_line_top),
        Pos2::new((path_left - 10.0).max(text_left), top_line_bottom),
    );
    let path_rect = Rect::from_min_max(
        Pos2::new(path_left, top_line_top),
        Pos2::new(text_right, top_line_bottom),
    );
    let branch_rect = Rect::from_min_max(
        Pos2::new(text_left, branch_line_top),
        Pos2::new(text_right, branch_line_bottom),
    );
    paint_workspace_repository_row_debug_guides(
        ui,
        rect,
        body_rect,
        name_rect,
        branch_rect,
        path_rect,
    );

    if let Some(snapshot) = snapshot {
        workspace_repository_unstaged_badge_line(
            ui,
            name_rect,
            &repository.name,
            snapshot.unstaged.len(),
        );
        workspace_repository_branch_sync_line(
            ui,
            branch_rect,
            &snapshot.branch,
            upstream_sync_counts(Some(snapshot)),
        );
    } else {
        workspace_repository_path_text_line(
            ui,
            name_rect,
            &repository.name,
            FontId::proportional(13.5),
            theme::text(),
        );
        workspace_repository_text_line(
            ui,
            branch_rect,
            menu_label(language, "repo_status_unloaded"),
            FontId::monospace(11.0),
            theme::muted(),
        );
    }
    workspace_repository_path_text_line(
        ui,
        path_rect,
        &user_facing_path_string(&repository.root),
        FontId::proportional(10.5),
        theme::muted(),
    );

    pointing_hand_cursor(response)
}

fn workspace_repository_unstaged_color() -> Color32 {
    Color32::from_rgb(213, 139, 28)
}

fn workspace_repository_path_left(text_left: f32, text_right: f32) -> f32 {
    let top_line_width = (text_right - text_left).max(0.0);
    let desired_path_width = (top_line_width * 0.46).clamp(176.0, 250.0);
    (text_right - desired_path_width)
        .max(text_left + 180.0)
        .min(text_right)
}

fn workspace_repository_unstaged_badge_text(count: usize) -> Option<String> {
    (count > 0).then(|| count.to_string())
}

fn workspace_repository_unstaged_badge_width(ui: &Ui, count: usize) -> f32 {
    let Some(text) = workspace_repository_unstaged_badge_text(count) else {
        return 0.0;
    };
    let font = FontId::monospace(11.0);
    let icon_size = 9.0;
    let icon_gap = 3.0;
    icon_size + icon_gap + text_width(ui, &text, font, workspace_repository_unstaged_color())
}

fn workspace_repository_unstaged_badge_line(ui: &Ui, rect: Rect, name: &str, count: usize) {
    let name_font = FontId::proportional(13.5);
    let name_color = theme::text();
    let badge_gap = 5.0;
    let badge_text = workspace_repository_unstaged_badge_text(count);
    let badge_width = workspace_repository_unstaged_badge_width(ui, count);
    let badge_reserve = if badge_text.is_some() {
        badge_width + badge_gap
    } else {
        0.0
    };
    let name_max_width = (rect.width() - badge_reserve).max(0.0);
    let name_text = elide_end_to_width(ui, name, name_max_width, name_font.clone(), name_color);
    let name_width = text_width(ui, &name_text, name_font.clone(), name_color);
    let name_rect =
        Rect::from_min_max(rect.min, Pos2::new(rect.left() + name_width, rect.bottom()));
    workspace_repository_text_line(ui, name_rect, &name_text, name_font, name_color);

    if let Some(badge_text) = badge_text {
        let badge_left = (name_rect.right() + badge_gap).min(rect.right());
        let badge_rect = Rect::from_min_max(
            Pos2::new(badge_left, rect.top()),
            Pos2::new(rect.right(), rect.bottom()),
        );
        workspace_repository_unstaged_badge(ui, badge_rect, &badge_text);
    }
}

fn workspace_repository_unstaged_badge(ui: &Ui, rect: Rect, text: &str) {
    let font = FontId::monospace(11.0);
    let color = workspace_repository_unstaged_color();
    let icon_size = 9.0;
    let icon_gap = 3.0;
    let icon_center_x = rect.left() + icon_size * 0.5;
    let icon_rect = Rect::from_center_size(
        Pos2::new(icon_center_x, rect.center().y),
        Vec2::splat(icon_size),
    );
    paint_ui_icon(ui, icon_rect, UiIcon::UnstagedFile, color);

    let tail_rect = Rect::from_min_max(
        Pos2::new(icon_rect.right() + icon_gap, rect.top()),
        rect.right_bottom(),
    );
    workspace_repository_text_line(ui, tail_rect, text, font, color);
}

fn workspace_repository_branch_badges(counts: UpstreamSyncCounts) -> String {
    let mut badges = Vec::new();
    if let Some(pull) = upstream_pull_badge(Some(counts)) {
        badges.push(pull);
    }
    if let Some(push) = upstream_push_badge(Some(counts)) {
        badges.push(push);
    }
    badges.join("  ")
}

fn workspace_repository_branch_sync_line(
    ui: &Ui,
    rect: Rect,
    branch: &str,
    counts: UpstreamSyncCounts,
) {
    let font = FontId::monospace(11.0);
    let color = theme::muted();
    let badge_gap = 6.0;
    let badges = workspace_repository_branch_badges(counts);
    let badges_width = text_width(ui, &badges, font.clone(), color);
    let badge_reserve = if badges.is_empty() {
        0.0
    } else {
        badges_width + badge_gap
    };
    let branch_max_width = (rect.width() - badge_reserve).max(0.0);
    let branch_text = elide_end_to_width(ui, branch, branch_max_width, font.clone(), color);
    let branch_width = text_width(ui, &branch_text, font.clone(), color);
    let branch_rect = Rect::from_min_max(
        rect.min,
        Pos2::new(rect.left() + branch_width, rect.bottom()),
    );
    workspace_repository_text_line(ui, branch_rect, &branch_text, font.clone(), color);

    if !badges.is_empty() {
        let badges_left = (branch_rect.right() + badge_gap).min(rect.right());
        let badges_rect = Rect::from_min_max(
            Pos2::new(badges_left, rect.top()),
            Pos2::new(rect.right(), rect.bottom()),
        );
        workspace_repository_text_line(ui, badges_rect, &badges, font, color);
    }
}

fn text_width(ui: &Ui, text: &str, font: FontId, color: Color32) -> f32 {
    ui.fonts(|fonts| {
        fonts
            .layout_no_wrap(text.to_owned(), font, color)
            .rect
            .width()
    })
}

