enum WorktreeTreeRow<'a> {
    Directory {
        path: String,
        depth: usize,
    },
    File {
        file: &'a WorktreeFile,
        depth: usize,
    },
}

fn worktree_tree_rows<'a>(
    files: &'a [WorktreeFile],
    collapsed_dirs: &HashSet<String>,
) -> Vec<WorktreeTreeRow<'a>> {
    let mut dirs = BTreeSet::new();
    for file in files {
        let path = normalize_worktree_path(&file.display_path);
        let parts = path.split('/').collect::<Vec<_>>();
        let mut prefix = String::new();
        for part in parts.iter().take(parts.len().saturating_sub(1)) {
            if !prefix.is_empty() {
                prefix.push('/');
            }
            prefix.push_str(part);
            dirs.insert(prefix.clone());
        }
    }

    let mut rows = Vec::new();
    for dir in dirs {
        if worktree_parent_collapsed(&dir, collapsed_dirs) {
            continue;
        }
        rows.push(WorktreeTreeRow::Directory {
            depth: dir.matches('/').count(),
            path: dir,
        });
    }
    for file in files {
        let path = normalize_worktree_path(&file.display_path);
        if worktree_parent_collapsed(&path, collapsed_dirs) {
            continue;
        }
        rows.push(WorktreeTreeRow::File {
            depth: path.matches('/').count(),
            file,
        });
    }

    rows.sort_by(|left, right| {
        let left_key = match left {
            WorktreeTreeRow::Directory { path, .. } => (path.as_str(), 0),
            WorktreeTreeRow::File { file, .. } => (file.display_path.as_str(), 1),
        };
        let right_key = match right {
            WorktreeTreeRow::Directory { path, .. } => (path.as_str(), 0),
            WorktreeTreeRow::File { file, .. } => (file.display_path.as_str(), 1),
        };
        left_key.cmp(&right_key)
    });
    rows
}

fn worktree_parent_collapsed(path: &str, collapsed_dirs: &HashSet<String>) -> bool {
    let path = normalize_worktree_path(path);
    let parts = path.split('/').collect::<Vec<_>>();
    let mut prefix = String::new();
    for part in parts.iter().take(parts.len().saturating_sub(1)) {
        if !prefix.is_empty() {
            prefix.push('/');
        }
        prefix.push_str(part);
        if collapsed_dirs.contains(&prefix) {
            return true;
        }
    }
    false
}

fn normalize_worktree_path(path: &str) -> String {
    path.replace('\\', "/")
}

fn worktree_path_basename(path: &str) -> &str {
    path.rsplit(['/', '\\']).next().unwrap_or(path)
}

fn select_worktree_row(
    ui: &Ui,
    file: &WorktreeFile,
    staged: bool,
    selected: &mut Option<WorktreeRowClick>,
) {
    let modifiers = ui.input(|input| WorktreeSelectionModifiers {
        ctrl: input.modifiers.ctrl,
        shift: input.modifiers.shift,
    });
    *selected = Some(WorktreeRowClick {
        file: SelectedWorktreeFile {
            path: file.path.clone(),
            display_path: file.display_path.clone(),
            staged,
            untracked: file.index_status == '?',
        },
        modifiers,
    });
}

fn worktree_directory_row(
    ui: &mut Ui,
    path: &str,
    depth: usize,
    collapsed: bool,
    language: Language,
    action: &mut Option<WorktreeMenuAction>,
) -> egui::Response {
    let response = pointing_hand_cursor(ui.allocate_response(
        Vec2::new(ui.available_width(), FILE_ROW_HEIGHT),
        Sense::click(),
    ));
    let rect = response.rect;
    if response.hovered() {
        ui.painter().rect_filled(
            rect.shrink2(Vec2::new(2.0, 1.0)),
            CornerRadius::same(4),
            theme::accent_soft(),
        );
    }
    let indent = FILE_ROW_LEFT_INSET + depth as f32 * 16.0;
    draw_clipped_cell(
        ui,
        rect.left() + indent,
        rect.center().y,
        14.0,
        if collapsed { ">" } else { "v" },
        theme::muted(),
        true,
    );
    draw_clipped_cell(
        ui,
        rect.left() + indent + 20.0,
        rect.center().y,
        (rect.width() - indent - 26.0).max(20.0),
        worktree_path_basename(path),
        theme::text(),
        true,
    );

    response.context_menu(|ui| {
        ui.set_min_width(180.0);
        ui.label(RichText::new(path).monospace().color(theme::text()));
        ui.separator();
        if ui
            .button(i18n::t(language, "worktree.add_gitignore"))
            .clicked()
        {
            *action = Some(WorktreeMenuAction::AddToGitIgnore {
                pattern: format!("{}/", path.trim_end_matches('/')),
            });
            ui.close_menu();
        }
    });

    response
}

fn worktree_file_row(
    ui: &mut Ui,
    file: &WorktreeFile,
    staged: bool,
    selected: bool,
    language: Language,
    action: &mut Option<WorktreeMenuAction>,
    depth: usize,
    path_label: &str,
) -> egui::Response {
    let status = if file.is_conflicted() {
        "U".to_owned()
    } else if staged {
        file.index_status.to_string()
    } else if file.index_status == '?' {
        "A".to_owned()
    } else {
        file.worktree_status.to_string()
    };
    let response = pointing_hand_cursor(ui.allocate_response(
        Vec2::new(ui.available_width(), FILE_ROW_HEIGHT),
        Sense::click(),
    ));
    let rect = response.rect;
    if selected || response.hovered() {
        ui.painter().rect_filled(
            rect.shrink2(Vec2::new(2.0, 1.0)),
            CornerRadius::same(4),
            if selected {
                theme::accent_deep()
            } else {
                theme::accent_soft()
            },
        );
    }

    draw_worktree_file_row_content(
        ui,
        rect,
        FILE_ROW_LEFT_INSET,
        &status,
        path_label,
        selected,
        depth,
    );

    response.context_menu(|ui| {
        ui.set_min_width(180.0);
        ui.label(
            RichText::new(&file.display_path)
                .monospace()
                .color(theme::text()),
        );
        ui.separator();
        if file.is_conflicted()
            && ui
                .button(i18n::t(language, "worktree.resolve_conflict"))
                .clicked()
        {
            *action = Some(WorktreeMenuAction::ResolveConflict {
                path: file.path.clone(),
            });
            ui.close_menu();
        }
        if staged {
            if ui
                .button(i18n::t(language, "worktree.unstage_file"))
                .clicked()
            {
                *action = Some(WorktreeMenuAction::Unstage {
                    path: file.path.clone(),
                });
                ui.close_menu();
            }
        } else {
            if ui
                .button(i18n::t(language, "worktree.stage_file"))
                .clicked()
            {
                *action = Some(WorktreeMenuAction::Stage {
                    path: file.path.clone(),
                });
                ui.close_menu();
            }
        }
        if ui.button(i18n::t(language, "worktree.discard")).clicked() {
            *action = Some(WorktreeMenuAction::Discard {
                path: file.path.clone(),
                untracked: file.index_status == '?',
            });
            ui.close_menu();
        }
        if ui
            .button(i18n::t(language, "worktree.add_gitignore"))
            .clicked()
        {
            *action = Some(WorktreeMenuAction::AddToGitIgnore {
                pattern: normalize_worktree_path(&file.display_path),
            });
            ui.close_menu();
        }
    });

    response
}

fn draw_worktree_file_row_content(
    ui: &mut Ui,
    rect: Rect,
    left_inset: f32,
    status: &str,
    path: &str,
    selected: bool,
    depth: usize,
) {
    let left_inset = left_inset + depth as f32 * 16.0;
    let icon_rect = Rect::from_min_size(
        Pos2::new(
            rect.left() + left_inset,
            rect.center().y - FILE_ROW_ICON_SLOT / 2.0,
        ),
        Vec2::splat(FILE_ROW_ICON_SLOT),
    );
    draw_file_status_icon(ui, icon_rect, status, selected);

    let text_rect = Rect::from_min_max(
        Pos2::new(icon_rect.right() + 6.0, rect.top()),
        Pos2::new(rect.right() - 6.0, rect.bottom()),
    );
    let text_color = if selected {
        Color32::WHITE
    } else {
        theme::text()
    };

    draw_clipped_cell(
        ui,
        text_rect.left(),
        rect.center().y,
        text_rect.width().max(20.0),
        path,
        text_color,
        true,
    );
}

fn commit_context_menu(
    ui: &mut Ui,
    commit: &Commit,
    language: Language,
) -> Option<CommitMenuAction> {
    let mut action = None;
    ui.set_min_width(220.0);
    ui.label(RichText::new(&commit.subject).strong().color(theme::text()));
    ui.label(
        RichText::new(format!("{}  {}", commit.short_hash, commit.author))
            .small()
            .color(theme::muted()),
    );
    ui.add_space(6.0);

    if ui.button(i18n::t(language, "menu.copy_hash")).clicked() {
        ui.ctx().copy_text(commit.hash.clone());
        ui.close_menu();
    }
    if ui
        .button(i18n::t(language, "menu.copy_short_hash"))
        .clicked()
    {
        ui.ctx().copy_text(commit.short_hash.clone());
        ui.close_menu();
    }

    ui.add_space(6.0);
    if ui
        .button(i18n::t(language, "menu.checkout_commit"))
        .clicked()
    {
        action = Some(CommitMenuAction::Checkout {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    if ui.button(i18n::t(language, "menu.create_branch")).clicked() {
        action = Some(CommitMenuAction::CreateBranch {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    if ui.button(i18n::t(language, "menu.create_tag")).clicked() {
        action = Some(CommitMenuAction::CreateTag {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    ui.add_space(6.0);
    if ui.button(i18n::t(language, "menu.cherry_pick")).clicked() {
        action = Some(CommitMenuAction::CherryPick {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    if ui
        .button(i18n::t(language, "menu.interactive_rebase_children"))
        .clicked()
    {
        action = Some(CommitMenuAction::InteractiveRebaseChildren {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    if ui.button(i18n::t(language, "menu.revert")).clicked() {
        action = Some(CommitMenuAction::Revert {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    if ui.button(i18n::t(language, "menu.reset")).clicked() {
        action = Some(CommitMenuAction::Reset {
            hash: commit.hash.clone(),
            short_hash: commit.short_hash.clone(),
        });
        ui.close_menu();
    }
    ui.add_space(6.0);
    hover_submenu_button(ui, i18n::t(language, "menu.compare"), |ui| {
        if menu_text_button(ui, true, i18n::t(language, "menu.compare_worktree")).clicked() {
            action = Some(CommitMenuAction::CompareWithWorktree {
                hash: commit.hash.clone(),
                short_hash: commit.short_hash.clone(),
            });
            ui.close_menu();
        }
        if menu_text_button(ui, true, i18n::t(language, "menu.external_diff")).clicked() {
            action = Some(CommitMenuAction::ExternalDiff {
                hash: commit.hash.clone(),
                short_hash: commit.short_hash.clone(),
            });
            ui.close_menu();
        }
        if menu_text_button(ui, true, i18n::t(language, "menu.open_remote")).clicked() {
            action = Some(CommitMenuAction::OpenRemote {
                hash: commit.hash.clone(),
            });
            ui.close_menu();
        }
    });
    action
}

fn detail_line(ui: &mut Ui, label: &str, value: &str) {
    ui.add_space(6.0);
    ui.label(RichText::new(label).small().color(theme::muted()));
    ui.add(
        egui::Label::new(RichText::new(value).monospace().color(theme::text()))
            .wrap()
            .selectable(true),
    );
}

fn file_change_row(ui: &mut Ui, status: &str, path: &str, selected: bool) -> egui::Response {
    let response = ui.allocate_response(
        Vec2::new(ui.available_width(), FILE_ROW_HEIGHT),
        Sense::click(),
    );
    let rect = response.rect;
    if selected || response.hovered() {
        ui.painter().rect_filled(
            rect.shrink2(Vec2::new(2.0, 1.0)),
            CornerRadius::same(4),
            if selected {
                theme::accent_deep()
            } else {
                theme::accent_soft()
            },
        );
    }

    draw_file_row_content(ui, rect, 4.0, status, path, selected);
    response
}

fn draw_file_row_content(
    ui: &mut Ui,
    rect: Rect,
    left_inset: f32,
    status: &str,
    path: &str,
    selected: bool,
) {
    let icon_rect = Rect::from_min_size(
        Pos2::new(
            rect.left() + left_inset,
            rect.center().y - FILE_ROW_ICON_SLOT / 2.0,
        ),
        Vec2::splat(FILE_ROW_ICON_SLOT),
    );
    draw_file_status_icon(ui, icon_rect, status, selected);

    let text_rect = Rect::from_min_max(
        Pos2::new(icon_rect.right() + 6.0, rect.top()),
        Pos2::new(rect.right() - 6.0, rect.bottom()),
    );
    let text_clip = text_rect.intersect(ui.clip_rect());
    ui.allocate_new_ui(egui::UiBuilder::new().max_rect(text_rect), |ui| {
        ui.set_clip_rect(text_clip);
        ui.with_layout(Layout::left_to_right(Align::Center), |ui| {
            ui.add_sized(
                [ui.available_width(), FILE_ROW_HEIGHT],
                egui::Label::new(RichText::new(path).monospace().color(if selected {
                    Color32::WHITE
                } else {
                    theme::text()
                }))
                .truncate(),
            );
        });
    });
}

fn draw_file_status_icon(ui: &mut Ui, rect: Rect, status: &str, on_dark: bool) {
    let kind = status.chars().next().unwrap_or('M');
    let color = file_status_color(kind, on_dark);
    let icon = file_status_icon(kind);
    draw_ui_icon(
        ui,
        Rect::from_center_size(rect.center(), Vec2::splat(16.0)),
        icon,
        color,
    );
}

fn file_status_color(kind: char, on_dark: bool) -> Color32 {
    if on_dark {
        return Color32::WHITE;
    }
    match kind {
        'A' | '?' => Color32::from_rgb(42, 166, 109),
        'D' => Color32::from_rgb(220, 76, 70),
        'U' => Color32::from_rgb(232, 174, 55),
        'M' | 'R' => theme::info(),
        _ => theme::muted(),
    }
}

fn file_status_icon(kind: char) -> UiIcon {
    match kind {
        'A' | '?' => UiIcon::AddFile,
        'D' => UiIcon::DeleteFile,
        'R' => UiIcon::RenameFile,
        'U' => UiIcon::Warning,
        'M' => UiIcon::Edit,
        _ => UiIcon::File,
    }
}

fn fill_diff_scroll_area(
    ui: &mut Ui,
    id_salt: impl std::hash::Hash,
    text: &str,
    mode: DiffDisplayMode,
    language: Language,
    selected_rows: &mut Vec<DiffLineKey>,
    truncated_label: Option<&str>,
) {
    let body_size = safe_ui_size(ui.available_size());
    let (body_rect, _) = ui.allocate_exact_size(body_size, Sense::hover());
    ui.allocate_new_ui(egui::UiBuilder::new().max_rect(body_rect), |ui| {
        safe_set_min_size(ui, body_rect.size());
        ui.set_max_size(body_rect.size());
        ui.set_clip_rect(body_rect);
        ScrollArea::both()
            .id_salt(id_salt)
            .max_height(body_rect.height())
            .auto_shrink([false, false])
            .show(ui, |ui| {
                render_unified_diff(ui, text, mode, language, selected_rows);
                if let Some(label) = truncated_label {
                    ui.label(RichText::new(label).color(theme::muted()));
                }
            });
    });
}

fn render_unified_diff(
    ui: &mut Ui,
    text: &str,
    mode: DiffDisplayMode,
    language: Language,
    selected_rows: &mut Vec<DiffLineKey>,
) {
    let previous_item_spacing = ui.spacing().item_spacing;
    ui.spacing_mut().item_spacing.y = 0.0;
    let items = collect_unified_diff_items(text, mode);
    let digit_width = ui.fonts(|fonts| {
        fonts
            .layout_no_wrap(
                "0".to_owned(),
                FontId::monospace(12.0),
                Color32::TRANSPARENT,
            )
            .rect
            .width()
            .max(1.0)
    });
    let gutter_layout = diff_gutter_layout(&items, digit_width);

    for item in items {
        match item {
            DiffRenderItem::FileHeader(text) => {
                ui.label(RichText::new(text).monospace().color(theme::info()));
            }
            DiffRenderItem::Omitted => diff_omitted_row(ui),
            DiffRenderItem::Line(line) => {
                diff_row(ui, &line, gutter_layout, language, selected_rows);
            }
        }
    }

    ui.spacing_mut().item_spacing = previous_item_spacing;
}

#[derive(Clone, Debug, Eq, PartialEq)]
enum DiffRenderItem {
    FileHeader(String),
    Omitted,
    Line(DiffLine),
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DiffLine {
    hunk_index: usize,
    left_no: String,
    right_no: String,
    body: String,
    kind: DiffKind,
}

#[derive(Clone, Debug, Eq, PartialEq)]
struct DiffLineKey {
    hunk_index: usize,
    left_no: String,
    right_no: String,
    body: String,
    kind: DiffKind,
}

impl DiffLine {
    fn key(&self) -> DiffLineKey {
        DiffLineKey {
            hunk_index: self.hunk_index,
            left_no: self.left_no.clone(),
            right_no: self.right_no.clone(),
            body: self.body.clone(),
            kind: self.kind,
        }
    }
}

fn collect_unified_diff_items(text: &str, mode: DiffDisplayMode) -> Vec<DiffRenderItem> {
    let mut items = Vec::new();
    let mut hunk_lines = Vec::new();
    let mut old_line: Option<usize> = None;
    let mut new_line: Option<usize> = None;
    let mut hunk_index = 0usize;

    for line in text.lines().take(1_200) {
        if line.starts_with("diff --git")
            || line.starts_with("diff --cc ")
            || line.starts_with("diff --combined ")
            || line.starts_with("index ")
            || line.starts_with("--- ")
            || line.starts_with("+++ ")
        {
            push_diff_hunk_items(&mut items, &hunk_lines, mode);
            hunk_lines.clear();
            if line.starts_with("diff --git")
                || line.starts_with("diff --cc ")
                || line.starts_with("diff --combined ")
            {
                if mode == DiffDisplayMode::Full {
                    items.push(DiffRenderItem::FileHeader(clean_diff_header(line)));
                }
            }
            continue;
        }

        if line.starts_with("@@") {
            push_diff_hunk_items(&mut items, &hunk_lines, mode);
            hunk_lines.clear();
            let (old_start, new_start) = parse_hunk_header(line);
            hunk_index += 1;
            old_line = old_start;
            new_line = new_start;
            continue;
        }

        let kind = if line.starts_with('+') {
            DiffKind::Added
        } else if line.starts_with('-') {
            DiffKind::Removed
        } else {
            DiffKind::Context
        };

        let left_no = match kind {
            DiffKind::Added => String::new(),
            _ => old_line.map(|line| line.to_string()).unwrap_or_default(),
        };
        let right_no = match kind {
            DiffKind::Removed => String::new(),
            _ => new_line.map(|line| line.to_string()).unwrap_or_default(),
        };
        let body = line
            .strip_prefix('+')
            .or_else(|| line.strip_prefix('-'))
            .unwrap_or(line);

        hunk_lines.push(DiffLine {
            hunk_index,
            left_no,
            right_no,
            body: body.to_owned(),
            kind,
        });

        match kind {
            DiffKind::Added => new_line = new_line.map(|line| line + 1),
            DiffKind::Removed => old_line = old_line.map(|line| line + 1),
            DiffKind::Context => {
                old_line = old_line.map(|line| line + 1);
                new_line = new_line.map(|line| line + 1);
            }
        }
    }

    push_diff_hunk_items(&mut items, &hunk_lines, mode);
    items
}

/// Return the complete unified hunk containing a selected rendered diff line.
/// Git needs the file preamble and every context line to reverse-apply it.
fn selected_diff_hunk_patch(text: &str, selected_rows: &[DiffLineKey]) -> Option<String> {
    if selected_rows.is_empty() {
        return None;
    }

    let mut preamble = Vec::<String>::new();
    let mut hunks = Vec::<(Vec<DiffLineKey>, String)>::new();
    let mut current: Option<(String, Vec<String>, Vec<DiffLineKey>)> = None;
    let mut old_line: Option<usize> = None;
    let mut new_line: Option<usize> = None;
    let mut hunk_index = 0usize;

    for raw_line in text.lines() {
        if raw_line.starts_with("diff --git") {
            push_selected_diff_hunk(&mut hunks, &preamble, &mut current);
            preamble.clear();
            preamble.push(raw_line.to_owned());
            old_line = None;
            new_line = None;
            continue;
        }
        if raw_line.starts_with("@@") {
            push_selected_diff_hunk(&mut hunks, &preamble, &mut current);
            hunk_index += 1;
            let (old_start, new_start) = parse_hunk_header(raw_line);
            old_line = old_start;
            new_line = new_start;
            current = Some((raw_line.to_owned(), Vec::new(), Vec::new()));
            continue;
        }

        let Some((_, lines, keys)) = current.as_mut() else {
            preamble.push(raw_line.to_owned());
            continue;
        };
        lines.push(raw_line.to_owned());
        if raw_line.starts_with("\\ No newline at end of file") {
            continue;
        }

        let kind = if raw_line.starts_with('+') {
            DiffKind::Added
        } else if raw_line.starts_with('-') {
            DiffKind::Removed
        } else {
            DiffKind::Context
        };
        let left_no = match kind {
            DiffKind::Added => String::new(),
            _ => old_line.map(|line| line.to_string()).unwrap_or_default(),
        };
        let right_no = match kind {
            DiffKind::Removed => String::new(),
            _ => new_line.map(|line| line.to_string()).unwrap_or_default(),
        };
        let body = raw_line
            .strip_prefix('+')
            .or_else(|| raw_line.strip_prefix('-'))
            .unwrap_or(raw_line);
        keys.push(DiffLineKey {
            hunk_index,
            left_no,
            right_no,
            body: body.to_owned(),
            kind,
        });
        match kind {
            DiffKind::Added => new_line = new_line.map(|line| line + 1),
            DiffKind::Removed => old_line = old_line.map(|line| line + 1),
            DiffKind::Context => {
                old_line = old_line.map(|line| line + 1);
                new_line = new_line.map(|line| line + 1);
            }
        }
    }
    push_selected_diff_hunk(&mut hunks, &preamble, &mut current);

    hunks.into_iter().find_map(|(keys, patch)| {
        keys.iter()
            .any(|key| selected_rows.iter().any(|selected| selected == key))
            .then_some(patch)
    })
}

fn push_selected_diff_hunk(
    hunks: &mut Vec<(Vec<DiffLineKey>, String)>,
    preamble: &[String],
    current: &mut Option<(String, Vec<String>, Vec<DiffLineKey>)>,
) {
    let Some((header, lines, keys)) = current.take() else {
        return;
    };
    let mut patch = preamble.join("\n");
    if !patch.is_empty() {
        patch.push('\n');
    }
    patch.push_str(&header);
    for line in lines {
        patch.push('\n');
        patch.push_str(&line);
    }
    patch.push('\n');
    hunks.push((keys, patch));
}

fn push_diff_hunk_items(
    items: &mut Vec<DiffRenderItem>,
    lines: &[DiffLine],
    mode: DiffDisplayMode,
) {
    if lines.is_empty() {
        return;
    }

    match mode {
        DiffDisplayMode::Full => {
            items.extend(lines.iter().cloned().map(DiffRenderItem::Line));
        }
        DiffDisplayMode::Blocks => {
            let ranges = condensed_diff_ranges(lines);
            for (range_index, (start, end)) in ranges.iter().copied().enumerate() {
                if range_index > 0 || start > 0 {
                    items.push(DiffRenderItem::Omitted);
                }
                items.extend(lines[start..=end].iter().cloned().map(DiffRenderItem::Line));
            }
            if ranges
                .last()
                .is_some_and(|(_, end)| *end < lines.len().saturating_sub(1))
            {
                items.push(DiffRenderItem::Omitted);
            }
        }
    }
}

fn condensed_diff_ranges(lines: &[DiffLine]) -> Vec<(usize, usize)> {
    const CONTEXT: usize = 3;
    let mut ranges: Vec<(usize, usize)> = Vec::new();

    for index in lines
        .iter()
        .enumerate()
        .filter_map(|(index, line)| (line.kind != DiffKind::Context).then_some(index))
    {
        let start = index.saturating_sub(CONTEXT);
        let end = (index + CONTEXT).min(lines.len().saturating_sub(1));
        if let Some((_, last_end)) = ranges.last_mut() {
            if start <= *last_end + 1 {
                *last_end = (*last_end).max(end);
                continue;
            }
        }
        ranges.push((start, end));
    }

    ranges
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum DiffKind {
    Added,
    Removed,
    Context,
}

#[derive(Clone, Copy, Debug)]
struct DiffGutterLayout {
    left_width: f32,
    right_width: f32,
}

impl DiffGutterLayout {
    fn total_width(self) -> f32 {
        self.left_width + self.right_width
    }
}

fn diff_gutter_layout(items: &[DiffRenderItem], digit_width: f32) -> DiffGutterLayout {
    let (left_digits, right_digits) = items.iter().fold((0usize, 0usize), |maximums, item| {
        let DiffRenderItem::Line(line) = item else {
            return maximums;
        };
        (
            maximums.0.max(line.left_no.len()),
            maximums.1.max(line.right_no.len()),
        )
    });
    let column_width = |digits: usize| {
        if digits == 0 {
            0.0
        } else {
            (digits as f32 * digit_width + 8.0).max(18.0)
        }
    };
    DiffGutterLayout {
        left_width: column_width(left_digits),
        right_width: column_width(right_digits),
    }
}

fn diff_row(
    ui: &mut Ui,
    line: &DiffLine,
    gutter_layout: DiffGutterLayout,
    language: Language,
    selected_rows: &mut Vec<DiffLineKey>,
) {
    let key = line.key();
    let width = ui.available_width().max(560.0);
    let (rect, response) = ui.allocate_exact_size(Vec2::new(width, 18.0), Sense::click());

    if response.clicked_by(egui::PointerButton::Primary) {
        let ctrl = ui.input(|input| input.modifiers.ctrl);
        if ctrl {
            if let Some(index) = selected_rows.iter().position(|selected| selected == &key) {
                selected_rows.remove(index);
            } else {
                selected_rows.push(key.clone());
            }
        } else {
            selected_rows.clear();
            selected_rows.push(key.clone());
        }
    }
    if response.clicked_by(egui::PointerButton::Secondary)
        && !selected_rows.iter().any(|selected| selected == &key)
    {
        selected_rows.clear();
        selected_rows.push(key.clone());
    }

    let selected = selected_rows.iter().any(|selected| selected == &key);
    let row_clip = diff_row_clip_rect(ui, rect);
    let painter = ui.painter().with_clip_rect(row_clip);
    let fill = if selected {
        Color32::from_rgb(82, 168, 236)
    } else {
        match line.kind {
            DiffKind::Added => Color32::from_rgb(214, 250, 221),
            DiffKind::Removed => Color32::from_rgb(255, 226, 226),
            DiffKind::Context => Color32::TRANSPARENT,
        }
    };
    let text_color = if selected {
        Color32::WHITE
    } else {
        match line.kind {
            DiffKind::Added => Color32::from_rgb(16, 92, 42),
            DiffKind::Removed => Color32::from_rgb(142, 37, 37),
            DiffKind::Context => Color32::from_rgb(71, 82, 96),
        }
    };
    if fill != Color32::TRANSPARENT {
        painter.rect_filled(rect, CornerRadius::ZERO, fill);
    }

    response.context_menu(|ui| {
        if ui.button(i18n::t(language, "menu.copy")).clicked() {
            ui.ctx().copy_text(selected_diff_rows_text(selected_rows));
            ui.close_menu();
        }
    });

    let gutter_width = gutter_layout.total_width();
    let gutter_bg = Rect::from_min_max(
        rect.left_top(),
        Pos2::new(rect.left() + gutter_width, rect.bottom()),
    );
    painter.rect_filled(
        gutter_bg,
        CornerRadius::ZERO,
        if selected {
            Color32::from_rgb(74, 151, 214)
        } else {
            Color32::from_rgb(248, 250, 252)
        },
    );
    painter.line_segment(
        [
            Pos2::new(gutter_bg.right(), rect.top()),
            Pos2::new(gutter_bg.right(), rect.bottom()),
        ],
        Stroke::new(
            1.0,
            if selected {
                Color32::from_rgb(67, 137, 195)
            } else {
                Color32::from_rgb(224, 229, 236)
            },
        ),
    );
    let gutter = if selected {
        Color32::from_rgb(235, 247, 255)
    } else {
        Color32::from_rgb(124, 135, 148)
    };
    painter.text(
        Pos2::new(
            rect.left() + gutter_layout.left_width - 4.0,
            rect.center().y,
        ),
        Align2::RIGHT_CENTER,
        &line.left_no,
        FontId::monospace(12.0),
        gutter,
    );
    painter.text(
        Pos2::new(rect.left() + gutter_width - 4.0, rect.center().y),
        Align2::RIGHT_CENTER,
        &line.right_no,
        FontId::monospace(12.0),
        gutter,
    );
    let sign = match line.kind {
        DiffKind::Added => "+",
        DiffKind::Removed => "-",
        DiffKind::Context => " ",
    };
    painter.text(
        Pos2::new(gutter_bg.right() + 6.0, rect.center().y),
        Align2::LEFT_CENTER,
        sign,
        FontId::monospace(12.0),
        text_color,
    );
    let text_rect = Rect::from_min_max(
        Pos2::new(gutter_bg.right() + 20.0, rect.top()),
        Pos2::new(rect.right() - 6.0, rect.bottom()),
    );
    if !selected {
        draw_diff_indent_guides(ui, text_rect, &line.body);
    }
    let text_clip = text_rect.intersect(row_clip);
    ui.painter().with_clip_rect(text_clip).text(
        text_rect.left_center(),
        Align2::LEFT_CENTER,
        &line.body,
        FontId::monospace(12.0),
        text_color,
    );
}

fn diff_row_clip_rect(ui: &Ui, rect: Rect) -> Rect {
    rect.intersect(ui.clip_rect())
}

fn selected_diff_rows_text(selected_rows: &[DiffLineKey]) -> String {
    selected_rows
        .iter()
        .map(|line| line.body.as_str())
        .collect::<Vec<_>>()
        .join("\n")
}

fn draw_diff_indent_guides(ui: &mut Ui, text_rect: Rect, body: &str) {
    let char_width = ui.fonts(|fonts| {
        fonts
            .layout_no_wrap(
                " ".to_owned(),
                FontId::monospace(12.0),
                Color32::TRANSPARENT,
            )
            .rect
            .width()
            .max(1.0)
    });
    let painter = ui
        .painter()
        .with_clip_rect(text_rect.intersect(ui.clip_rect()));
    let dot_color = Color32::from_rgb(190, 198, 210);
    let mut column = 0usize;
    for ch in body.chars() {
        match ch {
            ' ' => {
                let x = text_rect.left() + column as f32 * char_width + char_width * 0.5;
                if x < text_rect.right() {
                    painter.circle_filled(Pos2::new(x, text_rect.center().y), 1.0, dot_color);
                }
                column += 1;
            }
            '\t' => {
                let next_tab = ((column / 4) + 1) * 4;
                while column < next_tab {
                    let x = text_rect.left() + column as f32 * char_width + char_width * 0.5;
                    if x < text_rect.right() {
                        painter.circle_filled(Pos2::new(x, text_rect.center().y), 1.0, dot_color);
                    }
                    column += 1;
                }
            }
            _ => break,
        }
    }
}

fn diff_omitted_row(ui: &mut Ui) {
    let width = ui.available_width().max(560.0);
    let (rect, _) = ui.allocate_exact_size(Vec2::new(width, 18.0), Sense::hover());
    ui.painter()
        .rect_filled(rect, CornerRadius::ZERO, Color32::from_rgb(250, 251, 253));
    ui.painter().line_segment(
        [
            Pos2::new(rect.left(), rect.center().y),
            Pos2::new(rect.right(), rect.center().y),
        ],
        Stroke::new(1.0, Color32::from_rgb(225, 230, 238)),
    );
    ui.painter().text(
        Pos2::new(rect.left() + 48.0, rect.center().y),
        Align2::CENTER_CENTER,
        "...",
        FontId::monospace(12.0),
        Color32::from_rgb(128, 139, 153),
    );
}

fn clean_diff_header(line: &str) -> String {
    let raw = line
        .strip_prefix("diff --git ")
        .or_else(|| line.strip_prefix("diff --cc "))
        .or_else(|| line.strip_prefix("diff --combined "))
        .unwrap_or(line);
    let mut parts = raw.split_whitespace();
    let left = parts.next().unwrap_or(raw).trim_start_matches("a/");
    let right = parts.next().unwrap_or(left).trim_start_matches("b/");
    if left == right {
        left.to_owned()
    } else {
        format!("{left}  ->  {right}")
    }
}

fn parse_hunk_header(line: &str) -> (Option<usize>, Option<usize>) {
    let ranges = line
        .split_whitespace()
        .filter(|part| part.starts_with('-') || part.starts_with('+'))
        .collect::<Vec<_>>();
    let old = ranges
        .iter()
        .find(|part| part.starts_with('-'))
        .and_then(|part| part.trim_start_matches('-').split(',').next())
        .and_then(|value| value.parse::<usize>().ok());
    let new = ranges
        .iter()
        .rev()
        .find(|part| part.starts_with('+'))
        .and_then(|part| part.trim_start_matches('+').split(',').next())
        .and_then(|value| value.parse::<usize>().ok());
    (old, new)
}

fn view_uses_side_details(_view: MainView) -> bool {
    false
}

fn master_detail_split_heights(available_y: f32) -> (f32, f32) {
    let details_height =
        if available_y >= HISTORY_DETAILS_MIN_HEIGHT + HISTORY_LIST_MIN_HEIGHT + 8.0 {
            (available_y * 0.42).clamp(
                HISTORY_DETAILS_MIN_HEIGHT,
                available_y - HISTORY_LIST_MIN_HEIGHT - 8.0,
            )
        } else {
            (available_y * 0.40).max(140.0)
        };
    let list_height = (available_y - details_height - 8.0).max(HISTORY_LIST_MIN_HEIGHT);
    (list_height, details_height)
}

fn commit_message_editor_height(available_body_height: f32) -> f32 {
    (available_body_height - COMMIT_BUTTON_ROW_HEIGHT - COMMIT_MESSAGE_BOTTOM_GAP)
        .max(COMMIT_MESSAGE_EDITOR_MIN_HEIGHT)
}

fn shortcut_pressed(ctx: &egui::Context, key: egui::Key, shift: bool) -> bool {
    ctx.input(|input| {
        input.modifiers.ctrl
            && input.modifiers.shift == shift
            && !input.modifiers.alt
            && input.key_pressed(key)
    })
}

fn menu_shortcut_pressed(ctx: &egui::Context) -> Option<MenuShortcutCommand> {
    ctx.input(|input| {
        [
            egui::Key::O,
            egui::Key::Comma,
            egui::Key::S,
            egui::Key::U,
            egui::Key::B,
            egui::Key::M,
            egui::Key::T,
            egui::Key::P,
        ]
        .into_iter()
        .find_map(|key| {
            input
                .key_pressed(key)
                .then(|| menu_command_for_shortcut(input.modifiers, key))
                .flatten()
        })
    })
}

fn menu_command_for_shortcut(
    modifiers: egui::Modifiers,
    key: egui::Key,
) -> Option<MenuShortcutCommand> {
    match (modifiers.ctrl, modifiers.shift, modifiers.alt, key) {
        (true, false, false, egui::Key::O) => Some(MenuShortcutCommand::OpenRepository),
        (true, false, false, egui::Key::Comma) => Some(MenuShortcutCommand::OpenSettings),
        (true, true, false, egui::Key::Comma) => Some(MenuShortcutCommand::OpenRepositorySettings),
        (true, true, false, egui::Key::S) => Some(MenuShortcutCommand::StashChanges),
        (true, true, false, egui::Key::U) => Some(MenuShortcutCommand::Checkout),
        (true, true, false, egui::Key::B) => Some(MenuShortcutCommand::CreateBranch),
        (true, true, false, egui::Key::M) => Some(MenuShortcutCommand::Merge),
        (true, true, false, egui::Key::T) => Some(MenuShortcutCommand::CreateTag),
        (false, true, true, egui::Key::P) => Some(MenuShortcutCommand::CreatePullRequest),
        _ => None,
    }
}

fn actions_menu_shortcut_pressed(ctx: &egui::Context) -> Option<ActionsMenuCommand> {
    ctx.input(|input| {
        [
            egui::Key::O,
            egui::Key::T,
            egui::Key::D,
            egui::Key::Plus,
            egui::Key::Equals,
            egui::Key::Delete,
            egui::Key::Minus,
            egui::Key::C,
            egui::Key::R,
            egui::Key::L,
            egui::Key::B,
        ]
        .into_iter()
        .find_map(|key| {
            input
                .key_pressed(key)
                .then(|| actions_menu_command_for_shortcut(input.modifiers, key))
                .flatten()
        })
    })
}

fn actions_menu_command_for_shortcut(
    modifiers: egui::Modifiers,
    key: egui::Key,
) -> Option<ActionsMenuCommand> {
    match (modifiers.ctrl, modifiers.shift, modifiers.alt, key) {
        (true, true, false, egui::Key::O) => Some(ActionsMenuCommand::OpenSelected),
        (false, true, true, egui::Key::T) => Some(ActionsMenuCommand::OpenTerminal),
        (true, false, false, egui::Key::D) => Some(ActionsMenuCommand::ExternalDiff),
        (true, true, false, egui::Key::Plus | egui::Key::Equals) => {
            Some(ActionsMenuCommand::StageSelected)
        }
        (true, false, false, egui::Key::Delete) => Some(ActionsMenuCommand::RemoveSelected),
        (true, true, false, egui::Key::Minus) => Some(ActionsMenuCommand::UnstageSelected),
        (true, true, true, egui::Key::Plus | egui::Key::Equals) => {
            Some(ActionsMenuCommand::ToggleStageRepository)
        }
        (true, true, false, egui::Key::C) => Some(ActionsMenuCommand::ToggleStageRepository),
        (true, true, false, egui::Key::R) => Some(ActionsMenuCommand::DiscardSelected),
        (false, true, true, egui::Key::L) => Some(ActionsMenuCommand::SelectedHistory),
        (false, true, true, egui::Key::B) => Some(ActionsMenuCommand::LineReview),
        _ => None,
    }
}

fn stage_toggle_shortcut_pressed(ctx: &egui::Context) -> bool {
    ctx.input(|input| {
        let stage_toggle_modifiers = input.modifiers.shift
            && (input.modifiers.ctrl || input.modifiers.command)
            && !input.modifiers.alt;
        let c_key_pressed = input.key_pressed(egui::Key::C);
        let copy_event = input
            .events
            .iter()
            .any(|event| matches!(event, egui::Event::Copy));

        stage_toggle_modifiers && (c_key_pressed || copy_event)
    })
}

fn shortcut_stage_toggle_action(snapshot: &RepositorySnapshot) -> Option<WorktreeMenuAction> {
    if !snapshot.unstaged.is_empty() {
        Some(WorktreeMenuAction::StageAll)
    } else if !snapshot.staged.is_empty() {
        Some(WorktreeMenuAction::UnstageAll)
    } else {
        None
    }
}

fn stage_toggle_menu_label(
    language: Language,
    snapshot: Option<&RepositorySnapshot>,
) -> &'static str {
    match snapshot.and_then(shortcut_stage_toggle_action) {
        Some(WorktreeMenuAction::UnstageAll) => menu_label(language, "actions_unstage_all"),
        _ => menu_label(language, "actions_stage_all"),
    }
}

fn upstream_sync_counts(snapshot: Option<&RepositorySnapshot>) -> UpstreamSyncCounts {
    snapshot
        .and_then(|snapshot| snapshot.upstream.as_ref())
        .map(|upstream| UpstreamSyncCounts {
            ahead: upstream.ahead,
            behind: upstream.behind,
        })
        .unwrap_or_default()
}

fn branch_current_for_display(branch: &git::Branch, pending_checkout: Option<&str>) -> bool {
    pending_checkout.map_or(branch.current, |pending| {
        !branch.remote && branch.name == pending
    })
}

fn upstream_sync_counts_for_branch(branch: &git::Branch) -> Option<UpstreamSyncCounts> {
    branch.upstream.as_ref().map(|upstream| UpstreamSyncCounts {
        ahead: upstream.ahead,
        behind: upstream.behind,
    })
}

fn upstream_pull_badge(counts: Option<UpstreamSyncCounts>) -> Option<String> {
    let behind = counts?.behind;
    (behind > 0).then(|| format!("\u{2193}{behind}"))
}

fn upstream_push_badge(counts: Option<UpstreamSyncCounts>) -> Option<String> {
    let ahead = counts?.ahead;
    (ahead > 0).then(|| format!("\u{2191}{ahead}"))
}

fn toolbar_sync_label(label: &str, badge: Option<String>) -> String {
    match badge {
        Some(badge) => format!("{label}  {badge}"),
        None => label.to_owned(),
    }
}

fn empty_state(ui: &mut Ui, loading: bool, language: Language) {
    ui.centered_and_justified(|ui| {
        ui.vertical_centered(|ui| {
            if loading {
                ui.spinner();
                ui.add_space(8.0);
                ui.label(
                    RichText::new(i18n::t(language, "status.loading_repo"))
                        .heading()
                        .color(theme::text()),
                );
                return;
            }
            ui.label(
                RichText::new(i18n::t(language, "repo.none"))
                    .heading()
                    .color(theme::text()),
            );
            ui.label(
                RichText::new("Git Agent will render the commit graph with virtualized rows.")
                    .color(theme::muted()),
            );
        });
    });
}

fn no_commits_state(ui: &mut Ui, language: Language) {
    ui.centered_and_justified(|ui| {
        ui.vertical_centered(|ui| {
            ui.label(
                RichText::new(i18n::t(language, "commit.no_commits"))
                    .heading()
                    .color(theme::text()),
            );
            ui.label(
                RichText::new(i18n::t(language, "commit.no_commits_hint")).color(theme::muted()),
            );
        });
    });
}

fn paths_equal(left: &std::path::Path, right: &std::path::Path) -> bool {
    let left = left
        .canonicalize()
        .unwrap_or_else(|_| left.to_path_buf())
        .to_string_lossy()
        .to_lowercase();
    let right = right
        .canonicalize()
        .unwrap_or_else(|_| right.to_path_buf())
        .to_string_lossy()
        .to_lowercase();
    left == right
}

fn default_ssh_key_directory() -> Option<PathBuf> {
    let home = env::var_os("USERPROFILE")
        .or_else(|| env::var_os("HOME"))
        .map(PathBuf::from)?;
    let ssh = home.join(".ssh");
    Some(if ssh.is_dir() { ssh } else { home })
}

const PUTTY_DOWNLOAD_URL: &str = "https://www.chiark.greenend.org.uk/~sgtatham/putty/latest.html";
#[cfg(target_os = "windows")]
const OPENSSH_INSTALL_GUIDE_URL: &str =
    "https://learn.microsoft.com/windows-server/administration/openssh/openssh_install_firstuse";
#[cfg(not(target_os = "windows"))]
const OPENSSH_INSTALL_GUIDE_URL: &str = "https://www.openssh.com/portable.html";

fn resolve_ssh_client_executable(client: SshClientKind, configured: &str) -> Option<PathBuf> {
    let configured = configured.trim();
    if !configured.is_empty() {
        let path = PathBuf::from(configured);
        return path.is_file().then_some(path);
    }
    match client {
        SshClientKind::PuttyPlink => find_putty_tool(&platform_executable_name("plink")),
        SshClientKind::OpenSsh => find_openssh_tool(&platform_executable_name("ssh")),
    }
}

fn platform_executable_name(base: &str) -> String {
    if cfg!(target_os = "windows") {
        format!("{base}.exe")
    } else {
        base.to_owned()
    }
}

fn find_openssh_tool(name: &str) -> Option<PathBuf> {
    #[cfg(target_os = "windows")]
    if let Some(windows) = env::var_os("WINDIR") {
        let path = PathBuf::from(windows).join("System32/OpenSSH").join(name);
        if path.is_file() {
            return Some(path);
        }
    }
    find_executable_on_path(name)
}

fn find_putty_tool(name: &str) -> Option<PathBuf> {
    let program_files_roots = ["ProgramW6432", "ProgramFiles", "ProgramFiles(x86)"]
        .into_iter()
        .filter_map(env::var_os)
        .map(PathBuf::from);
    find_putty_tool_in_program_files(name, program_files_roots)
        .or_else(|| find_executable_on_path(name))
}

fn find_putty_tool_in_program_files(
    name: &str,
    roots: impl IntoIterator<Item = PathBuf>,
) -> Option<PathBuf> {
    roots
        .into_iter()
        .map(|root| root.join("PuTTY").join(name))
        .find(|path| path.is_file())
}

fn find_executable_on_path(name: &str) -> Option<PathBuf> {
    env::var_os("PATH")
        .into_iter()
        .flat_map(|paths| env::split_paths(&paths).collect::<Vec<_>>())
        .map(|directory| directory.join(name))
        .find(|path| path.is_file())
}

fn companion_executable(configured: &str, base: &str) -> Option<PathBuf> {
    let configured = configured.trim();
    if configured.is_empty() {
        return None;
    }
    let parent = Path::new(configured).parent()?;
    let path = parent.join(platform_executable_name(base));
    path.is_file().then_some(path)
}

fn putty_agent_executable(configured: &str) -> Option<PathBuf> {
    companion_executable(configured, "pageant")
        .or_else(|| find_putty_tool(&platform_executable_name("pageant")))
}

fn openssh_add_executable(configured: &str) -> Option<PathBuf> {
    companion_executable(configured, "ssh-add")
        .or_else(|| find_openssh_tool(&platform_executable_name("ssh-add")))
}

#[cfg(target_os = "windows")]
const WINDOWS_OPENSSH_INSTALL_ELEVATION_SCRIPT: &str = r#"
$ErrorActionPreference = 'Stop'
$command = "`$ErrorActionPreference = 'Stop'; Add-WindowsCapability -Online -Name 'OpenSSH.Client~~~~0.0.1.0' | Out-Null"
$encoded = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($command))
try {
    $process = Start-Process -FilePath 'powershell.exe' -Verb RunAs -WindowStyle Hidden -Wait -PassThru -ArgumentList @('-NoLogo', '-NoProfile', '-NonInteractive', '-EncodedCommand', $encoded)
    exit $process.ExitCode
} catch {
    exit 1223
}
"#;

fn install_openssh_client(language: Language) -> anyhow::Result<String> {
    let executable_name = platform_executable_name("ssh");
    if let Some(path) = find_openssh_tool(&executable_name) {
        return Ok(user_facing_path_string(&path));
    }

    #[cfg(target_os = "windows")]
    {
        let status = hidden_command(Path::new("powershell.exe"))
            .args([
                "-NoLogo",
                "-NoProfile",
                "-NonInteractive",
                "-Command",
                WINDOWS_OPENSSH_INSTALL_ELEVATION_SCRIPT,
            ])
            .status()?;
        for _ in 0..30 {
            if let Some(path) = find_openssh_tool(&executable_name) {
                return Ok(user_facing_path_string(&path));
            }
            thread::sleep(Duration::from_millis(100));
        }
        let detail = status
            .code()
            .map(|code| format!(" (exit code {code})"))
            .unwrap_or_default();
        return Err(anyhow::anyhow!(
            "{}{detail}",
            i18n::t(language, "ssh.openssh_install.failed")
        ));
    }

    #[cfg(not(target_os = "windows"))]
    Err(anyhow::anyhow!(i18n::t(
        language,
        "ssh.openssh_install.guided_only"
    )))
}

fn launch_ssh_agent(
    client: SshClientKind,
    configured: &str,
    key: Option<&Path>,
    language: Language,
) -> anyhow::Result<SshAgentStatus> {
    match client {
        SshClientKind::PuttyPlink => {
            let pageant = putty_agent_executable(configured).ok_or_else(|| {
                anyhow::anyhow!(
                    "Pageant was not found. Install the official PuTTY package, or select OpenSSH in Options > Git."
                )
            })?;
            let mut command = Command::new(&pageant);
            if let Some(key) = key {
                command.arg(key);
            }
            command.spawn().map_err(|error| {
                anyhow::anyhow!("Failed to start {}: {error}", pageant.display())
            })?;
            Ok(SshAgentStatus {
                client,
                backend: user_facing_path_string(&pageant),
                identities: Vec::new(),
                can_list_identities: false,
            })
        }
        SshClientKind::OpenSsh => {
            ensure_openssh_agent_running(configured, language)?;
            if let Some(key) = key {
                launch_interactive_openssh_add(configured, key)?;
            }
            read_ssh_agent_status(client, configured, language)
        }
    }
}

fn read_ssh_agent_status(
    client: SshClientKind,
    configured: &str,
    language: Language,
) -> anyhow::Result<SshAgentStatus> {
    match client {
        SshClientKind::PuttyPlink => {
            let pageant = putty_agent_executable(configured).ok_or_else(|| {
                anyhow::anyhow!(
                    "Pageant was not found. Install the official PuTTY package, or select OpenSSH in Options > Git."
                )
            })?;
            Ok(SshAgentStatus {
                client,
                backend: user_facing_path_string(&pageant),
                identities: Vec::new(),
                can_list_identities: false,
            })
        }
        SshClientKind::OpenSsh => {
            ensure_openssh_agent_running(configured, language)?;
            let ssh_add = openssh_add_executable(configured)
                .ok_or_else(|| anyhow::anyhow!(i18n::t(language, "ssh.openssh_agent_not_found")))?;
            let output = hidden_command(&ssh_add).arg("-l").output()?;
            if !openssh_agent_available(&output) {
                return Err(anyhow::anyhow!(i18n::t(
                    language,
                    "ssh.openssh_agent_connect_failed"
                )));
            }
            Ok(SshAgentStatus {
                client,
                backend: "OpenSSH ssh-agent".to_owned(),
                identities: openssh_identity_lines(&output.stdout),
                can_list_identities: true,
            })
        }
    }
}

fn openssh_identity_lines(stdout: &[u8]) -> Vec<String> {
    std::str::from_utf8(stdout)
        .ok()
        .into_iter()
        .flat_map(str::lines)
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .filter(|line| {
            line.split_whitespace()
                .next()
                .is_some_and(|bits| bits.bytes().all(|byte| byte.is_ascii_digit()))
        })
        .map(str::to_owned)
        .collect()
}

fn ssh_agent_should_prompt_for_key(status: &SshAgentStatus) -> bool {
    !status.can_list_identities || status.identities.is_empty()
}

fn add_ssh_key_to_agent(
    client: SshClientKind,
    configured: &str,
    key: &Path,
    language: Language,
) -> anyhow::Result<String> {
    if !key.is_file() {
        return Err(anyhow::anyhow!("SSH key does not exist: {}", key.display()));
    }
    match client {
        SshClientKind::PuttyPlink => {
            let pageant = putty_agent_executable(configured).ok_or_else(|| {
                anyhow::anyhow!(
                    "Pageant was not found. Install the official PuTTY package, or select OpenSSH in Options > Git."
                )
            })?;
            Command::new(&pageant)
                .arg(key)
                .spawn()
                .map_err(|error| anyhow::anyhow!("Failed to load SSH key: {error}"))?;
        }
        SshClientKind::OpenSsh => {
            ensure_openssh_agent_running(configured, language)?;
            launch_interactive_openssh_add(configured, key)?;
        }
    }
    Ok(user_facing_path_string(key))
}

fn ensure_openssh_agent_running(configured: &str, language: Language) -> anyhow::Result<()> {
    let ssh_add = openssh_add_executable(configured)
        .ok_or_else(|| anyhow::anyhow!(i18n::t(language, "ssh.openssh_agent_not_found")))?;
    let first_check = hidden_command(&ssh_add).arg("-l").output()?;
    if openssh_agent_available(&first_check) {
        return Ok(());
    }

    #[cfg(target_os = "windows")]
    {
        let output = hidden_command(Path::new("sc.exe"))
            .args(["start", "ssh-agent"])
            .output()?;
        if !output.status.success() {
            if sc_error_code(&output) == Some(1060) {
                return Err(anyhow::anyhow!(i18n::t(
                    language,
                    "ssh.openssh_agent_service_missing"
                )));
            }
            if !start_windows_openssh_agent_elevated()? {
                return Err(anyhow::anyhow!(i18n::t(
                    language,
                    "ssh.openssh_agent_elevation_failed"
                )));
            }
        }
        for _ in 0..20 {
            thread::sleep(Duration::from_millis(100));
            let check = hidden_command(&ssh_add).arg("-l").output()?;
            if openssh_agent_available(&check) {
                return Ok(());
            }
        }
        return Err(anyhow::anyhow!(i18n::t(
            language,
            "ssh.openssh_agent_connect_failed"
        )));
    }

    #[cfg(not(target_os = "windows"))]
    Err(anyhow::anyhow!(
        "OpenSSH agent is not available in this application environment"
    ))
}

fn openssh_agent_available(output: &std::process::Output) -> bool {
    output.status.success() || output_contains_ascii(output, b"no identities")
}

fn output_contains_ascii(output: &std::process::Output, needle: &[u8]) -> bool {
    [&output.stderr[..], &output.stdout[..]]
        .iter()
        .any(|bytes| {
            bytes
                .windows(needle.len())
                .any(|window| window.eq_ignore_ascii_case(needle))
        })
}

#[cfg(target_os = "windows")]
fn sc_error_code(output: &std::process::Output) -> Option<u32> {
    parse_sc_error_code(&output.stderr).or_else(|| parse_sc_error_code(&output.stdout))
}

#[cfg(target_os = "windows")]
fn parse_sc_error_code(bytes: &[u8]) -> Option<u32> {
    let marker = b"FAILED ";
    let start = bytes
        .windows(marker.len())
        .position(|window| window.eq_ignore_ascii_case(marker))?
        + marker.len();
    let digits = bytes[start..]
        .iter()
        .copied()
        .take_while(u8::is_ascii_digit)
        .collect::<Vec<_>>();
    std::str::from_utf8(&digits).ok()?.parse().ok()
}

#[cfg(target_os = "windows")]
const WINDOWS_OPENSSH_AGENT_ELEVATION_SCRIPT: &str = r#"
$ErrorActionPreference = 'Stop'
$command = "Set-Service -Name 'ssh-agent' -StartupType Manual; Start-Service -Name 'ssh-agent'"
$encoded = [Convert]::ToBase64String([Text.Encoding]::Unicode.GetBytes($command))
try {
    $process = Start-Process -FilePath 'powershell.exe' -Verb RunAs -WindowStyle Hidden -Wait -PassThru -ArgumentList @('-NoLogo', '-NoProfile', '-NonInteractive', '-EncodedCommand', $encoded)
    exit $process.ExitCode
} catch {
    exit 1223
}
"#;

#[cfg(target_os = "windows")]
fn start_windows_openssh_agent_elevated() -> anyhow::Result<bool> {
    Ok(hidden_command(Path::new("powershell.exe"))
        .args([
            "-NoLogo",
            "-NoProfile",
            "-NonInteractive",
            "-Command",
            WINDOWS_OPENSSH_AGENT_ELEVATION_SCRIPT,
        ])
        .status()?
        .success())
}

fn hidden_command(program: &Path) -> Command {
    let mut command = Command::new(program);
    #[cfg(target_os = "windows")]
    command.creation_flags(WINDOWS_CREATE_NO_WINDOW);
    command
}

fn launch_interactive_openssh_add(configured: &str, key: &Path) -> anyhow::Result<()> {
    #[cfg(target_os = "windows")]
    {
        let ssh_add = openssh_add_executable(configured)
            .ok_or_else(|| anyhow::anyhow!("OpenSSH ssh-add was not found"))?;
        let executable = user_facing_path_string(&ssh_add).replace('\'', "''");
        let key = user_facing_path_string(key).replace('\'', "''");
        let script = format!(
            "& '{executable}' -- '{key}'; if ($LASTEXITCODE -ne 0) {{ Read-Host 'Press Enter to close' }}"
        );
        let status = Command::new("powershell.exe")
            .args(["-NoLogo", "-NoProfile", "-Command", &script])
            .status()?;
        if status.success() {
            Ok(())
        } else {
            Err(anyhow::anyhow!("ssh-add failed"))
        }
    }
    #[cfg(not(target_os = "windows"))]
    {
        let ssh_add = openssh_add_executable(configured)
            .ok_or_else(|| anyhow::anyhow!("OpenSSH ssh-add was not found"))?;
        Command::new(ssh_add)
            .arg(key)
            .spawn()
            .map(|_| ())
            .map_err(Into::into)
    }
}

fn open_command_prompt(root: &Path) -> std::io::Result<()> {
    #[cfg(target_os = "windows")]
    {
        Command::new(git_bash_executable())
            .arg(format!("--cd={}", root.display()))
            .spawn()
            .map(|_| ())
    }
    #[cfg(not(target_os = "windows"))]
    {
        Command::new("sh")
            .arg("-c")
            .arg("x-terminal-emulator || open -a Terminal . || gnome-terminal .")
            .current_dir(root)
            .spawn()
            .map(|_| ())
    }
}

fn run_custom_git_action(root: &Path, command: &str) -> anyhow::Result<()> {
    validate_custom_git_action_settings("custom", command).map_err(anyhow::Error::msg)?;
    let output = if cfg!(target_os = "windows") {
        Command::new("cmd")
            .arg("/C")
            .arg(command)
            .current_dir(root)
            .output()
    } else {
        Command::new("sh")
            .arg("-c")
            .arg(command)
            .current_dir(root)
            .output()
    }?;
    if output.status.success() {
        return Ok(());
    }
    let stderr = String::from_utf8_lossy(&output.stderr);
    let stdout = String::from_utf8_lossy(&output.stdout);
    let detail = if !stderr.trim().is_empty() {
        stderr.trim().to_owned()
    } else {
        stdout.trim().to_owned()
    };
    Err(anyhow::anyhow!(
        "custom git action failed: {}\n{}",
        command,
        detail
    ))
}

#[cfg(target_os = "windows")]
fn git_bash_executable() -> PathBuf {
    for path in [
        "C:/Program Files/Git/git-bash.exe",
        "C:/Program Files (x86)/Git/git-bash.exe",
    ] {
        let path = PathBuf::from(path);
        if path.exists() {
            return path;
        }
    }
    PathBuf::from("git-bash.exe")
}

