fn remote_web_url(remote_url: &str) -> Option<String> {
    let remote_url = remote_url.trim();
    if remote_url.is_empty() {
        return None;
    }

    if remote_url.starts_with("http://") || remote_url.starts_with("https://") {
        return Some(strip_git_suffix(remote_url).to_owned());
    }

    if let Some(rest) = remote_url.strip_prefix("ssh://") {
        let rest = rest.split_once('@').map(|(_, value)| value).unwrap_or(rest);
        let (host, path) = rest.split_once('/')?;
        return Some(format!(
            "https://{}/{}",
            host,
            strip_git_suffix(path.trim_start_matches('/'))
        ));
    }

    if let Some((_, rest)) = remote_url.split_once('@') {
        if let Some((host, path)) = rest.split_once(':') {
            return Some(format!(
                "https://{}/{}",
                host,
                strip_git_suffix(path.trim_start_matches('/'))
            ));
        }
    }

    Some(strip_git_suffix(remote_url).to_owned())
}

fn branch_compare_url(base_url: &str, current_branch: &str, target_branch: &str) -> String {
    let base_url = base_url.trim_end_matches('/');
    let current_branch = url_path_component(current_branch);
    let target_branch = url_path_component(target_branch);
    if base_url.contains("gitlab.") || base_url.contains("gitlab.com") {
        format!("{base_url}/-/compare/{current_branch}...{target_branch}")
    } else {
        format!("{base_url}/compare/{current_branch}...{target_branch}")
    }
}

fn branch_pull_request_url(base_url: &str, branch: &str) -> String {
    let base_url = base_url.trim_end_matches('/');
    if base_url.contains("gitlab.") || base_url.contains("gitlab.com") {
        return format!(
            "{base_url}/-/merge_requests/new?merge_request%5Bsource_branch%5D={}",
            url_query_component(branch)
        );
    }
    format!("{base_url}/compare/{}?expand=1", url_path_component(branch))
}

fn split_remote_branch_name(name: &str) -> Option<(String, String)> {
    let (remote, branch) = name.split_once('/')?;
    if remote.trim().is_empty() || branch.trim().is_empty() {
        return None;
    }
    Some((remote.to_owned(), branch.to_owned()))
}

fn checkout_local_branch_default(remote_branch: &str) -> String {
    remote_branch
        .rsplit_once('/')
        .map(|(_, branch)| branch)
        .filter(|branch| !branch.trim().is_empty())
        .unwrap_or(remote_branch)
        .to_owned()
}

fn validate_checkout_new_branch(
    language: Language,
    remote_branch: &str,
    local_branch: &str,
    remote_branch_choices: &[String],
    local_branch_names: &[String],
) -> Option<String> {
    let remote_branch = remote_branch.trim();
    let local_branch = local_branch.trim();
    let mut issues = Vec::new();

    if remote_branch.is_empty()
        || !remote_branch_choices
            .iter()
            .any(|branch| branch == remote_branch)
    {
        issues.push(i18n::t(language, "checkout.error.remote_branch_invalid"));
    }
    if !valid_checkout_local_branch_name(local_branch) {
        issues.push(i18n::t(language, "checkout.error.local_branch_invalid"));
    } else if local_branch_names
        .iter()
        .any(|branch| branch == local_branch)
    {
        issues.push(i18n::t(language, "checkout.error.local_branch_exists"));
    }

    if issues.is_empty() {
        None
    } else {
        let mut message = i18n::t(language, "checkout.error.fix_inputs").to_owned();
        for (index, issue) in issues.iter().enumerate() {
            message.push_str(&format!("\n{}. {}", index + 1, issue));
        }
        Some(message)
    }
}

fn valid_checkout_local_branch_name(name: &str) -> bool {
    let name = name.trim();
    if name.is_empty()
        || name == "HEAD"
        || name.starts_with('/')
        || name.ends_with('/')
        || name.ends_with('.')
        || name.contains("..")
        || name.contains("//")
        || name.contains("@{")
    {
        return false;
    }
    !name
        .chars()
        .any(|ch| ch.is_whitespace() || matches!(ch, '~' | '^' | ':' | '?' | '*' | '[' | '\\'))
}

fn history_dialog_commits(
    snapshot: &RepositorySnapshot,
    scope: HistoryBranchScope,
    order: HistorySortOrder,
) -> Vec<Commit> {
    let commits = match (scope, order) {
        (HistoryBranchScope::Current, HistorySortOrder::Date) => &snapshot.date_commits,
        (HistoryBranchScope::Current, HistorySortOrder::Topology) => &snapshot.topology_commits,
        (HistoryBranchScope::All, HistorySortOrder::Date) => &snapshot.all_date_commits,
        (HistoryBranchScope::All, HistorySortOrder::Topology) => &snapshot.all_topology_commits,
    };
    if commits.is_empty() {
        snapshot.commits.clone()
    } else {
        commits.clone()
    }
}

fn merge_dialog_commits(snapshot: &RepositorySnapshot, order: HistorySortOrder) -> Vec<Commit> {
    history_dialog_commits(snapshot, HistoryBranchScope::All, order)
}

fn current_named_local_branch(snapshot: &RepositorySnapshot) -> Option<&git::Branch> {
    let branch_name = snapshot.branch.trim();
    if branch_name.is_empty() || branch_name == "HEAD" || branch_name.starts_with("(HEAD detached")
    {
        return None;
    }
    snapshot
        .branches
        .iter()
        .find(|branch| !branch.remote && branch.name == branch_name)
}

fn github_authentication_error(message: &str) -> bool {
    let message = message.to_ascii_lowercase();
    let auth_error =
        message.contains("authentication required") || message.contains("authentication error");
    let github_context = message.contains("github")
        || message.contains("push access to verify locks")
        || message.contains("git push");
    auth_error && github_context
}

#[allow(dead_code)]
fn interactive_rebase_has_targets(snapshot: &RepositorySnapshot) -> bool {
    !snapshot.rebase_in_progress
        && current_named_local_branch(snapshot).is_some()
        && interactive_rebase_dialog_commits(snapshot, HistorySortOrder::Date)
            .iter()
            .any(|commit| !interactive_rebase_commit_is_merge(commit))
}

fn interactive_rebase_dialog_commits(
    snapshot: &RepositorySnapshot,
    order: HistorySortOrder,
) -> Vec<Commit> {
    let first_parent_hashes = interactive_rebase_first_parent_hashes(snapshot);
    let mut commits = history_dialog_commits(snapshot, HistoryBranchScope::Current, order)
        .into_iter()
        .filter(|commit| first_parent_hashes.contains(&commit.hash))
        .collect::<Vec<_>>();
    let limit = match snapshot.upstream.as_ref() {
        Some(upstream) if upstream.ahead == 0 => return Vec::new(),
        Some(upstream) => upstream.ahead.clamp(1, 256),
        None => 32,
    };
    commits.truncate(limit);
    commits
}

fn interactive_rebase_commits_for_scope(
    snapshot: &RepositorySnapshot,
    scope: InteractiveRebaseScope,
    base_hash: &str,
    order: HistorySortOrder,
) -> Vec<Commit> {
    match scope {
        InteractiveRebaseScope::LocalUnpushed => interactive_rebase_dialog_commits(snapshot, order),
        InteractiveRebaseScope::ChildrenOfCommit => {
            interactive_rebase_children_of_commit(snapshot, base_hash, order)
        }
    }
}

fn interactive_rebase_children_of_commit(
    snapshot: &RepositorySnapshot,
    base_hash: &str,
    order: HistorySortOrder,
) -> Vec<Commit> {
    let child_hashes = interactive_rebase_first_parent_hashes_after_base(snapshot, base_hash);
    if child_hashes.is_empty() {
        return Vec::new();
    }
    history_dialog_commits(snapshot, HistoryBranchScope::Current, order)
        .into_iter()
        .filter(|commit| child_hashes.contains(&commit.hash))
        .collect()
}

fn interactive_rebase_first_parent_hashes_after_base(
    snapshot: &RepositorySnapshot,
    base_hash: &str,
) -> HashSet<String> {
    let base_hash = base_hash.trim();
    if base_hash.is_empty() || base_hash == "--root" {
        return interactive_rebase_first_parent_hashes(snapshot);
    }
    let topology = history_dialog_commits(
        snapshot,
        HistoryBranchScope::Current,
        HistorySortOrder::Topology,
    );
    let commits_by_hash = topology
        .iter()
        .map(|commit| (commit.hash.as_str(), commit))
        .collect::<HashMap<_, _>>();
    let Some(mut current_hash) = interactive_rebase_head_hash(snapshot, &topology) else {
        return HashSet::new();
    };
    let mut hashes = HashSet::new();
    loop {
        if current_hash == base_hash {
            return hashes;
        }
        if !hashes.insert(current_hash.clone()) {
            return HashSet::new();
        }
        let Some(commit) = commits_by_hash.get(current_hash.as_str()) else {
            return HashSet::new();
        };
        let Some(parent) = commit.parents.first() else {
            return HashSet::new();
        };
        current_hash = parent.clone();
    }
}

fn interactive_rebase_graph_drop_is_valid(
    snapshot: &RepositorySnapshot,
    source_hash: &str,
    target_hash: &str,
) -> bool {
    if source_hash.trim().is_empty() || target_hash.trim().is_empty() || source_hash == target_hash
    {
        return false;
    }
    let topology = history_dialog_commits(
        snapshot,
        HistoryBranchScope::Current,
        HistorySortOrder::Topology,
    );
    let source_is_editable = topology
        .iter()
        .any(|commit| commit.hash == source_hash && !interactive_rebase_commit_is_merge(commit));
    source_is_editable
        && interactive_rebase_first_parent_hashes_after_base(snapshot, target_hash)
            .contains(source_hash)
}

fn interactive_rebase_first_parent_hashes(snapshot: &RepositorySnapshot) -> HashSet<String> {
    let topology = history_dialog_commits(
        snapshot,
        HistoryBranchScope::Current,
        HistorySortOrder::Topology,
    );
    let commits_by_hash = topology
        .iter()
        .map(|commit| (commit.hash.as_str(), commit))
        .collect::<HashMap<_, _>>();
    let mut hashes = HashSet::new();
    let Some(mut current_hash) = interactive_rebase_head_hash(snapshot, &topology) else {
        return hashes;
    };

    while hashes.insert(current_hash.clone()) {
        let Some(commit) = commits_by_hash.get(current_hash.as_str()) else {
            break;
        };
        let Some(parent) = commit.parents.first() else {
            break;
        };
        current_hash = parent.clone();
    }

    hashes
}

fn interactive_rebase_head_hash(
    snapshot: &RepositorySnapshot,
    topology: &[Commit],
) -> Option<String> {
    let branch_name = current_named_local_branch(snapshot).map(|branch| branch.name.as_str());
    if let Some(branch_name) = branch_name {
        if let Some(commit) = topology
            .iter()
            .find(|commit| commit.refs.iter().any(|label| label == branch_name))
        {
            return Some(commit.hash.clone());
        }
    }
    topology.first().map(|commit| commit.hash.clone())
}

fn interactive_rebase_local_unpushed_hashes(snapshot: &RepositorySnapshot) -> HashSet<String> {
    let Some(upstream) = snapshot.upstream.as_ref() else {
        return HashSet::new();
    };
    let ahead = upstream.ahead;
    if ahead == 0 {
        return HashSet::new();
    }
    let topology = history_dialog_commits(
        snapshot,
        HistoryBranchScope::Current,
        HistorySortOrder::Topology,
    );
    let commits_by_hash = topology
        .iter()
        .map(|commit| (commit.hash.as_str(), commit))
        .collect::<HashMap<_, _>>();
    let Some(mut current_hash) = interactive_rebase_head_hash(snapshot, &topology) else {
        return HashSet::new();
    };
    let mut hashes = HashSet::new();
    for _ in 0..ahead {
        if !hashes.insert(current_hash.clone()) {
            break;
        }
        let Some(commit) = commits_by_hash.get(current_hash.as_str()) else {
            break;
        };
        let Some(parent) = commit.parents.first() else {
            break;
        };
        current_hash = parent.clone();
    }
    hashes
}

fn interactive_rebase_rewrites_published_history(
    snapshot: &RepositorySnapshot,
    commits: &[Commit],
) -> bool {
    if snapshot.upstream.is_none() || commits.is_empty() {
        return false;
    }
    let local_unpushed = interactive_rebase_local_unpushed_hashes(snapshot);
    commits
        .iter()
        .any(|commit| !local_unpushed.contains(&commit.hash))
}

fn short_rebase_base_label(base: &str) -> String {
    if base == "--root" {
        return "--root".to_owned();
    }
    base.chars().take(8).collect()
}

fn interactive_rebase_commit_is_merge(commit: &Commit) -> bool {
    commit.parents.len() > 1
}

fn interactive_rebase_actionable_commits(commits: &[Commit]) -> Vec<Commit> {
    commits
        .iter()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .cloned()
        .collect()
}

fn interactive_rebase_disabled_hashes(commits: &[Commit]) -> HashSet<String> {
    commits
        .iter()
        .filter(|commit| interactive_rebase_commit_is_merge(commit))
        .map(|commit| commit.hash.clone())
        .collect()
}

fn interactive_rebase_default_order(commits: &[Commit]) -> Vec<String> {
    commits
        .iter()
        .rev()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .map(|commit| commit.hash.clone())
        .collect()
}

#[derive(Clone, Debug)]
struct InteractiveRebaseAutosquashPlan {
    actions: BTreeMap<String, InteractiveRebaseTodoAction>,
    targets: BTreeMap<String, String>,
    ordered_hashes: Vec<String>,
}

fn interactive_rebase_autosquash_plan(commits: &[Commit]) -> InteractiveRebaseAutosquashPlan {
    let by_hash = commits
        .iter()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .map(|commit| (commit.hash.as_str(), commit))
        .collect::<HashMap<_, _>>();
    let chronological = interactive_rebase_default_order(commits)
        .into_iter()
        .filter_map(|hash| by_hash.get(hash.as_str()).copied())
        .collect::<Vec<_>>();
    let mut actions = chronological
        .iter()
        .map(|commit| (commit.hash.clone(), InteractiveRebaseTodoAction::Pick))
        .collect::<BTreeMap<_, _>>();
    let mut targets = BTreeMap::new();

    for (index, commit) in chronological.iter().enumerate() {
        let Some((action, target)) = interactive_rebase_autosquash_directive(&commit.subject)
        else {
            continue;
        };
        let Some(target_commit) = chronological[..index]
            .iter()
            .rev()
            .find(|candidate| interactive_rebase_autosquash_target_matches(candidate, target))
        else {
            continue;
        };
        actions.insert(commit.hash.clone(), action);
        targets.insert(commit.hash.clone(), target_commit.hash.clone());
    }

    let mut children = BTreeMap::<String, Vec<String>>::new();
    for commit in &chronological {
        if let Some(target) = targets.get(&commit.hash) {
            children
                .entry(target.clone())
                .or_default()
                .push(commit.hash.clone());
        }
    }
    let mut ordered_hashes = Vec::with_capacity(chronological.len());
    for commit in &chronological {
        if !targets.contains_key(&commit.hash) {
            interactive_rebase_append_autosquash_children(
                &commit.hash,
                &children,
                &mut ordered_hashes,
            );
        }
    }

    InteractiveRebaseAutosquashPlan {
        actions,
        targets,
        ordered_hashes,
    }
}

fn interactive_rebase_autosquash_directive(
    subject: &str,
) -> Option<(InteractiveRebaseTodoAction, &str)> {
    let subject = subject.trim();
    if let Some(target) = subject.strip_prefix("fixup!") {
        return (!target.trim().is_empty())
            .then_some((InteractiveRebaseTodoAction::Fixup, target.trim()));
    }
    if let Some(target) = subject.strip_prefix("squash!") {
        return (!target.trim().is_empty())
            .then_some((InteractiveRebaseTodoAction::Squash, target.trim()));
    }
    None
}

fn interactive_rebase_autosquash_target_matches(candidate: &Commit, target: &str) -> bool {
    candidate.subject.trim() == target
        || (target.len() >= 7 && candidate.hash.starts_with(target))
        || (target.len() >= 7 && candidate.short_hash.starts_with(target))
}

fn interactive_rebase_append_autosquash_children(
    hash: &str,
    children: &BTreeMap<String, Vec<String>>,
    ordered_hashes: &mut Vec<String>,
) {
    ordered_hashes.push(hash.to_owned());
    if let Some(followers) = children.get(hash) {
        for follower in followers {
            interactive_rebase_append_autosquash_children(follower, children, ordered_hashes);
        }
    }
}

fn interactive_rebase_synchronize_plan(
    dialog: &mut InteractiveRebaseActionDialog,
    commits: &[Commit],
) {
    let available = commits
        .iter()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .map(|commit| commit.hash.as_str())
        .collect::<HashSet<_>>();
    let mut seen = HashSet::new();
    dialog
        .ordered_hashes
        .retain(|hash| available.contains(hash.as_str()) && seen.insert(hash.clone()));
    for hash in interactive_rebase_default_order(commits) {
        if seen.insert(hash.clone()) {
            dialog.ordered_hashes.push(hash);
        }
    }
    dialog
        .actions
        .retain(|hash, _| available.contains(hash.as_str()));
    dialog.autosquash_targets.retain(|hash, target| {
        available.contains(hash.as_str()) && available.contains(target.as_str())
    });
    dialog
        .reword_messages
        .retain(|hash, _| dialog.actions.get(hash) == Some(&InteractiveRebaseTodoAction::Reword));
    dialog
        .reword_authors
        .retain(|hash, _| dialog.actions.get(hash) == Some(&InteractiveRebaseTodoAction::Reword));
    dialog
        .confirmed_reword_hashes
        .retain(|hash| dialog.actions.get(hash) == Some(&InteractiveRebaseTodoAction::Reword));
    if dialog
        .editing_reword_hash
        .as_ref()
        .is_some_and(|hash| dialog.actions.get(hash) != Some(&InteractiveRebaseTodoAction::Reword))
    {
        dialog.editing_reword_hash = None;
    }
    if dialog
        .dragged_hash
        .as_ref()
        .is_some_and(|hash| !available.contains(hash.as_str()))
    {
        dialog.dragged_hash = None;
    }
}

fn interactive_rebase_ordered_commits(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<Commit> {
    let by_hash = commits
        .iter()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .map(|commit| (commit.hash.as_str(), commit))
        .collect::<HashMap<_, _>>();
    dialog
        .ordered_hashes
        .iter()
        .filter_map(|hash| by_hash.get(hash.as_str()).copied())
        .cloned()
        .collect()
}

fn interactive_rebase_display_commits(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<Commit> {
    let mut planned = interactive_rebase_ordered_commits(dialog, commits)
        .into_iter()
        .rev();

    commits
        .iter()
        .cloned()
        .map(|commit| {
            if interactive_rebase_commit_is_merge(&commit) {
                commit
            } else {
                planned.next().unwrap_or(commit)
            }
        })
        .collect()
}

fn interactive_rebase_move_hash(
    ordered_hashes: &mut Vec<String>,
    dragged_hash: &str,
    target_hash: &str,
    insert_before: bool,
) -> bool {
    if dragged_hash == target_hash {
        return false;
    }
    let Some(source_index) = ordered_hashes.iter().position(|hash| hash == dragged_hash) else {
        return false;
    };
    let dragged = ordered_hashes.remove(source_index);
    let Some(mut target_index) = ordered_hashes.iter().position(|hash| hash == target_hash) else {
        ordered_hashes.insert(source_index, dragged);
        return false;
    };
    if !insert_before {
        target_index += 1;
    }
    ordered_hashes.insert(target_index, dragged);
    true
}

fn interactive_rebase_move_hash_from_display(
    ordered_hashes: &mut Vec<String>,
    dragged_hash: &str,
    target_hash: &str,
    insert_above_target: bool,
) -> bool {
    // The interactive-rebase table is rendered newest-first, unlike git's todo.
    interactive_rebase_move_hash(
        ordered_hashes,
        dragged_hash,
        target_hash,
        !insert_above_target,
    )
}

fn interactive_rebase_step_hash(
    ordered_hashes: &mut [String],
    hash: &str,
    move_towards_newer: bool,
) -> bool {
    let Some(index) = ordered_hashes
        .iter()
        .position(|candidate| candidate == hash)
    else {
        return false;
    };
    let target = if move_towards_newer {
        index
            .checked_add(1)
            .filter(|target| *target < ordered_hashes.len())
    } else {
        index.checked_sub(1)
    };
    let Some(target) = target else {
        return false;
    };
    ordered_hashes.swap(index, target);
    true
}

fn interactive_rebase_action_label(
    language: Language,
    action: InteractiveRebaseTodoAction,
) -> &'static str {
    match action {
        InteractiveRebaseTodoAction::Pick => i18n::t(language, "interactive_rebase.todo.pick"),
        InteractiveRebaseTodoAction::Reword => i18n::t(language, "interactive_rebase.todo.reword"),
        InteractiveRebaseTodoAction::Edit => i18n::t(language, "interactive_rebase.todo.edit"),
        InteractiveRebaseTodoAction::Squash => i18n::t(language, "interactive_rebase.todo.squash"),
        InteractiveRebaseTodoAction::Fixup => i18n::t(language, "interactive_rebase.todo.fixup"),
        InteractiveRebaseTodoAction::Drop => i18n::t(language, "interactive_rebase.todo.drop"),
    }
}

fn interactive_rebase_selected_actionable_hashes(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<String> {
    commits
        .iter()
        .filter(|commit| {
            !interactive_rebase_commit_is_merge(commit)
                && dialog.selected_hashes.contains(&commit.hash)
        })
        .map(|commit| commit.hash.clone())
        .collect()
}

fn interactive_rebase_selected_squash_targets(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<Commit> {
    commits
        .iter()
        .filter(|commit| {
            !interactive_rebase_commit_is_merge(commit)
                && dialog.selected_hashes.contains(&commit.hash)
        })
        .cloned()
        .collect()
}

fn interactive_rebase_selected_squash_range_hashes(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<String> {
    let selected_positions = commits
        .iter()
        .enumerate()
        .filter(|(_, commit)| {
            !interactive_rebase_commit_is_merge(commit)
                && dialog.selected_hashes.contains(&commit.hash)
        })
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    let Some(last) = selected_positions.iter().max().copied() else {
        return Vec::new();
    };

    commits[..=last]
        .iter()
        .filter(|commit| !interactive_rebase_commit_is_merge(commit))
        .map(|commit| commit.hash.clone())
        .collect()
}

fn interactive_rebase_apply_squash_range_to_target(
    dialog: &mut InteractiveRebaseActionDialog,
    commits: &[Commit],
    target_hash: &str,
) {
    let target_hash = target_hash.trim();
    let target_is_selected = commits.iter().any(|commit| {
        commit.hash == target_hash
            && !interactive_rebase_commit_is_merge(commit)
            && dialog.selected_hashes.contains(&commit.hash)
    });
    let range = interactive_rebase_selected_squash_range_hashes(dialog, commits);
    if !target_is_selected || range.len() < 2 || !range.iter().any(|hash| hash == target_hash) {
        return;
    }

    dialog.squash_target_hash = Some(target_hash.to_owned());
    dialog.squash_range_hashes = range.clone();
    for hash in range {
        let action = if hash == target_hash {
            InteractiveRebaseTodoAction::Pick
        } else {
            InteractiveRebaseTodoAction::Squash
        };
        dialog.actions.insert(hash, action);
    }
}

fn interactive_rebase_dialog_has_changes(dialog: &InteractiveRebaseActionDialog) -> bool {
    dialog
        .actions
        .values()
        .any(|action| *action != InteractiveRebaseTodoAction::Pick)
        || dialog.ordered_hashes != dialog.original_ordered_hashes
        || dialog.squash_target_hash.is_some() && dialog.squash_range_hashes.len() > 1
}

fn interactive_rebase_squash_target_applied(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> bool {
    let Some(target_hash) = dialog.squash_target_hash.as_deref() else {
        return false;
    };
    dialog.squash_range_hashes.len() > 1
        && dialog
            .squash_range_hashes
            .iter()
            .any(|hash| hash == target_hash)
        && commits.iter().any(|commit| commit.hash == target_hash)
}

fn interactive_rebase_squash_target_button_label(
    language: Language,
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> String {
    if interactive_rebase_squash_target_applied(dialog, commits) {
        if let Some(target) = dialog
            .squash_target_hash
            .as_ref()
            .and_then(|hash| commits.iter().find(|commit| commit.hash == *hash))
        {
            return format!(
                "{} {}",
                i18n::t(language, "interactive_rebase.squash_to_target_applied"),
                target.short_hash
            );
        }
    }
    i18n::t(language, "interactive_rebase.squash_to_target").to_owned()
}

fn interactive_rebase_base_for_commits(commits: &[Commit]) -> Option<String> {
    let actionable = interactive_rebase_actionable_commits(commits);
    let oldest = actionable.last()?;
    Some(
        oldest
            .parents
            .first()
            .cloned()
            .unwrap_or_else(|| "--root".to_owned()),
    )
}

fn interactive_rebase_todo_items(
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Vec<git::InteractiveRebaseTodoItem> {
    let chronological_commits = interactive_rebase_ordered_commits(dialog, commits);

    let squash_target = dialog.squash_target_hash.as_deref();
    let squash_range = dialog
        .squash_range_hashes
        .iter()
        .map(String::as_str)
        .collect::<HashSet<_>>();
    let use_squash_range = squash_target.is_some()
        && squash_range.len() > 1
        && squash_target.is_some_and(|target| squash_range.contains(target));

    let mut items = Vec::new();
    let mut emitted_squash_range = false;
    for commit in &chronological_commits {
        if use_squash_range && squash_range.contains(commit.hash.as_str()) {
            if emitted_squash_range {
                continue;
            }
            let Some(target_hash) = squash_target else {
                continue;
            };
            if let Some(target_commit) = chronological_commits
                .iter()
                .find(|candidate| candidate.hash == target_hash)
            {
                items.push(git::InteractiveRebaseTodoItem {
                    action: git::InteractiveRebaseAction::Pick,
                    hash: target_commit.hash.clone(),
                    subject: target_commit.subject.clone(),
                    message: None,
                    author_name: None,
                    author_email: None,
                });
                for candidate in &chronological_commits {
                    if squash_range.contains(candidate.hash.as_str())
                        && candidate.hash != target_hash
                    {
                        items.push(git::InteractiveRebaseTodoItem {
                            action: git::InteractiveRebaseAction::Squash,
                            hash: candidate.hash.clone(),
                            subject: candidate.subject.clone(),
                            message: None,
                            author_name: None,
                            author_email: None,
                        });
                    }
                }
            }
            emitted_squash_range = true;
            continue;
        }

        let action = dialog
            .actions
            .get(&commit.hash)
            .copied()
            .unwrap_or(InteractiveRebaseTodoAction::Pick);
        items.push(git::InteractiveRebaseTodoItem {
            action: action.to_git_action(),
            hash: commit.hash.clone(),
            subject: commit.subject.clone(),
            message: (action == InteractiveRebaseTodoAction::Reword).then(|| {
                dialog
                    .reword_messages
                    .get(&commit.hash)
                    .cloned()
                    .unwrap_or_else(|| commit.subject.clone())
            }),
            author_name: (action == InteractiveRebaseTodoAction::Reword).then(|| {
                dialog
                    .reword_authors
                    .get(&commit.hash)
                    .map(|author| author.name.clone())
                    .unwrap_or_else(|| commit.author.clone())
            }),
            author_email: (action == InteractiveRebaseTodoAction::Reword).then(|| {
                dialog
                    .reword_authors
                    .get(&commit.hash)
                    .map(|author| author.email.clone())
                    .unwrap_or_else(|| commit.author_email.clone())
            }),
        });
    }
    items
}

fn validate_interactive_rebase_dialog(
    language: Language,
    dialog: &InteractiveRebaseActionDialog,
    commits: &[Commit],
) -> Option<String> {
    let actionable = interactive_rebase_actionable_commits(commits);
    if actionable.is_empty() {
        return Some(i18n::t(language, "interactive_rebase.error.no_commits").to_owned());
    }
    if !interactive_rebase_dialog_has_changes(dialog) {
        return Some(i18n::t(language, "interactive_rebase.error.no_changes").to_owned());
    }
    let has_unsaved_reword = dialog.actions.iter().any(|(hash, action)| {
        *action == InteractiveRebaseTodoAction::Reword
            && (!dialog.confirmed_reword_hashes.contains(hash)
                || dialog
                    .reword_messages
                    .get(hash)
                    .is_none_or(|message| message.trim().is_empty())
                || dialog.reword_authors.get(hash).is_none_or(|author| {
                    author.name.trim().is_empty() || author.email.trim().is_empty()
                }))
    });
    if has_unsaved_reword {
        return Some(i18n::t(language, "interactive_rebase.error.reword_unconfirmed").to_owned());
    }
    if interactive_rebase_todo_items(dialog, commits)
        .first()
        .is_some_and(|item| {
            matches!(
                item.action,
                git::InteractiveRebaseAction::Squash | git::InteractiveRebaseAction::Fixup
            )
        })
    {
        return Some(i18n::t(language, "interactive_rebase.error.first_squash").to_owned());
    }
    None
}

fn interactive_rebase_dirty_message(language: Language) -> String {
    i18n::t(language, "interactive_rebase.error.dirty").to_owned()
}

fn lfs_pattern_list(
    ui: &mut Ui,
    patterns: &mut Vec<String>,
    selected: &mut Option<usize>,
    language: Language,
) {
    soft_panel_frame(theme::panel_soft(), 4, 4)
        .stroke(Stroke::NONE)
        .show(ui, |ui| {
            ui.set_min_size(Vec2::new(270.0, 200.0));
            ScrollArea::vertical()
                .id_salt("lfs_pattern_list")
                .max_height(200.0)
                .auto_shrink([false, false])
                .show(ui, |ui| {
                    if patterns.is_empty() {
                        ui.label(
                            RichText::new(i18n::t(language, "lfs.pattern_empty"))
                                .color(theme::muted()),
                        );
                    }
                    for index in 0..patterns.len() {
                        let is_selected = *selected == Some(index);
                        ui.horizontal(|ui| {
                            let select_response = ui.selectable_label(is_selected, "");
                            if select_response.clicked() {
                                *selected = Some(index);
                            }
                            let hint = i18n::t(language, "lfs.pattern_placeholder");
                            themed_text_edit_selection(ui);
                            let response = ui.add_sized(
                                [220.0, 22.0],
                                themed_singleline_text_edit(&mut patterns[index], hint),
                            );
                            if response.clicked() {
                                *selected = Some(index);
                            }
                        });
                    }
                });
        });
}

fn validate_lfs_patterns(language: Language, patterns: &[String]) -> Option<String> {
    let mut seen = HashSet::<String>::new();
    for pattern in patterns {
        let pattern = pattern.trim();
        if pattern.is_empty() {
            return Some(i18n::t(language, "lfs.error.pattern_required").to_owned());
        }
        if !seen.insert(pattern.to_owned()) {
            return Some(i18n::t(language, "lfs.error.duplicate_pattern").to_owned());
        }
    }
    None
}

fn git_flow_config_defaults(snapshot: &RepositorySnapshot) -> git::GitFlowConfig {
    let production_branch = if snapshot
        .branches
        .iter()
        .any(|branch| !branch.remote && branch.name == "main")
    {
        "main"
    } else if snapshot
        .branches
        .iter()
        .any(|branch| !branch.remote && branch.name == "master")
    {
        "master"
    } else {
        snapshot.branch.as_str()
    };

    git::GitFlowConfig {
        production_branch: production_branch.to_owned(),
        development_branch: "develop".to_owned(),
        ..git::GitFlowConfig::default()
    }
}

fn git_flow_operation_menu_enabled(
    snapshot: Option<&RepositorySnapshot>,
    git_dialog_enabled: bool,
) -> bool {
    git_dialog_enabled
        && snapshot
            .and_then(|snapshot| snapshot.git_flow_config.as_ref())
            .is_some()
}

fn git_flow_current_branch_for_kind(
    snapshot: &RepositorySnapshot,
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> Option<String> {
    let prefix = git_flow_prefix(config, kind);
    snapshot
        .branch
        .starts_with(prefix)
        .then(|| snapshot.branch.clone())
}

fn git_flow_operation_default_name(
    snapshot: &RepositorySnapshot,
    config: &git::GitFlowConfig,
    operation: GitFlowOperation,
) -> String {
    match operation {
        GitFlowOperation::Start(_) => String::new(),
        GitFlowOperation::Finish(kind) => git_flow_current_branch_for_kind(snapshot, config, kind)
            .and_then(|branch| {
                branch
                    .strip_prefix(git_flow_prefix(config, kind))
                    .map(str::to_owned)
            })
            .unwrap_or_default(),
    }
}

fn git_flow_prefix(config: &git::GitFlowConfig, kind: git::GitFlowBranchKind) -> &str {
    match kind {
        git::GitFlowBranchKind::Feature => &config.feature_prefix,
        git::GitFlowBranchKind::Release => &config.release_prefix,
        git::GitFlowBranchKind::Hotfix => &config.hotfix_prefix,
    }
}

fn git_flow_start_base(config: &git::GitFlowConfig, kind: git::GitFlowBranchKind) -> &str {
    match kind {
        git::GitFlowBranchKind::Feature | git::GitFlowBranchKind::Release => {
            &config.development_branch
        }
        git::GitFlowBranchKind::Hotfix => &config.production_branch,
    }
}

fn git_flow_default_start_point(
    snapshot: &RepositorySnapshot,
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> String {
    let base = git_flow_start_base(config, kind);
    if snapshot.branches.iter().any(|branch| branch.name == base) {
        return base.to_owned();
    }
    let remote_base = format!("origin/{base}");
    if snapshot
        .branches
        .iter()
        .any(|branch| branch.name == remote_base)
    {
        return remote_base;
    }
    base.to_owned()
}

fn git_flow_start_point_options(
    snapshot: Option<&RepositorySnapshot>,
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> Vec<GitFlowStartPointOption> {
    let Some(snapshot) = snapshot else {
        return vec![GitFlowStartPointOption {
            name: git_flow_start_base(config, kind).to_owned(),
            subject: String::new(),
        }];
    };

    let default_start = git_flow_default_start_point(snapshot, config, kind);
    let mut seen = HashSet::new();
    let mut options = Vec::new();
    for name in std::iter::once(default_start).chain(
        snapshot
            .branches
            .iter()
            .map(|branch| branch.name.clone())
            .filter(|name| !name.trim().is_empty()),
    ) {
        if seen.insert(name.clone()) {
            options.push(GitFlowStartPointOption {
                subject: git_flow_branch_subject(snapshot, &name).unwrap_or_default(),
                name,
            });
        }
    }
    options
}

fn git_flow_finish_branch_options(
    snapshot: Option<&RepositorySnapshot>,
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> Vec<GitFlowFinishBranchOption> {
    let Some(snapshot) = snapshot else {
        return Vec::new();
    };
    let prefix = git_flow_prefix(config, kind);
    snapshot
        .branches
        .iter()
        .filter(|branch| !branch.remote)
        .filter(|branch| branch.name.starts_with(prefix))
        .map(|branch| GitFlowFinishBranchOption {
            display_name: branch
                .name
                .strip_prefix(prefix)
                .unwrap_or(branch.name.as_str())
                .to_owned(),
            subject: git_flow_branch_subject(snapshot, &branch.name).unwrap_or_default(),
            branch_name: branch.name.clone(),
        })
        .collect()
}

fn git_flow_default_finish_branch(
    snapshot: &RepositorySnapshot,
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> Option<String> {
    let prefix = git_flow_prefix(config, kind);
    if snapshot.branch.starts_with(prefix) {
        return Some(snapshot.branch.clone());
    }
    git_flow_finish_branch_options(Some(snapshot), config, kind)
        .first()
        .map(|option| option.branch_name.clone())
}

fn git_flow_finish_target_branch(
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> &str {
    match kind {
        git::GitFlowBranchKind::Feature => &config.development_branch,
        git::GitFlowBranchKind::Release | git::GitFlowBranchKind::Hotfix => {
            &config.production_branch
        }
    }
}

fn git_flow_finish_target_branches(
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
) -> Vec<&str> {
    match kind {
        git::GitFlowBranchKind::Feature => vec![config.development_branch.as_str()],
        git::GitFlowBranchKind::Release | git::GitFlowBranchKind::Hotfix => {
            vec![
                config.development_branch.as_str(),
                config.production_branch.as_str(),
            ]
        }
    }
}

fn git_flow_finish_branch_label(language: Language, kind: git::GitFlowBranchKind) -> &'static str {
    match kind {
        git::GitFlowBranchKind::Feature => i18n::t(language, "git_flow.feature_name"),
        git::GitFlowBranchKind::Release => i18n::t(language, "git_flow.release_name"),
        git::GitFlowBranchKind::Hotfix => i18n::t(language, "git_flow.hotfix_name"),
    }
}

fn git_flow_finish_latest_label(language: Language, kind: git::GitFlowBranchKind) -> &'static str {
    match kind {
        git::GitFlowBranchKind::Feature => i18n::t(language, "git_flow.preview.latest_feature"),
        git::GitFlowBranchKind::Release => i18n::t(language, "git_flow.preview.latest_release"),
        git::GitFlowBranchKind::Hotfix => i18n::t(language, "git_flow.preview.latest_hotfix"),
    }
}

fn git_flow_finish_tag_name(
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
    branch_name: &str,
) -> String {
    let prefix = git_flow_prefix(config, kind);
    let suffix = branch_name
        .strip_prefix(prefix)
        .unwrap_or(branch_name)
        .trim();
    if config.version_tag_prefix.is_empty() || suffix.starts_with(&config.version_tag_prefix) {
        suffix.to_owned()
    } else {
        format!("{}{}", config.version_tag_prefix, suffix)
    }
}

fn git_flow_branch_subject(snapshot: &RepositorySnapshot, branch_name: &str) -> Option<String> {
    snapshot
        .all_date_commits
        .iter()
        .chain(snapshot.date_commits.iter())
        .chain(snapshot.commits.iter())
        .find(|commit| {
            commit
                .refs
                .iter()
                .any(|reference| reference == branch_name || reference.ends_with(branch_name))
        })
        .map(|commit| commit.subject.clone())
}

fn git_flow_full_branch_name(
    config: &git::GitFlowConfig,
    kind: git::GitFlowBranchKind,
    name: &str,
) -> String {
    let prefix = git_flow_prefix(config, kind);
    let name = name.trim().trim_start_matches('/');
    if name.starts_with(prefix) {
        name.to_owned()
    } else {
        format!("{prefix}{name}")
    }
}

fn git_flow_config_field(ui: &mut Ui, language: Language, label: &str, value: &mut String) {
    ui.horizontal(|ui| {
        ui.add_sized(
            [132.0, 24.0],
            egui::Label::new(RichText::new(label).small().color(theme::muted())),
        );
        let hint = placeholder_for_label(language, label);
        themed_text_edit_selection(ui);
        ui.add_sized(
            [ui.available_width(), 24.0],
            themed_singleline_text_edit(value, &hint),
        );
    });
}

fn searchable_branch_dropdown(
    ui: &mut Ui,
    id: egui::Id,
    selected: &mut String,
    choices: &[(String, String)],
    width: f32,
    empty_label: &str,
    search_placeholder: &str,
) -> bool {
    let selected_text = choices
        .iter()
        .find(|(value, _)| value == selected)
        .map(|(_, label)| label.clone())
        .filter(|label| !label.is_empty())
        .unwrap_or_else(|| {
            if selected.is_empty() {
                empty_label.to_owned()
            } else {
                selected.clone()
            }
        });
    let filter_id = id.with("branch_filter");
    let filter_input_id = filter_id.with("input");
    let popup_was_open = egui::ComboBox::is_open(ui.ctx(), id);
    let mut changed = false;
    let mut selected_option = false;

    let combo_response = egui::ComboBox::from_id_salt(id)
        .width(width)
        .selected_text(selected_text)
        .close_behavior(egui::popup::PopupCloseBehavior::CloseOnClickOutside)
        .show_ui(ui, |ui| {
            let mut filter = ui
                .ctx()
                .data(|data| data.get_temp::<String>(filter_id).unwrap_or_default());
            let search_frame = egui::Frame::new()
                .fill(theme::panel_recessed())
                .stroke(Stroke::NONE)
                .corner_radius(CornerRadius::same(4))
                .inner_margin(egui::Margin::symmetric(4, 2))
                .show(ui, |ui| {
                    themed_text_edit_selection(ui);
                    ui.add_sized(
                        [ui.available_width(), 20.0],
                        themed_singleline_text_edit(&mut filter, search_placeholder)
                            .id(filter_input_id)
                            .frame(false),
                    )
                });
            paint_branch_dropdown_search_inset_shadow(ui, search_frame.response.rect);
            let filter_response = search_frame.inner;
            if filter_response.changed() {
                ui.ctx()
                    .data_mut(|data| data.insert_temp(filter_id, filter.clone()));
            }
            let filter = filter.trim().to_lowercase();
            ui.add_space(4.0);

            ScrollArea::vertical()
                .id_salt(filter_id.with("choices"))
                .max_height(216.0)
                .auto_shrink([false, false])
                .show(ui, |ui| {
                    let mut has_match = false;
                    for (value, label) in choices {
                        let matches_filter = filter.is_empty()
                            || value.to_lowercase().contains(&filter)
                            || label.to_lowercase().contains(&filter);
                        if !matches_filter {
                            continue;
                        }
                        has_match = true;
                        if ui
                            .selectable_value(selected, value.clone(), label)
                            .clicked()
                        {
                            changed = true;
                            selected_option = true;
                            ui.ctx()
                                .data_mut(|data| data.insert_temp(filter_id, String::new()));
                        }
                    }
                    if !has_match {
                        ui.label(
                            RichText::new(search_placeholder)
                                .small()
                                .color(theme::muted()),
                        );
                    }
                });
        });
    if combo_response.response.clicked() && !popup_was_open {
        ui.ctx()
            .data_mut(|data| data.insert_temp(filter_id, String::new()));
        ui.memory_mut(|memory| memory.request_focus(filter_input_id));
    }
    if selected_option {
        ui.memory_mut(|memory| memory.close_popup());
    }
    changed
}

fn paint_branch_dropdown_search_inset_shadow(ui: &Ui, rect: Rect) {
    let rect = rect.shrink(0.5);
    let dark = theme::inset_shadow().gamma_multiply(0.3);
    let light = theme::inset_highlight().gamma_multiply(0.22);
    let radius = 4.0;
    ui.painter().line_segment(
        [
            Pos2::new(rect.left() + radius, rect.top()),
            Pos2::new(rect.right() - radius, rect.top()),
        ],
        Stroke::new(1.0, dark),
    );
    ui.painter().line_segment(
        [
            Pos2::new(rect.left(), rect.top() + radius),
            Pos2::new(rect.left(), rect.bottom() - radius),
        ],
        Stroke::new(1.0, dark),
    );
    ui.painter().line_segment(
        [
            Pos2::new(rect.left() + radius, rect.bottom()),
            Pos2::new(rect.right() - radius, rect.bottom()),
        ],
        Stroke::new(1.0, light),
    );
    ui.painter().line_segment(
        [
            Pos2::new(rect.right(), rect.top() + radius),
            Pos2::new(rect.right(), rect.bottom() - radius),
        ],
        Stroke::new(1.0, light),
    );
}

