    #[test]
    fn selected_diff_hunk_patch_keeps_the_file_preamble_and_only_the_selected_hunk() {
        let diff = "\
diff --git a/example.txt b/example.txt
index 1111111..2222222 100644
--- a/example.txt
+++ b/example.txt
@@ -1,2 +1,2 @@
-before
+after
 context
@@ -20,2 +20,2 @@
-old tail
+new tail
 context tail
";
        let selected = collect_unified_diff_items(diff, DiffDisplayMode::Full)
            .into_iter()
            .find_map(|item| match item {
                DiffRenderItem::Line(line) if line.body == "after" => Some(line.key()),
                _ => None,
            })
            .unwrap();

        let patch = selected_diff_hunk_patch(diff, &[selected]).unwrap();
        assert!(patch.contains("diff --git a/example.txt b/example.txt"));
        assert!(patch.contains("@@ -1,2 +1,2 @@"));
        assert!(patch.contains("+after"));
        assert!(!patch.contains("@@ -20,2 +20,2 @@"));
        assert!(!patch.contains("+new tail"));
    }

    #[test]
    fn diff_blocks_collapse_unchanged_context_and_keep_nearby_changes_together() {
        let diff = "\
diff --git a/file.txt b/file.txt
@@ -1,18 +1,18 @@
 line 1
 line 2
 line 3
-old 4
+new 4
 line 5
 line 6
 line 7
 line 8
-old 9
+new 9
 line 10
 line 11
 line 12
 line 13
 line 14
 line 15
 line 16
 line 17
 line 18";
        let full = collect_unified_diff_items(diff, DiffDisplayMode::Full);
        let blocks = collect_unified_diff_items(diff, DiffDisplayMode::Blocks);

        assert!(blocks.len() < full.len());
        assert!(
            blocks
                .iter()
                .any(|item| matches!(item, DiffRenderItem::Omitted))
        );
        let visible_lines = blocks
            .iter()
            .filter(|item| matches!(item, DiffRenderItem::Line(_)))
            .count();
        assert!(visible_lines >= 10);
    }

