    #[test]
    fn help_menu_uses_about_and_async_release_update_without_process_viewer() {
        fn section<'a>(source: &'a str, start: &str, end: &str) -> &'a str {
            let start = source.find(start).unwrap();
            let end = source[start..].find(end).unwrap();
            &source[start..start + end]
        }

        let source = include_str!("app.rs");
        let implementation = &source[..source.find("#[cfg(test)]").unwrap()];
        assert!(!implementation.contains("process_viewer"));
        assert!(!implementation.contains("process_viewer_modal"));

        let help_menu = section(
            implementation,
            "menu_label(self.language, \"help\"),",
            "fn top_bar_panel(&mut self",
        );
        let about = help_menu
            .find("menu_label(self.language, \"about\")")
            .unwrap();
        let update = help_menu
            .find("menu_label(self.language, \"check_updates\")")
            .unwrap();
        assert!(about < update);
        assert!(help_menu.contains("self.about_open = true;"));
        assert!(help_menu.contains("self.start_update_check();"));
        assert!(help_menu.contains("self.update_task.is_none()"));

        let check = section(
            implementation,
            "fn start_update_check(&mut self)",
            "fn start_update_install(&mut self)",
        );
        let visible = check.find("self.update_dialog_open = true;").unwrap();
        let owned = check.find("self.update_task = Some(receiver);").unwrap();
        let spawned = check.find("thread::spawn(move ||").unwrap();
        assert!(visible < owned && owned < spawned);
        assert!(check.contains("self.update_task_action = Some(UpdateTaskAction::Check)"));

        let install = section(
            implementation,
            "fn start_update_install(&mut self)",
            "fn open_repo_config_file(&mut self)",
        );
        let install_owned = install.find("self.update_task = Some(receiver);").unwrap();
        let install_spawned = install.find("thread::spawn(move ||").unwrap();
        assert!(install_owned < install_spawned);
        assert!(install.contains("self.update_task.is_some()"));
        assert!(install.contains("updater::download_and_install(&asset)"));

        let poll = section(
            implementation,
            "if let Some(receiver) = self.update_task.take()",
            "if let Some(receiver) = self.create_patch_task.take()",
        );
        assert!(poll.contains("self.update_task_action = None;"));
        assert!(poll.contains("self.update_task = Some(receiver);"));
        assert!(poll.contains("UpdateTaskOutput::Checked(release)"));
        assert!(poll.contains("UpdateTaskOutput::Installed(outcome)"));
        assert!(poll.contains("update.stopped"));

        let modal = section(
            implementation,
            "fn update_modal(&mut self",
            "fn ssh_agent_status_modal(&mut self",
        );
        assert!(modal.contains("let task_busy = self.update_task.is_some();"));
        assert!(modal.contains("!task_busy"));
        assert!(modal.contains("update.download_install"));
        assert!(modal.contains("self.start_update_install();"));
    }

    #[test]
    fn about_copy_is_loaded_from_single_localized_markdown_file() {
        assert!(ABOUT_MARKDOWN.contains(ABOUT_ZH_MARKER));
        assert!(ABOUT_MARKDOWN.contains(ABOUT_EN_MARKER));

        let chinese = about_markdown(Language::Chinese);
        let english = about_markdown(Language::English);
        assert!(!chinese.is_empty());
        assert!(!english.is_empty());
        assert_ne!(chinese, english);
        assert!(!chinese.contains("<!-- lang:"));
        assert!(!english.contains("<!-- lang:"));
        assert!(english.contains("Git Agent is a desktop client"));

        for key in [
            "about.title",
            "about.version",
            "about.repository",
            "update.title",
            "update.current_version",
            "update.latest_version",
            "update.checking",
            "update.installing",
            "update.available",
            "update.up_to_date",
            "update.package",
            "update.no_asset",
            "update.download_install",
            "update.open_release",
            "update.retry",
            "update.failed",
            "update.installed",
            "update.restart_required",
            "update.stopped",
        ] {
            for language in [Language::Chinese, Language::English] {
                let translated = i18n::t(language, key);
                assert!(!translated.is_empty(), "{key}");
                assert_ne!(translated, key, "{key}");
            }
        }
    }

    #[test]
    fn repo_settings_uses_shadow_gap_cards_for_remote_and_advanced_pages() {
        let source = include_str!("app.rs");
        let implementation_source = &source[..source.find("#[cfg(test)]").unwrap()];
        let modal_start = implementation_source
            .find("fn repo_settings_modal(&mut self")
            .unwrap();
        let modal_end = implementation_source[modal_start..]
            .find("fn global_settings_page")
            .unwrap();
        let modal_source = &implementation_source[modal_start..modal_start + modal_end];
        let remotes_start = implementation_source
            .find("fn repo_remotes_settings_page")
            .unwrap();
        let remotes_end = implementation_source[remotes_start..]
            .find("fn repo_advanced_settings_page")
            .unwrap();
        let remotes_source = &implementation_source[remotes_start..remotes_start + remotes_end];
        let advanced_start = implementation_source
            .find("fn repo_advanced_settings_page")
            .unwrap();
        let advanced_end = implementation_source[advanced_start..]
            .find("fn remote_settings_table(")
            .unwrap();
        let advanced_source = &implementation_source[advanced_start..advanced_start + advanced_end];
        let card_start = implementation_source
            .find("fn repo_settings_card(")
            .unwrap();
        let card_end = implementation_source[card_start..]
            .find("fn repo_settings_tab_strip(")
            .unwrap();
        let card_source = &implementation_source[card_start..card_start + card_end];
        let tabs_start = implementation_source
            .find("fn repo_settings_tab_strip(")
            .unwrap();
        let tabs_end = implementation_source[tabs_start..]
            .find("fn repo_settings_tab_button(")
            .unwrap();
        let tabs_source = &implementation_source[tabs_start..tabs_start + tabs_end];

        assert!(REPO_SETTINGS_DIALOG_HEIGHT <= 460.0);
        assert!(REPO_SETTINGS_TABS_HEIGHT <= 42.0);
        assert!(REPO_SETTINGS_TAB_HEIGHT <= 38.0);
        assert!(modal_source.contains("repo_settings_dialog_height(self.repo_settings_tab)"));
        assert!(modal_source.contains("repo_settings_tab_strip("));
        assert!(!modal_source.contains("nav_width"));
        assert!(!modal_source.contains("content_height = safe_ui_length"));
        assert!(tabs_source.contains("allocate_ui_with_layout"));
        assert!(tabs_source.contains("REPO_SETTINGS_TABS_HEIGHT"));
        assert!(!tabs_source.contains("horizontal_centered"));
        assert!(card_source.contains(".shadow(panel_shadow())"));
        assert!(card_source.contains(".stroke(Stroke::NONE)"));
        assert!(remotes_source.contains("repo_settings_card("));
        assert!(remotes_source.contains("remote_settings_table("));
        assert!(!remotes_source.contains("repo_remote_details_card("));
        assert!(!remotes_source.contains("egui::Grid::new(\"repo_remotes_grid\")"));
        assert!(advanced_source.contains("snapshot.config"));
        assert!(advanced_source.contains("repo_settings_readonly_text("));
        assert!(advanced_source.contains("repo_settings_commit_links_panel("));
        assert!(advanced_source.contains("settings_checkbox_row("));
        assert!(modal_source.contains("open_repo_config_file()"));
        assert_eq!(
            settings_tab_label(Language::Chinese, SettingsTab::RepoAdvanced),
            "\u{9ad8}\u{7ea7}"
        );
    }
